#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        // The strategy is to pick numbers of the form 2k where k is odd,
        // or more generally, numbers that are 2 * (an odd number).
        // This ensures gcd(a,b) is at least 2.
        // To avoid a divides b or b divides a, we can pick numbers
        // from a range where this is less likely, or specifically construct them.
        // A simple pattern that works is to pick numbers starting from 4n and going downwards,
        // skipping numbers that are multiples of 2.
        // Or, more simply, pick numbers 4n, 4n-2, 4n-4, ...
        // However, 4n-2, 4n-4, ... might have divisibility issues.
        // For example, if n=3, 4n=12. We need 3 numbers.
        // 12, 10, 8.
        // gcd(12,10)=2, 12 not div 10, 10 not div 12. OK.
        // gcd(12,8)=4, 12 not div 8, 8 not div 12. OK.
        // gcd(10,8)=2, 10 not div 8, 8 not div 10. OK.
        // This set works for n=3.
        //
        // Let's try the sequence: 4n, 4n-2, 4n-4, ..., 4n - 2*(n-1) = 2n+2.
        // This gives n numbers: 4n, 4n-2, ..., 2n+2.
        // All these numbers are even, so gcd(a,b) >= 2.
        // Let a = 2k_a and b = 2k_b.
        // The condition "a divides b" becomes "2k_a divides 2k_b", which simplifies to "k_a divides k_b".
        // The numbers are 2(2n), 2(2n-1), 2(2n-2), ..., 2(n+1).
        // The corresponding k values are 2n, 2n-1, 2n-2, ..., n+1.
        // We need to check if any k_i divides k_j for i != j.
        // Since all k values are distinct and in the range [n+1, 2n],
        // if k_i divides k_j, then k_j must be at least 2 * k_i.
        // But the maximum value in the set is 2n, and the minimum is n+1.
        // If k_i is in [n+1, 2n], then 2 * k_i would be at least 2*(n+1) = 2n+2.
        // This value (2n+2) is strictly greater than the maximum value in the set (2n).
        // Therefore, no k_i can divide k_j for i != j within this set.
        // This means no 2k_i can divide 2k_j for i != j.
        // So, the sequence 4n, 4n-2, ..., 2n+2 works.

        for (int i = 0; i < n; ++i) {
            std::cout << 4 * n - 2 * i << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

