    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        }
    }

    // To maximize the binary number, we should prioritize '1's (from "one")
    // over '0's (from "zero").
    // The number of '1's is determined by the count of 'n's.
    // The number of '0's is determined by the count of 'z's.

    // Print '1's first
    for (int i = 0; i < count_n; ++i) {
        std::cout << "1";
        if (i < count_n - 1 || count_z > 0) { // If there are more '1's or any '0's to print
            std::cout << " ";
        }
    }

    // Then print '0's
    for (int i = 0; i < count_z; ++i) {
        std::cout << "0";
        if (i < count_z - 1) { // If there are more '0's to print
            std::cout << " ";
        }
    }
    std::cout << std::endl;

    return 0;
}

