#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k coal and k sticks.
        // To get k coal, we need k * y sticks.
        // So, total sticks required for coal and torches = k * y + k = k * (y + 1).
        long long total_sticks_needed = k * (y + 1);

        // We start with 1 stick.
        // We need to acquire (total_sticks_needed - 1) more sticks using the first trade.
        // Each trade of type 1 (1 stick for x sticks) gives a net gain of (x - 1) sticks.
        long long sticks_to_gain = total_sticks_needed - 1;
        long long trades_for_sticks = (sticks_to_gain + (x - 2)) / (x - 1); // Equivalent to ceil(sticks_to_gain / (x - 1))

        // Total trades = trades for sticks + trades for coal
        // Trades for coal = k (since 1 trade gives 1 coal)
        long long total_trades = trades_for_sticks + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

