void solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<bool> row_has_one(n, false);
    std::vector<bool> col_has_one(m, false);

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            int val;
            std::cin >> val;
            if (val == 1) {
                row_has_one[i] = true;
                col_has_one[j] = true;
            }
        }
    }

    int available_rows = 0;
    for (bool b : row_has_one) {
        if (!b) {
            available_rows++;
        }
    }

    int available_cols = 0;
    for (bool b : col_has_one) {
        if (!b) {
            available_cols++;
        }
    }

    int moves_possible = std::min(available_rows, available_cols);

    if (moves_possible % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

