int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    std::vector<long long> a(n);
    long long total_sum = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_sum += a[i];
    }

    if (total_sum % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_duration_per_post = total_sum / k;
    std::vector<int> s_values;
    long long current_post_sum = 0;
    int current_post_videos_count = 0;
    int posts_formed = 0;

    for (int i = 0; i < n; ++i) {
        current_post_sum += a[i];
        current_post_videos_count++;

        if (current_post_sum == target_duration_per_post) {
            s_values.push_back(current_post_videos_count);
            current_post_sum = 0;
            current_post_videos_count = 0;
            posts_formed++;
        } else if (current_post_sum > target_duration_per_post) {
            std::cout << "No\n";
            return 0;
        }
    }

    if (posts_formed == k) {
        std::cout << "Yes\n";
        for (int i = 0; i < s_values.size(); ++i) {
            std::cout << s_values[i] << (i == s_values.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        // This case should ideally be covered by the current_post_sum > target_duration_per_post check
        // or if current_post_sum != 0 after loop, but for robustness.
        std::cout << "No\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this specific element.
        // The flags has_pos_one and has_neg_one are updated based on elements a[0]...a[i-1]
        // for operations on a[i]...a[n-1].
        // So, we update them after checking a[i] vs b[i].
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    std::cout << "YES\n";
}

