#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_dist = 0;
        int last_R_pos = -1; // Represents the last 'R' cell or the starting cell 0.
                             // If last_R_pos = -1, it means the frog is at cell 0.
                             // If last_R_pos = i, it means the frog is at cell i+1 (1-indexed string char s[i]).

        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // If s[i] is 'R', the frog can land on cell i+1.
                // The distance from the previous safe spot (last_R_pos + 1) to current safe spot (i+1) is (i+1) - (last_R_pos + 1).
                // This simplifies to i - last_R_pos.
                max_dist = std::max(max_dist, i - last_R_pos);
                last_R_pos = i;
            }
        }
        // After iterating through the string, the frog needs to jump from the last 'R' cell (or cell 0 if no 'R's)
        // to the target cell n+1.
        // The last 'R' cell is at index `last_R_pos` in the string, which corresponds to cell `last_R_pos + 1`.
        // The target is cell `s.length() + 1`.
        // The distance needed is (s.length() + 1) - (last_R_pos + 1), which simplifies to s.length() - last_R_pos.
        max_dist = std::max(max_dist, (int)s.length() - last_R_pos);
        std::cout << max_dist << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks to minimize the absolute difference between the medians of two classes.
        // Each class must have an odd number of students.
        // Let the sorted skill levels be a_0, a_1, ..., a_{2n-1}.
        //
        // Consider the case where one class has size 1 and the other has size 2n-1.
        // The median of a class of size 1 is its single element.
        // The median of a class of size 2n-1 is its n-th element (0-indexed: a_{n-1} if it were the whole array).
        //
        // If we pick a_i as the median of the first class (size 1), and a_j as the median of the second class (size 2n-1).
        // The key insight is that to minimize the difference, the medians should be as close as possible.
        //
        // If we sort the entire array, a_0, a_1, ..., a_{2n-1}.
        // The median of the first class will be some a_i.
        // The median of the second class will be some a_j.
        //
        // Consider the specific partition where the first class consists of students with skill levels
        // a_0, a_1, ..., a_{n-1} and the second class consists of students with skill levels
        // a_n, a_{n+1}, ..., a_{2n-1}.
        // This partition is not valid because the sizes are n and n. If n is even, this is invalid.
        // If n is odd, this is valid, and the medians would be a_{(n-1)/2} and a_{n + (n-1)/2}.
        //
        // The problem statement implies that we can choose any odd sizes S1, S2 such that S1+S2 = 2n.
        //
        // The crucial observation is that if we sort the entire array, a_0, a_1, ..., a_{2n-1},
        // the optimal strategy is to pick the median of the first class as a_{n-1} and the median of the second class as a_n.
        //
        // Why?
        // Let the two classes be C1 and C2. Let their sizes be S1 and S2, both odd. S1+S2 = 2n.
        // Let m1 be the median of C1 and m2 be the median of C2. We want to minimize |m1 - m2|.
        //
        // Consider the sorted array a_0, ..., a_{2n-1}.
        // The element a_{n-1} is the (n)-th element.
        // The element a_n is the (n+1)-th element.
        //
        // If we choose a_{n-1} as the median of one class and a_n as the median of the other class,
        // we can always construct such classes.
        //
        // For example, let C1 contain a_0, ..., a_{n-1}. This class has size n.
        // Let C2 contain a_n, ..., a_{2n-1}. This class has size n.
        // If n is odd, then this is a valid partition.
        // The median of C1 is a_{(n-1)/2}.
        // The median of C2 is a_{n + (n-1)/2}.
        // The difference is a_{n + (n-1)/2} - a_{(n-1)/2}.
        //
        // However, the problem is simpler.
        // The minimum possible difference is achieved by taking the (n)-th element (0-indexed: a_{n-1})
        // and the (n+1)-th element (0-indexed: a_n) from the fully sorted array.
        //
        // This is because if we pick a_{n-1} as the median of one class and a_n as the median of the other,
        // we can always form two valid classes.
        //
        // Let's say we want a_{n-1} to be the median of Class 1.
        // We need to pick (S1-1)/2 elements smaller than or equal to a_{n-1} and (S1-1)/2 elements greater than or equal to a_{n-1}.
        // We have n elements a_0, ..., a_{n-1} that are <= a_{n-1}.
        // We have n elements a_{n-1}, ..., a_{2n-1} that are >= a_{n-1}.
        //
        // Let's say we want a_n to be the median of Class 2.
        // We need to pick (S2-1)/2 elements smaller than or equal to a_n and (S2-1)/2 elements greater than or equal to a_n.
        // We have n+1 elements a_0, ..., a_n that are <= a_n.
        // We have n elements a_n, ..., a_{2n-1} that are >= a_n.
        //
        // The minimum difference will always be a_n - a_{n-1}.
        // This is because a_{n-1} is the largest possible median for a class that is "left-leaning" (i.e., its median is among the first n elements).
        // And a_n is the smallest possible median for a class that is "right-leaning" (i.e., its median is among the last n elements).
        //
        // More formally, consider any partition into two odd-sized classes C1 and C2 with medians m1 and m2.
        // Without loss of generality, assume m1 <= m2.
        //
        // For C1 with median m1, there are (S1-1)/2 elements <= m1 and (S1-1)/2 elements >= m1.
        // For C2 with median m2, there are (S2-1)/2 elements <= m2 and (S2-1)/2 elements >= m2.
        //
        // The total number of elements less than or equal to m1 is at least (S1-1)/2 + (S2-1)/2 = (S1+S2-2)/2 = (2n-2)/2 = n-1.
        // This means m1 must be at least a_{n-1} (if 0-indexed).
        //
        // The total number of elements greater than or equal to m2 is at least (S1-1)/2 + (S2-1)/2 = n-1.
        // This means m2 must be at most a_n (if 0-indexed).
        //
        // So, we must have a_{n-1} <= m1 <= m2 <= a_n.
        // The minimum possible value for m2 - m1 is thus a_n - a_{n-1}.
        //
        // We can achieve this difference by assigning a_{n-1} to be the median of one class and a_n to be the median of the other.
        // For example, Class 1: {a_0, ..., a_{n-1}} (size n). Median is a_{(n-1)/2} if n is odd.
        // Class 2: {a_n, ..., a_{2n-1}} (size n). Median is a_{n + (n-1)/2} if n is odd.
        // This is not the general construction.
        //
        // A simpler construction:
        // Class 1: {a_{n-1}} (size 1). Median is a_{n-1}.
        // Class 2: {all other 2n-1 students}. Median is a_n.
        // This is valid because 2n-1 is always odd.
        // For Class 2, we have 2n-1 students. Its median is the ((2n-1)-1)/2 + 1 = n-th element.
        // If we remove a_{n-1} from the sorted array, the remaining elements are a_0, ..., a_{n-2}, a_n, ..., a_{2n-1}.
        // The n-th element in this new sorted array is a_n.
        // So, the medians are a_{n-1} and a_n. The difference is a_n - a_{n-1}.
        // This construction is always possible and yields the minimum difference.

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i from 1 to n-1 (corresponding to q_2 to q_n)
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i must be unique if it's a new max
                // and q_i is guaranteed to be <= n.
                // However, if q_i was already used as p_j for j < i, it's an issue.
                // But p_j = q_j if q_j > q_{j-1}. So q_i would be equal to some q_j.
                // This implies q_i was not a new maximum, contradiction.
                // So this check is mostly for robustness, but shouldn't trigger with valid q.
                possible = false;
                break;
            }
            p[i] = q[i];
            used_numbers.insert(q[i]);
        } else { // q[i] == q[i-1]
            // p_i must be some unused number less than q[i]
            // To maximize chances, pick the smallest available number
            int current_val = 1;
            while (used_numbers.count(current_val)) {
                current_val++;
            }

            if (current_val >= q[i]) {
                // No unused number less than q[i] is available
                possible = false;
                break;
            }
            p[i] = current_val;
            used_numbers.insert(current_val);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number we will use in the zig-zag part to generate k distinct differences

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
    }

    // Fill the remaining elements in increasing order
    // The numbers from 'left' to 'right' (inclusive) are unused.
    // At this point, 'left' is the smallest unused number, and 'right' is the largest unused number.
    // Since we used numbers from 1 to 'left-1' and from 'right+1' to 'k+1' in the zig-zag,
    // the remaining numbers are 'left', 'left+1', ..., 'right'.
    // These are exactly the numbers that were not used in the zig-zag part.
    // For example, if k=2, we use 1, 3, 2. left=2, right=2.
    // The numbers used are 1, 2, 3.
    // The next number to use is 'left' (which is 2).
    // But wait, the zig-zag uses numbers from 1 to k+1.
    // So, after the loop, 'left' will be (k+1)/2 + 1 if k is odd, or k/2 + 1 if k is even.
    // And 'right' will be (k+1)/2 if k is odd, or k/2 + 1 if k is even.
    // The numbers used are 1, 2, ..., k+1.
    // The 'left' variable will point to the next available number after the zig-zag part.
    // The 'right' variable will point to the last available number after the zig-zag part.
    // The numbers used in the zig-zag are 1, 2, ..., k+1.
    // So, the next number to fill is k+2.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // Fill with k+2, k+3, ..., n
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;
    int current_open_count = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_needed > 0) {
                result += '(';
                open_needed--;
                current_open_count++;
            }
        } else { // c == ')'
            if (close_needed > 0 && current_open_count > 0) {
                result += ')';
                close_needed--;
                current_open_count--;
            }
        }
        if (result.length() == k) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;

    std::vector<long long> costs;
    long long current_n = 1;
    long long current_cost = 1; // Cost for n=1
    costs.push_back(current_cost);

    // Precompute costs for nice staircases
    // The maximum possible n for x = 10^18 is when 2^k - 1 is roughly 10^18.
    // 2^k approx 10^18 => k approx log2(10^18) = 18 * log2(10) approx 18 * 3.32 = 59.79.
    // So k can go up to around 60.
    // The cost formula is (2^k - 1) * (2^k) / 2.
    // For k=60, 2^60 is a very large number.
    // The cost is (2^k - 1) * 2^(k-1).
    // For k=1, n=1, cost = 1 * 1 / 2 = 1. (2^1-1)*2^0 = 1.
    // For k=2, n=3, cost = 3 * 2 = 6. (2^2-1)*2^1 = 3*2 = 6.
    // For k=3, n=7, cost = 7 * 4 = 28. (2^3-1)*2^2 = 7*4 = 28.
    // The formula for cost is (2^k - 1) * 2^(k-1).
    // Let n_k = 2^k - 1. The cost is n_k * (n_k + 1) / 2.
    // This is (2^k - 1) * (2^k - 1 + 1) / 2 = (2^k - 1) * 2^k / 2 = (2^k - 1) * 2^(k-1).

    // We need to be careful with overflow.
    // 2^60 is about 1.15 * 10^18.
    // (2^60 - 1) * 2^59 would overflow long long.
    // The maximum x is 10^18.
    // Let's find the maximum k such that (2^k - 1) * 2^(k-1) <= 10^18.
    // For k=1, cost = 1.
    // For k=2, cost = 3 * 2 = 6.
    // For k=3, cost = 7 * 4 = 28.
    // For k=4, cost = 15 * 8 = 120.
    // For k=5, cost = 31 * 16 = 496.
    // ...
    // For k=30, 2^30 is about 10^9.
    // (2^30 - 1) * 2^29 is about (10^9) * (0.5 * 10^9) = 0.5 * 10^18. This fits.
    // For k=31, (2^31 - 1) * 2^30 is about (2 * 10^9) * (10^9) = 2 * 10^18. This might exceed 10^18.
    // Let's calculate precisely.
    // k=30: (1073741824LL - 1) * 536870912LL = 1073741823LL * 536870912LL = 576460750999999999LL. This is < 10^18.
    // k=31: (2147483648LL - 1) * 1073741824LL = 2147483647LL * 1073741824LL = 2305843008139952128LL. This is > 10^18.
    // So we need costs up to k=30.

    for (int k = 2; k <= 30; ++k) {
        long long n_k = (1LL << k) - 1; // 2^k - 1
        long long cost_k = n_k * (1LL << (k - 1)); // (2^k - 1) * 2^(k-1)
        if (cost_k > 2000000000000000000LL) { // A bit more than 10^18 to be safe, though 10^18 is enough
            break;
        }
        costs.push_back(cost_k);
    }

    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        // Iterate through costs in descending order (greedy approach)
        // This is correct because the costs are powers of 2 related,
        // specifically, cost_k = (2^k - 1) * 2^(k-1).
        // The costs are 1, 6, 28, 120, 496, ...
        // This is a canonical coin problem.
        // If we have coins 1, 6, 28, ... and we want to make change for X,
        // a greedy approach works if the coin values satisfy certain properties.
        // Here, the costs are not directly powers of 2, but they are of the form (2^k-1)*2^(k-1).
        // Let C_k be the cost for k stairs.
        // C_1 = 1
        // C_2 = 6
        // C_3 = 28
        // C_4 = 120
        // C_5 = 496
        // C_6 = 2016
        // C_7 = 8128
        // C_8 = 32640
        // C_9 = 130816
        // C_10 = 523776
        // C_11 = 2096128
        // C_12 = 8386560
        // C_13 = 33550336
        // C_14 = 134209536
        // C_15 = 536854528
        // C_16 = 2147450880
        // C_17 = 8589869056
        // C_18 = 34359607296
        // C_19 = 137438633984
        // C_20 = 549755581440
        // C_21 = 2199022880768
        // C_22 = 8796091877376
        // C_23 = 35184371900416
        // C_24 = 140737479000000 (approx)
        // C_25 = 562949953421312
        // C_26 = 2251799813685248
        // C_27 = 9007199254740992
        // C_28 = 36028797018963968
        // C_29 = 144115187660000000 (approx)
        // C_30 = 576460750999999999

        // The greedy approach works here.
        // If we have a sum S and we can use a cost C_k, we should use the largest C_k <= S.
        // This is because C_k is significantly larger than the sum of all smaller costs.
        // Sum of C_i for i < k:
        // Sum_{i=1}^{k-1} (2^i - 1) * 2^(i-1)
        // This sum is always less than C_k.
        // For example, C_1 + C_2 = 1 + 6 = 7 < C_3 = 28.
        // C_1 + ... + C_{k-1} < C_k.
        // This property ensures that a greedy approach (always taking the largest possible staircase)
        // yields the maximum number of staircases.

        for (int i = costs.size() - 1; i >= 0; --i) {
            if (x >= costs[i]) {
                x -= costs[i];
                count++;
            }
        }
        std::cout << count << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        std::string s;
        std::cin >> s;
        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        int horizontal_moves = std::min(counts['L'], counts['R']);
        int vertical_moves = std::min(counts['U'], counts['D']);

        if (horizontal_moves == 0 && vertical_moves == 0) {
            std::cout << 0 << "\n\n";
        } else if (horizontal_moves == 0) { // Only vertical moves possible
            std::cout << 2 << "\n";
            std::cout << "UD\n";
        } else if (vertical_moves == 0) { // Only horizontal moves possible
            std::cout << 2 << "\n";
            std::cout << "LR\n";
        } else {
            std::cout << 2 * (horizontal_moves + vertical_moves) << "\n";
            for (int i = 0; i < horizontal_moves; ++i) {
                std::cout << 'L';
            }
            for (int i = 0; i < vertical_moves; ++i) {
                std::cout << 'U';
            }
            for (int i = 0; i < horizontal_moves; ++i) {
                std::cout << 'R';
            }
            for (int i = 0; i < vertical_moves; ++i) {
                std::cout << 'D';
            }
            std::cout << "\n";
        }
    }
    return 0;
}

