#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the 0-indexed position of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    // For m=1, the subsegment [1] is always a permutation of {1}.
    // The element 1 is at pos[1]. So l=pos[1], r=pos[1].
    // min_idx = pos[1], max_idx = pos[1].
    // current_min_idx = pos[1], current_max_idx = pos[1].
    // length = current_max_idx - current_min_idx + 1 = 1.
    // For m=1, length == m, so it's beautiful.
    result[0] = '1';

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 2; m <= n; ++m) {
        // To check if m is beautiful, we need to extend the current range
        // [current_min_idx, current_max_idx] to include 'm'.
        // The number 'm' is at pos[m].

        // Update the range to include 'm'.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // The length of the subsegment p[current_min_idx ... current_max_idx]
        // is current_max_idx - current_min_idx + 1.
        // For this subsegment to be a permutation of {1, ..., m}, its length
        // must be exactly m.
        if (current_max_idx - current_min_idx + 1 == m) {
            result[m - 1] = '1';
        } else {
            result[m - 1] = '0';
        }
    }
    std::cout << result << "\n";
}

