    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    if (n <= 2) {
        std::cout << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return;
    }

    std::vector<int> result_subsequence;
    result_subsequence.push_back(p[0]);

    for (int i = 1; i < n - 1; ++i) {
        // Check if p[i] is a local extremum
        // p[i] is a peak if p[i-1] < p[i] and p[i] > p[i+1]
        // p[i] is a valley if p[i-1] > p[i] and p[i] < p[i+1]
        bool is_peak = (p[i] > p[i-1] && p[i] > p[i+1]);
        bool is_valley = (p[i] < p[i-1] && p[i] < p[i+1]);

        if (is_peak || is_valley) {
            result_subsequence.push_back(p[i]);
        }
    }
    result_subsequence.push_back(p[n-1]);

    std::cout << result_subsequence.size() << "\n";
    for (size_t i = 0; i < result_subsequence.size(); ++i) {
        std::cout << result_subsequence[i] << (i == result_subsequence.size() - 1 ? "" : " ");
    }
    std::cout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will track the rightmost point x_k for a given x_i

    for (int i = 0; i < n; ++i) {
        // For each x_i, we need to find all x_k such that x_k - x_i <= d.
        // Since x is sorted, we can advance right_ptr.
        // right_ptr will always be >= i.
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // At this point, all points from x[i] to x[right_ptr - 1] satisfy the condition with x[i].
        // We need to choose two distinct points x_j and x_k from the range (x_i, x_{right_ptr-1}].
        // The number of available points in this range (excluding x_i itself) is (right_ptr - 1) - i.
        // Let m = (right_ptr - 1) - i. These are the points x_{i+1}, ..., x_{right_ptr-1}.
        // We need to choose 2 points from these m points.
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        // The number of points available to be x_j or x_k (where j, k > i) is (right_ptr - 1) - i.
        // Let's call this number 'num_candidates'.
        // num_candidates = (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // If right_ptr - 1 is the index of the last valid point, then the number of points
        // in the range [i+1, right_ptr-1] is (right_ptr-1) - (i+1) + 1 = right_ptr - 1 - i.
        // Let's denote this as 'k_count'.
        long long k_count = right_ptr - 1 - i;

        if (k_count >= 2) {
            count += k_count * (k_count - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost to make the current median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Elements to the left of the median (smaller half)
    // These elements must be <= s to maintain s as median
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of the median (larger half)
    // These elements must be >= s to maintain s as median
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

