// Function to check if a sub-array is a permutation of 1 to len
// This version uses a frequency array and checks max element
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) {
        return false; // Permutations must have non-zero length
    }
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len;
}

