    // Precompute properties for suffixes
    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    int max_suffix_val = 0;
    bool suffix_valid = true;
    for (int i = n - 1; i >= 0; --i) {
        int current_val = a[i];
        int suffix_len = n - i;
        if (current_val <= 0 || current_val > suffix_len || seen_suffix[current_val]) {
            suffix_valid = false;
        }
        seen_suffix[current_val] = true;
        if (current_val > max_suffix_val) {
            max_suffix_val = current_val;
        }
        if (suffix_valid && max_suffix_val == suffix_len) {
            is_suffix_perm[suffix_len] = true;
        } else {
            is_suffix_perm[suffix_len] = false;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 is length of p1, from 1 to n-1
        int l2 = n - l1; // l2 is length of p2
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

