            counts[c]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Iterate in a fixed order to ensure consistent tie-breaking if needed,
        // though any tie-breaking is fine for this problem.
        // R, P, S is a common order.
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }

        // If all counts are 0 (empty string, though n >= 1), this logic still works.
        // If n=1, one char will have count 1, others 0.
        // If s is "R", counts['R']=1, max_count=1, most_frequent_bot_move='R'.
        // Then winning_move = 'P'. Output "P". Correct.

        char winning_move = get_winning_move(most_frequent_bot_move);

        for (size_t i = 0; i < s.length(); ++i) {
