        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;
    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 != 0) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case: N=2, P1 takes 1, P2 takes 1. P1 gets 1.
                chanek_coins += 1;
                n -= 1; // N becomes 1, next turn P2 takes 1.
            } else if ((n / 2) % 2 != 0) { // N/2 is odd
                // If P1 takes N/2, N becomes N/2 (odd). P2 takes 1.
                // If P1 takes 1, N becomes N-1 (odd). P2 takes 1.
                // Taking N/2 is better for P1 if N/2 > 1.
                // If N/2 = 1, then N=2, handled above.
                chanek_coins += n / 2;
                n /= 2;
            } else { // N/2 is even
                // If P1 takes N/2, N becomes N/2 (even). P2 can take N/4.
                // If P1 takes 1, N becomes N-1 (odd). P2 takes 1.
                // P1 takes 1 to force P2 to take 1, leaving more for P1 later.
                chanek_coins += 1;
                n -= 1;
            }
        }
        // Opponent's turn logic (implicitly handled by the loop structure)
        // If n > 0, it's opponent's turn.
        // Opponent will apply similar logic to maximize their coins.
        // We only care about Chanek's coins, so we just simulate the opponent's optimal move
        // by reducing n based on what the opponent would take.
        if (n > 0) {
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                if (n == 2) {
                    n -= 1;
                } else if ((n / 2) % 2 != 0) { // N/2 is odd
                    n /= 2;
                } else { // N/2 is even
                    n -= 1;
                }
            }
        }
    }
    return chanek_coins;
}

