int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::vector<int> w(k);
        for (int i = 0; i < k; ++i) {
            std::cin >> w[i];
        }

        std::sort(a.begin(), a.end());
        std::sort(w.begin(), w.end());

        long long total_happiness = 0;
        int a_ptr_left = 0;
        int a_ptr_right = n - 1;

        // Handle friends with w_i = 1 first
        // These friends should get the largest remaining numbers
        for (int i = k - 1; i >= 0; --i) {
            if (w[i] == 1) {
                total_happiness += a[a_ptr_right] * 2;
                a_ptr_right--;
            } else {
                // Since w is sorted, all remaining w[i] will be > 1
                break;
            }
        }

        // Handle friends with w_i > 1
        // These friends need one largest number and one smallest number from their assigned w_i numbers.
        // To maximize sum, give the largest remaining numbers to be their max_val.
        // Give the smallest remaining numbers to be their min_val.
        // The w_i-2 numbers in between don't affect max/min, so we can use up small numbers for them.
        for (int i = k - 1; i >= 0; --i) {
            if (w[i] > 1) {
                total_happiness += a[a_ptr_right]; // Max value for this friend
                a_ptr_right--;

                total_happiness += a[a_ptr_left]; // Min value for this friend
                a_ptr_left += (w[i] - 1); // Consume w_i - 1 smallest numbers
            }
        }

        std::cout << total_happiness << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // First pass: Determine necessary '0's in w based on '0's in s
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Second pass: Verify if the constructed w can produce s
    std::string s_prime(n, '0'); // This will be the s generated by our candidate w
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_prime[i] = '1';
        } else {
            s_prime[i] = '0';
        }
    }

    if (s == s_prime) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

