int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long b_count = 0;
    long long power_of_2 = 1; // Represents 2^b_count
    const long long MOD = 1e9 + 7;

    // Iterate through the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % MOD;
            power_of_2 = (power_of_2 * 2) % MOD;
        } else { // s[i] == 'a'
            // Each 'a' needs to jump over all 'b's to its right.
            // If there are 'k' 'b's to its right, this 'a' will cause 'k' operations.
            // However, each operation 'ab' -> 'bba' effectively doubles the number of 'b's
            // that an 'a' to its left will see.
            // So, if an 'a' encounters 'b_count' 'b's, it contributes 'b_count' steps.
            // After this 'a' is processed, it effectively becomes 'b's for 'a's to its left.
            // The number of 'b's it contributes is 2^b_count.
            // The number of steps it adds is the current 'b_count'.
            total_steps = (total_steps + b_count) % MOD;
            b_count = (b_count + power_of_2) % MOD; // This 'a' effectively becomes 2^b_count 'b's for 'a's to its left.
                                                     // This is equivalent to saying that for each 'b' to the right of this 'a',
                                                     // this 'a' will generate a new 'b' when it passes it.
                                                     // So, if there are 'k' 'b's, this 'a' will generate 'k' new 'b's.
                                                     // The total number of 'b's that 'a's to the left will see
                                                     // increases by 2^k (the original 'k' 'b's plus 'k' new 'b's,
                                                     // and then those new 'b's also double the count for the next 'a', etc.)
                                                     // The logic is: when an 'a' is processed, it adds `b_count` steps.
                                                     // Then, for any 'a' to its left, this 'a' effectively becomes `2^b_count` 'b's.
                                                     // So, `b_count` for the next 'a' (to the left) increases by `2^b_count`.
            power_of_2 = (power_of_2 * 2) % MOD; // This 'a' effectively doubles the 'power_of_2' for the next 'a' to its left.
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need S' = 2 * X'
    // Let S_orig = current_sum, X_orig = current_xor_sum
    // We want to find b1, b2, b3 such that
    // S_orig + b1 + b2 + b3 = 2 * (X_orig ^ b1 ^ b2 ^ b3)

    // Strategy: Append at most 3 elements.
    // It's always possible to append 2 elements.
    // Let's try to append two elements, say x and y.
    // S_orig + x + y = 2 * (X_orig ^ x ^ y)

    // A common strategy for these problems is to make the XOR sum equal to some value,
    // and then adjust the sum.
    // Let's try to make the final XOR sum equal to X_orig.
    // If we append X_orig, then the new XOR sum is X_orig ^ X_orig = 0.
    // This doesn't seem right.

    // Let's try to make the final XOR sum equal to some value K.
    // And the final sum equal to 2K.

    // Consider appending two elements: X_orig and current_sum + X_orig.
    // Let b1 = current_xor_sum.
    // New XOR sum: X_orig ^ b1 = X_orig ^ X_orig = 0.
    // New sum: S_orig + b1 = S_orig + X_orig.
    // Now we need S_orig + X_orig = 2 * 0, which means S_orig + X_orig = 0.
    // This is only true if S_orig = 0 and X_orig = 0, which is not generally true.

    // Let's try to append two elements: X_orig and S_orig + X_orig.
    // Let b1 = X_orig.
    // Let b2 = S_orig + X_orig.
    // New XOR sum: X_orig ^ b1 ^ b2 = X_orig ^ X_orig ^ (S_orig + X_orig) = 0 ^ (S_orig + X_orig) = S_orig + X_orig.
    // New sum: S_orig + b1 + b2 = S_orig + X_orig + (S_orig + X_orig) = 2 * (S_orig + X_orig).
    //
    // So, if we append b1 = X_orig and b2 = S_orig + X_orig,
    // The new sum is S' = S_orig + X_orig + (S_orig + X_orig) = 2 * (S_orig + X_orig).
    // The new XOR sum is X' = X_orig ^ X_orig ^ (S_orig + X_orig) = S_orig + X_orig.
    //
    // The condition S' = 2 * X' becomes
    // 2 * (S_orig + X_orig) = 2 * (S_orig + X_orig).
    // This is always true!
    //
    // The only constraint is that appended elements must be non-negative.
    // X_orig is non-negative (XOR sum of non-negative numbers).
    // S_orig is non-negative (sum of non-negative numbers).
    // So S_orig + X_orig is also non-negative.
    //
    // This strategy always works and appends exactly 2 elements.
    // The problem statement says "at most 3 elements" and "you don't have to minimize".
    // So appending 2 elements is fine.

    // Example 1: [1, 2, 3, 6]
    // S_orig = 12, X_orig = 1^2^3^6 = 6
    // S_orig = 2 * X_orig (12 = 2 * 6). Already good. Output 0.
    // My strategy would output 2 elements: X_orig=6, S_orig+X_orig=12+6=18.
    // New array: [1,2,3,6,6,18]. Sum=12+6+18=36. XOR=6^6^18=18. 36 = 2*18. Correct.
    // The example output is 0. This means if it's already good, we can output 0.

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        std::cout << 2 << std::endl;
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
    }
}

