// Function to get distinct prime factors of a number
std::set<long long> get_distinct_prime_factors(long long n) {
    std::set<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.insert(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.insert(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find x < p such that p % x == 0 and x % q != 0.
        // The largest such x will be p / (some factor of q that makes x not divisible by q).
        // We want to remove the minimum necessary factors from p to make it not divisible by q.
        // This means we want to divide p by the smallest possible factor 'f' such that (p/f) % q != 0.
        // Or, equivalently, we want to maximize x = p / f.
        // This means we want to minimize f.
        // The factors 'f' we consider must be factors of p.
        // If x = p/f is not divisible by q, it means that the prime factorization of x
        // does not contain all prime factors of q with sufficient powers.

        // Let's find distinct prime factors of q.
        std::set<long long> q_distinct_prime_factors = get_distinct_prime_factors(q);

        long long max_x = 0;

        for (long long prime_factor : q_distinct_prime_factors) {
            // For each distinct prime factor 'f' of q, we try to remove all occurrences of 'f' from p
            // until p is no longer divisible by q.
            // Or, more precisely, we want to find the largest divisor of p, say x_candidate,
            // such that x_candidate is not divisible by q.
            // We can construct such an x_candidate by taking p and dividing it by powers of 'prime_factor'.

            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= prime_factor;
            }
            // current_p is now a divisor of original p, and current_p is not divisible by q.
            // This current_p is a candidate for max_x.
            // We need to ensure current_p is still a divisor of original p.
            // The loop `while (current_p % q == 0)` ensures that we divide `p` by `prime_factor`
            // until `p` is no longer divisible by `q`.
            // This `current_p` is `p / (prime_factor^k)` for some `k`.
            // This `current_p` is guaranteed to be a divisor of the original `p`.
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int correct_sequences = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // If the first matryoshka in a chain is 1, it's a potential start of the main sequence.
        // We need to count how many consecutive correct nestings (j -> j+1) exist starting from 1.
        if (chain[0] == 1) {
            int current_expected = 1;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == current_expected) {
                    correct_sequences++;
                    current_expected++;
                } else {
                    // The sequence 1 -> 2 -> ... -> current_expected-1 is correct.
                    // Any further elements in this chain are not part of the initial correct prefix.
                    break; 
                }
            }
        }
    }

    // Total operations needed:
    // 1. Disassemble all incorrect nestings.
    //    Each chain of length `m` has `m-1` nestings.
    //    Total initial nestings = n - k (since sum of m_i = n, and each chain has m_i-1 nestings)
    //    Number of correct nestings (1->2, 2->3, ...) is `correct_sequences - 1`.
    //    So, `(n - k) - (correct_sequences - 1)` nestings need to be undone.
    //    Each undo operation costs 1 second.
    //    This simplifies to `n - k - correct_sequences + 1` operations.
    // 2. Reassemble the final chain.
    //    The final chain `1 -> 2 -> ... -> n` requires `n-1` nestings.
    //    We already have `correct_sequences - 1` of these.
    //    So, `(n-1) - (correct_sequences - 1)` new nestings need to be performed.
    //    Each new nesting operation costs 1 second.
    //    This simplifies to `n - correct_sequences` operations.

    // Total operations = (disassemble incorrect) + (assemble missing correct)
    // Total operations = ( (n - k) - (correct_sequences - 1) ) + ( (n - 1) - (correct_sequences - 1) )
    // Total operations = (n - k - correct_sequences + 1) + (n - correct_sequences)
    // Total operations = n - k - correct_sequences + 1 + n - correct_sequences
    // Total operations = 2*n - k - 2*correct_sequences + 1

    // Let's re-evaluate.
    // We need to form n-1 connections (1->2, 2->3, ..., (n-1)->n).
    // `correct_sequences - 1` of these connections are already present and correct.
    // So, `(n-1) - (correct_sequences - 1)` connections need to be *made*. This is `n - correct_sequences` 'put' operations.

    // For the 'get out' operations:
    // Each chain has `m_i` dolls. If `m_i > 1`, it has `m_i - 1` internal nestings.
    // The total number of initial nestings across all chains is `(m_1-1) + (m_2-1) + ... + (m_k-1) = (m_1+...+m_k) - k = n - k`.
    // Out of these `n-k` initial nestings, `correct_sequences - 1` are part of the final `1->2->...->n` sequence.
    // The remaining `(n-k) - (correct_sequences - 1)` nestings must be undone. These are 'get out' operations.
    // This simplifies to `n - k - correct_sequences + 1` 'get out' operations.

    total_operations = (long long)(n - correct_sequences) + (long long)(n - k - correct_sequences + 1);

    std::cout << total_operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (char pivot_char = '0'; pivot_char <= '9'; ++pivot_char) {
        std::string coloring(n, ' ');
        char last_digit_color1 = '0'; // Smallest possible digit
        char first_digit_color2 = '9' + 1; // Largest possible digit + 1
        bool possible_pivot = true;

        // First pass: assign digits based on pivot_char
        // Digits < pivot_char go to color 1
        // Digits > pivot_char go to color 2
        // Digits == pivot_char are initially unassigned (marked with '0' for now)
        for (int i = 0; i < n; ++i) {
            if (s[i] < pivot_char) {
                coloring[i] = '1';
                if (s[i] < last_digit_color1) { // Check non-decreasing for color 1
                    possible_pivot = false;
                    break;
                }
                last_digit_color1 = s[i];
            } else if (s[i] > pivot_char) {
                coloring[i] = '2';
                // We can't check first_digit_color2 yet, as it might be set by a later digit
                // This check will be done in the second pass or implicitly by the final check
            } else { // s[i] == pivot_char
                coloring[i] = '0'; // Mark as unassigned for now
            }
        }

        if (!possible_pivot) {
            continue;
        }

        // Second pass: assign digits == pivot_char
        // All digits == pivot_char that appear BEFORE the first digit > pivot_char must be color 1
        // All digits == pivot_char that appear AFTER the first digit > pivot_char must be color 2
        // This ensures S1 is non-decreasing and S2 is non-decreasing.
        // The boundary is where the first digit > pivot_char is encountered.
        // If no digit > pivot_char, all pivot_char digits can be color 1.
        // If no digit < pivot_char, all pivot_char digits can be color 2.

        bool seen_digit_greater_than_pivot = false;
        for (int i = 0; i < n; ++i) {
            if (s[i] > pivot_char) {
                seen_digit_greater_than_pivot = true;
            }
            if (s[i] == pivot_char) {
                if (!seen_digit_greater_than_pivot) {
                    coloring[i] = '1';
                    if (s[i] < last_digit_color1) { // Check non-decreasing for color 1
                        possible_pivot = false;
                        break;
                    }
                    last_digit_color1 = s[i];
                } else {
                    coloring[i] = '2';
                }
            }
        }

        if (!possible_pivot) {
            continue;
        }

        // Final check for the entire sequence S1 + S2
        std::string s1_str = "";
        std::string s2_str = "";
        for (int i = 0; i < n; ++i) {
            if (coloring[i] == '1') {
                s1_str += s[i];
            } else { // coloring[i] == '2'
                s2_str += s[i];
            }
        }

        std::string combined_str = s1_str + s2_str;
        bool sorted = true;
        for (int i = 0; i < n - 1; ++i) {
            if (combined_str[i] > combined_str[i+1]) {
                sorted = false;
                break;
            }
        }

        if (sorted) {
            std::cout << coloring << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

