    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_chars(k, '?'); // Stores the determined character for each remainder i % k

    // Step 1: Propagate constraints from existing '0's and '1's
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            int remainder = i % k;
            if (fixed_chars[remainder] == '?') {
                fixed_chars[remainder] = s[i];
            } else if (fixed_chars[remainder] != s[i]) {
                // Conflict: s[i] contradicts a previously determined character for this remainder
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Check if the first k characters can be made k/2 zeros and k/2 ones
    int zeros_count = 0;
    int ones_count = 0;
    int unknown_count = 0;

    for (int i = 0; i < k; ++i) {
        if (fixed_chars[i] == '0') {
            zeros_count++;
        } else if (fixed_chars[i] == '1') {
            ones_count++;
        } else { // fixed_chars[i] == '?'
            unknown_count++;
        }
    }

    int target_half = k / 2;

    if (zeros_count > target_half || ones_count > target_half) {
        // Too many 0s or 1s already in the first k positions
        std::cout << "NO\n";
        return;
    }

    // We need (target_half - zeros_count) more zeros and (target_half - ones_count) more ones.
    // The remaining unknown_count must be exactly equal to these needed counts combined.
    // (target_half - zeros_count) + (target_half - ones_count) == unknown_count
    // k - (zeros_count + ones_count) == unknown_count
    // This is always true by definition of unknown_count.
    // The crucial check is that we have enough '?' to fill the deficit.
    // This is implicitly handled by the `zeros_count > target_half || ones_count > target_half` check.
    // If zeros_count <= target_half and ones_count <= target_half, then we can always fill the remaining '?'s
    // to satisfy the k/2 condition for the first block.

    std::cout << "YES\n";
}

