    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;
    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum_r = sum_{r=1}^{b-1} r = (b-1) * b / 2
    // This sum needs to be calculated modulo MOD.
    // Since b-1 and b are consecutive, one is even.
    // So, (b-1)*b is always divisible by 2.
    // We need to find (b-1) * b * inv(2) mod MOD.
    // inv(2) mod MOD is (MOD + 1) / 2 because MOD is odd.
    long long sum_r_term = (b - 1);
    sum_r_term %= MOD;
    long long b_term = b;
    b_term %= MOD;

    long long sum_r = (sum_r_term * b_term) % MOD;
    long long inv2 = (MOD + 1) / 2;
    sum_r = (sum_r * inv2) % MOD;

    // Sum_k = sum_{k=1}^{a} (k * b + 1)
    // Sum_k = sum_{k=1}^{a} (k * b) + sum_{k=1}^{a} 1
    // Sum_k = b * sum_{k=1}^{a} k + a
    // Sum_k = b * (a * (a+1) / 2) + a
    // This sum also needs to be calculated modulo MOD.
    long long sum_k_part1_a = a;
    sum_k_part1_a %= MOD;
    long long sum_k_part1_a_plus_1 = (a + 1);
    sum_k_part1_a_plus_1 %= MOD;

    long long sum_k_part1_numerator = (sum_k_part1_a * sum_k_part1_a_plus_1) % MOD;
    long long sum_k_part1 = (sum_k_part1_numerator * inv2) % MOD;

    long long sum_k_b_term = b;
    sum_k_b_term %= MOD;

    sum_k_part1 = (sum_k_part1 * sum_k_b_term) % MOD;

    long long sum_k_part2 = a;
    sum_k_part2 %= MOD;

    long long sum_k = (sum_k_part1 + sum_k_part2) % MOD;

    long long total_sum = (sum_r * sum_k) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

