#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> d(n);
    std::deque<int> q;

    // Initialize distances for blocks adjacent to ground (y=0)
    // These blocks are destroyed in 1 operation.
    // The effective height for these blocks is 1.
    for (int i = 0; i < n; ++i) {
        d[i] = 1;
        q.push_back(i);
    }

    // BFS to propagate minimum operations from ground
    int head = 0;
    while(head < q.size()){
        int u = q[head++];

        // Propagate to left neighbor
        if (u > 0) {
            // If tower u-1 is taller than tower u, and its current min_ops is not set
            // or can be improved by coming from u.
            // The effective height for tower u-1 from this path would be d[u] + 1.
            // We take min(h[u-1], d[u]+1) because the block at (u-1, d[u]) would be destroyed
            // in d[u]+1 operations if it were only limited by the right side.
            // But it's also limited by its own height.
            long long new_d_val = std::min(h[u-1], d[u] + 1);
            if (new_d_val > d[u-1]) { // If we found a better path (more operations)
                d[u-1] = new_d_val;
                q.push_back(u-1); // Add to queue to propagate further
            }
        }
        // Propagate to right neighbor
        if (u < n - 1) {
            long long new_d_val = std::min(h[u+1], d[u] + 1);
            if (new_d_val > d[u+1]) {
                d[u+1] = new_d_val;
                q.push_back(u+1);
            }
        }
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, d[i]);
    }

    std::cout << max_ops << std::endl;

    return 0;
}

