int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: [1, 1], len = 1
        // Add -a[0] to a[0]. -a[0] is a multiple of 1.
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        a[0] = 0;

        // Operation 2: [1, 1], len = 1
        // Add 0 to a[0]. 0 is a multiple of 1.
        std::cout << "1 1\n";
        std::cout << "0\n";

        // Operation 3: [1, 1], len = 1
        // Add 0 to a[0]. 0 is a multiple of 1.
        std::cout << "1 1\n";
        std::cout << "0\n";
        return 0;
    }

    // Operation 1: Make a[0]...a[n-2] divisible by n.
    // Segment [1, n-1], length n-1.
    // For each a[i] in this segment, we want to add x_i such that (a[i] + x_i) % n == 0.
    // And x_i must be a multiple of (n-1).
    // This is equivalent to (a[i] % n + x_i % n) % n == 0.
    // We need to find x_i such that x_i % (n-1) == 0 and (a[i] + x_i) % n == 0.
    // Let a[i] % n = r_i. We need (r_i + x_i) % n == 0.
    // So x_i % n = (n - r_i) % n.
    // We need x_i = k * (n-1) for some integer k.
    // So k * (n-1) % n = (n - r_i) % n.
    // k * (-1) % n = (n - r_i) % n.
    // -k % n = (n - r_i) % n.
    // k % n = r_i % n.
    // So we can choose k = r_i.
    // Then x_i = r_i * (n-1).
    // This x_i is a multiple of (n-1).
    // And (a[i] + x_i) % n = (a[i] + r_i * (n-1)) % n = (a[i] + (a[i]%n) * (-1)) % n = (a[i] - a[i]%n) % n = 0.
    // This works for a[0]...a[n-2].

    std::cout << "1 " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long remainder = (a[i] % n + n) % n; // Ensure positive remainder
        long long add_val = remainder * (n - 1);
        std::cout << add_val << (i == n - 2 ? "" : " ");
        a[i] += add_val;
    }
    std::cout << "\n";

    // Operation 2: Make a[n-1] divisible by n.
    // Segment [n, n], length 1.
    // For a[n-1], we want to add x such that (a[n-1] + x) % n == 0.
    // x must be a multiple of 1. This is always true for any integer x.
    // So we can choose x = (n - (a[n-1] % n + n) % n) % n.
    // Or simply x = - (a[n-1] % n + n) % n.
    // This makes a[n-1] divisible by n.

    std::cout << n << " " << n << "\n";
    long long remainder_n_minus_1 = (a[n - 1] % n + n) % n;
    long long add_val_n_minus_1 = (n - remainder_n_minus_1) % n;
    std::cout << add_val_n_minus_1 << "\n";
    a[n - 1] += add_val_n_minus_1;

    // Now all elements a[0]...a[n-1] are divisible by n.
    // Operation 3: Make all elements zero.
    // Segment [1, n], length n.
    // For each a[i], we want to add x_i such that a[i] + x_i = 0.
    // x_i must be a multiple of n.
    // Since a[i] is already divisible by n, we can choose x_i = -a[i].
    // -a[i] is a multiple of n.

    std::cout << "1 " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_val_0 = 0;    // Value if input is 0
    int current_val_1023 = 1023; // Value if input is 1023 (all 1s for bits 0-9)

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;
        if (op_char == '&') {
            current_val_0 &= x;
            current_val_1023 &= x;
        } else if (op_char == '|') {
            current_val_0 |= x;
            current_val_1023 |= x;
        } else if (op_char == '^') {
            current_val_0 ^= x;
            current_val_1023 ^= x;
        }
    }

    // Determine the equivalent operations
    // We need to find A, O, X such that:
    // (0 & A | O ^ X) == current_val_0
    // (1023 & A | O ^ X) == current_val_1023

    // Let's find the effective AND mask (A), OR mask (O), and XOR mask (X)
    // for the bits 0-9.
    // For each bit j:
    // Let x_j be the j-th bit of the input.
    // Let a_j, o_j, x_j be the j-th bits of A, O, X respectively.
    // The final j-th bit is (x_j & a_j | o_j) ^ x_j.

    // Case 1: Input bit is 0
    // (0 & a_j | o_j) ^ x_j = o_j ^ x_j
    // This must be equal to the j-th bit of current_val_0.
    // So, (current_val_0 >> j) & 1 = o_j ^ x_j

    // Case 2: Input bit is 1
    // (1 & a_j | o_j) ^ x_j = (a_j | o_j) ^ x_j
    // This must be equal to the j-th bit of current_val_1023.
    // So, (current_val_1023 >> j) & 1 = (a_j | o_j) ^ x_j

    int final_and_mask = 1023; // All bits are 1 initially for AND
    int final_or_mask = 0;     // All bits are 0 initially for OR
    int final_xor_mask = 0;    // All bits are 0 initially for XOR

    for (int j = 0; j < 10; ++j) {
        int bit_0_result = (current_val_0 >> j) & 1;
        int bit_1_result = (current_val_1023 >> j) & 1;

        // We need to find a_j, o_j, x_j such that:
        // 1) o_j ^ x_j = bit_0_result
        // 2) (a_j | o_j) ^ x_j = bit_1_result

        // Let's analyze the 4 possible (bit_0_result, bit_1_result) pairs:
        // (0,0): Input 0 -> 0, Input 1 -> 0
        //   o_j ^ x_j = 0  => o_j = x_j
        //   (a_j | o_j) ^ x_j = 0 => (a_j | o_j) = x_j
        //   Since o_j = x_j, this means (a_j | o_j) = o_j. This implies a_j = 0.
        //   So, a_j=0, o_j=0, x_j=0 (or a_j=0, o_j=1, x_j=1).
        //   To minimize operations, we prefer a_j=0, o_j=0, x_j=0.
        //   This means the bit is always 0, regardless of input.
        //   This is achieved by `& 0` for this bit.
        if (bit_0_result == 0 && bit_1_result == 0) {
            final_and_mask &= ~(1 << j); // Set a_j to 0
            // o_j and x_j can be 0
        }
        // (0,1): Input 0 -> 0, Input 1 -> 1
        //   o_j ^ x_j = 0  => o_j = x_j
        //   (a_j | o_j) ^ x_j = 1 => (a_j | o_j) = x_j ^ 1
        //   Since o_j = x_j, this means (a_j | o_j) = o_j ^ 1.
        //   This implies a_j = 1 and o_j = 0 (so x_j = 0).
        //   So, a_j=1, o_j=0, x_j=0.
        //   This means the bit is unchanged (x_j -> x_j).
        //   This is achieved by `& 1` for this bit.
        else if (bit_0_result == 0 && bit_1_result == 1) {
            // a_j is 1 (default for final_and_mask)
            // o_j is 0 (default for final_or_mask)
            // x_j is 0 (default for final_xor_mask)
        }
        // (1,0): Input 0 -> 1, Input 1 -> 0
        //   o_j ^ x_j = 1  => o_j = x_j ^ 1
        //   (a_j | o_j) ^ x_j = 0 => (a_j | o_j) = x_j
        //   Since o_j = x_j ^ 1, this means (a_j | (x_j ^ 1)) = x_j.
        //   This implies a_j = 0 and x_j = 1 (so o_j = 0).
        //   So, a_j=0, o_j=0, x_j=1.
        //   This means the bit is inverted (x_j -> x_j ^ 1).
        //   This is achieved by `& 0` and `^ 1` for this bit.
        else if (bit_0_result == 1 && bit_1_result == 0) {
            final_and_mask &= ~(1 << j); // Set a_j to 0
            final_xor_mask |= (1 << j);  // Set x_j to 1
            // o_j is 0 (default for final_or_mask)
        }
        // (1,1): Input 0 -> 1, Input 1 -> 1
        //   o_j ^ x_j = 1  => o_j = x_j ^ 1
        //   (a_j | o_j) ^ x_j = 1 => (a_j | o_j) = x_j ^ 1
        //   Since o_j = x_j ^ 1, this means (a_j | o_j) = o_j. This implies a_j = 0.
        //   So, a_j=0, o_j=1, x_j=0 (or a_j=0, o_j=0, x_j=1).
        //   To minimize operations, we prefer a_j=0, o_j=1, x_j=0.
        //   This means the bit is always 1, regardless of input.
        //   This is achieved by `| 1` for this bit.
        else if (bit_0_result == 1 && bit_1_result == 1) {
            final_or_mask |= (1 << j); // Set o_j to 1
            // a_j and x_j can be 0
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_mask != 1023) { // If any bit of A is 0
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) { // If any bit of O is 1
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) { // If any bit of X is 1
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

