    std::vector<int> val(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        val[i] = (a[i] == 1 ? 1 : -1);
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // S_L[k] = sum(val[0]...val[k-1])
    std::vector<int> s_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        s_left[i + 1] = s_left[i] + val[i];
    }

    // Calculate suffix sums for the right half (jars n+1 to 2n)
    // S_R[k] = sum(val[2n-1]...val[2n-k])
    std::vector<int> s_right(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        s_right[i + 1] = s_right[i] + val[2 * n - 1 - i];
    }

    // Map to store the minimum number of jars removed from the left half
    // to achieve a certain balance difference.
    // key: balance difference (S-B)
    // value: number of jars removed (k_L)
    std::map<int, int> left_diff_to_kL;
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_diff = s_left[n] - s_left[k_L]; // Balance of remaining jars on left
        if (left_diff_to_kL.find(current_diff) == left_diff_to_kL.end()) {
            left_diff_to_kL[current_diff] = k_L;
        }
    }

    int min_removed = 2 * n; // Initialize with max possible removed jars

    // Iterate through possible number of jars removed from the right half (k_R)
    for (int k_R = 0; k_R <= n; ++k_R) {
        int current_diff_right = s_right[n] - s_right[k_R]; // Balance of remaining jars on right
        int target_diff_left = -current_diff_right; // We need S_L_rem - B_L_rem = -(S_R_rem - B_R_rem)

        if (left_diff_to_kL.count(target_diff_left)) {
            int k_L = left_diff_to_kL[target_diff_left];
            min_removed = std::min(min_removed, k_L + k_R);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;
        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }
        long long total_substrings = n * (n + 1) / 2;
        long long num_zeros = n - m;
        long long k = num_zeros / (m + 1);
        long long r = num_zeros % (m + 1);
        long long sum_zero_substrings = r * (k + 1) * (k + 2) / 2 + (m + 1 - r) * k * (k + 1) / 2;
        long long result = total_substrings - sum_zero_substrings;
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> deletion_order(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> deletion_order[i];
        deletion_order[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Process deletions in reverse order, effectively adding vertices
    for (int step = n - 1; step >= 0; --step) {
        int k = deletion_order[step]; // The vertex being "added" in this step
        active_vertices[k] = true;

        // Update shortest paths using k as an intermediate vertex
        // This is the core Floyd-Warshall step
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // After updating with k, also update paths between existing active vertices
        // using k as an intermediate. This is crucial because k might connect
        // two previously active vertices more efficiently.
        // The previous loop already did this for all i,j.
        // Now, we need to ensure all pairs of currently active vertices are updated
        // using any other currently active vertex as an intermediate.
        // Since we are adding vertices one by one, and updating dist[i][j] for all i,j
        // using the newly added vertex k, the dist matrix will always contain
        // shortest paths considering all vertices up to k.
        // So, we just need to sum up for currently active vertices.

        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (active_vertices[i]) {
                for (int j = 0; j < n; ++j) {
                    if (active_vertices[j]) {
                        current_sum += dist[i][j];
                    }
                }
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (before x_1, before x_2, ..., before x_n)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

