        // Now, we are at x_after_step3 with y_added_step2 + y_added_step3 accumulated.
        // We can use the precomputed DP table for x_after_step3.
        Result res = calculate_dp(x_after_step3); // This will use the precomputed values for x >= 2

        if (res.final_x == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << y_added_step2 + y_added_step3 + res.total_y << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Case k = 1 (2 pieces)
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) {
        std::string s_prefix = s.substr(0, i);
        std::string s_suffix = s.substr(i);
        std::string new_s = s_suffix + s_prefix;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2 (3 pieces)
    // If n is odd, and all characters are the same, it's impossible.
    // Example: "qqq", "qqqqq"
    // If n is even, and all characters are the same, it's impossible.
    // Example: "qq", "qqqq"
    // This check covers all cases where all characters are the same.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }
    if (all_same) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
    // Consider the string s = "nolon" (n=5)
    // s_prefix = "n", s_middle = "olo", s_suffix = "n"
    // Rearrange to s_suffix + s_middle + s_prefix = "n" + "olo" + "n" = "nolon" (original)
    // This is not what we want.
    //
    // The problem statement implies that if k=1 doesn't work, and it's not "all same characters",
    // then k=2 is the answer.
    //
    // Let's verify this.
    // If s is a palindrome and not all characters are the same,
    // then there must be at least one character s[i] such that s[i] != s[0].
    // Since s is a palindrome, s[i] == s[n-1-i].
    //
    // Consider cutting s into s[0...i-1], s[i], s[i+1...n-1].
    // This is 2 cuts.
    //
    // A simpler argument for k=2:
    // If s is a palindrome and not all characters are the same,
    // then s must contain at least two distinct characters.
    // For example, "abacaba".
    //
    // If we take s[0] and s[n-1] (which are equal), and move them to the middle,
    // or move the middle part to the ends.
    //
    // Consider the string s. Since it's a palindrome and not all characters are the same,
    // there must be some character s[i] such that s[i] != s[0].
    //
    // If n is odd, say n = 2m + 1.
    // s = s[0...m-1] + s[m] + s[m+1...2m]
    // s[0...m-1] is the reverse of s[m+1...2m].
    // Let P = s[0...m-1], M = s[m], S = s[m+1...2m].
    // s = P + M + S.
    // Since s is a palindrome, P is reverse of S.
    //
    // If we cut s into s[0...n-2] and s[n-1].
    // s_prefix = s[0...n-2], s_suffix = s[n-1].
    // New string: s[n-1] + s[0...n-2].
    // This is a single cut. We already checked this.
    //
    // The problem statement implies that if k=1 doesn't work, and it's not "all same characters",
    // then k=2 is the answer.
    //
    // Example: "nolon"
    // n=5
    // k=1 checks:
    // "olon" + "n" = "olonn" (not palindrome)
    // "lon" + "no" = "lonno" (not palindrome)
    // "on" + "nol" = "onnol" (not palindrome)
    // "n" + "nolo" = "nnolo" (not palindrome)
    // So k=1 fails for "nolon".
    //
    // Since "nolon" is not all same characters, the answer is 2.
    // Example cuts for "nolon": no|l|on -> on|l|no. This is a palindrome and != "nolon".
    // This requires 2 cuts.
    //
    // The logic is:
    // 1. Try k=1. If a valid new palindrome is found, output 1.
    // 2. If k=1 fails, check if all characters in s are the same.
    //    If yes, output "Impossible".
    // 3. If k=1 fails and not all characters are the same, output 2.
    //
    // This covers all cases and matches the example outputs.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    if (n < 3) {
        std::cout << 0 << std::endl;
        return 0;
    }

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[l] stores the minimum r such that [l, r] contains a bad triplet.
                                                // If no such r exists, it's n+1.

    // Iterate through all possible starting positions x for a bad triplet
    for (int x = 0; x <= n - 3; ++x) {
        // Iterate through all possible k values
        // The maximum value for k is such that x + 2k < n
        // So 2k < n - x => k < (n - x) / 2
        // k must be at least 1
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a bad triplet (x, x+k, x+2k)
                // This triplet starts at index x (0-based) and ends at index x+2k (0-based).
                // In 1-based indexing, it starts at x+1 and ends at x+2k+1.
                // For any l_0-based such that l_0 <= x, and any r_0-based such that r_0 >= x+2k,
                // the interval [l_0, r_0] contains this bad triplet.
                // We are interested in the minimum r for a given l.
                // For a fixed l_0, the minimum r_0 that contains this triplet is x+2k.
                // So, for any l_0 from 0 to x, the minimum r_0 is x+2k.
                // We want to update min_r_for_l[l_0+1] with x+2k+1.
                // Since we want the minimum r for each l, we take std::min.

                // The current bad triplet (x, x+k, x+2k) implies that for any l_0-based index
                // from 0 up to x, the minimum r_0-based index that makes [l_0, r_0] valid
                // is at most x+2k.
                // So, for l_0 from 0 to x, min_r_for_l[l_0+1] should be updated with x+2k+1.
                // However, we only need to update min_r_for_l[x+1] because if min_r_for_l[x+1]
                // is updated to R, then for any l' < x+1, min_r_for_l[l'+1] will be at most R.
                // This is because if [x+1, R] contains a bad triplet, then [l'+1, R] also contains it.
                // So we only need to update min_r_for_l[x+1] with x+2k+1.
                // The actual minimum r for l will be propagated later.

                min_r_for_l[x + 1] = std::min(min_r_for_l[x + 1], x + 2 * k + 1);
            }
        }
    }

    // Propagate minimum r values.
    // If min_r_for_l[i] is R, then for any j < i, min_r_for_l[j] must be <= R.
    // So, min_r_for_l[i] = min(min_r_for_l[i], min_r_for_l[i+1]).
    // We iterate from n down to 1.
    for (int i = n - 1; i >= 1; --i) {
        min_r_for_l[i] = std::min(min_r_for_l[i], min_r_for_l[i + 1]);
    }

    long long total_valid_pairs = 0;
    for (int l = 1; l <= n; ++l) {
        if (min_r_for_l[l] <= n) { // If there is at least one r for this l
            // For a given l, any r from min_r_for_l[l] to n will form a valid pair.
            // The number of such r's is n - min_r_for_l[l] + 1.
            total_valid_pairs += (n - min_r_for_l[l] + 1);
        }
    }

    std::cout << total_valid_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    long long min_goodness = -1;
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., all 1s)
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    long long current_goodness_case1 = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    min_goodness = current_goodness_case1;
    for (int i = 0; i < n; ++i) {
        best_partition[a[i].original_index] = 1;
    }

    // Case 2: a[0] in one subsequence, a[1...n-1] in another
    // min_f:
    //   - a[0] + a[1] + h (a[0] and a[1] different)
    //   - a[1] + a[2] (a[1] and a[2] same)
    // max_f:
    //   - a[n-2] + a[n-1] (a[n-2] and a[n-1] same)
    //   - a[0] + a[n-1] + h (a[0] and a[n-1] different)
    //
    // min_f = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value)
    // max_f = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h)
    //
    // This simplifies to:
    // min_f = a[0].value + a[1].value + h (if n=2, this is the only option for min_f involving a[0])
    // min_f = a[1].value + a[2].value (if n > 2, this is the smallest sum within the larger group)
    //
    // The minimum possible f value is always a[0].value + a[1].value + h (if a[0] and a[1] are separated)
    // OR a[1].value + a[2].value (if a[0] is separated and a[1], a[2] are together).
    //
    // The maximum possible f value is always a[n-2].value + a[n-1].value (if a[n-2], a[n-1] are together)
    // OR a[0].value + a[n-1].value + h (if a[0] and a[n-1] are separated).

    // Let's consider the specific partition: a[0] in group 1, a[1...n-1] in group 2.
    // Values of f:
    // 1. a[i] + a[j] for i,j in [1, n-1] (same group)
    // 2. a[0] + a[j] + h for j in [1, n-1] (different groups)
    //
    // min_f = std::min(a[1].value + a[2].value (if n > 2), a[0].value + a[1].value + h)
    // max_f = std::max(a[n-2].value + a[n-1].value (if n > 2), a[0].value + a[n-1].value + h)
    //
    // If n=2: a[0] in group 1, a[1] in group 2. Only f(a[0], a[1]) = a[0].value + a[1].value + h.
    // min_f = max_f = a[0].value + a[1].value + h. Goodness = 0.
    // This is handled by the general logic below.

    long long current_min_f_case2;
    if (n == 2) {
        current_min_f_case2 = a[0].value + a[1].value + h;
    } else {
        current_min_f_case2 = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
    }

    long long current_max_f_case2;
    if (n == 2) {
        current_max_f_case2 = a[0].value + a[1].value + h;
    } else {
        current_max_f_case2 = std::max(a[n - 2].value + a[n - 1].value, a[0].value + a[n - 1].value + h);
    }

    long long current_goodness_case2 = current_max_f_case2 - current_min_f_case2;

    if (current_goodness_case2 < min_goodness) {
        min_goodness = current_goodness_case2;
        best_partition[a[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            best_partition[a[i].original_index] = 2;
        }
    }

    // Case 3: a[0...n-2] in one subsequence, a[n-1] in another
    // This is symmetric to Case 2.
    // Values of f:
    // 1. a[i] + a[j] for i,j in [0, n-2] (same group)
    // 2. a[i] + a[n-1] + h for i in [0, n-2] (different groups)
    //
    // min_f = std::min(a[0].value + a[1].value (if n > 2), a[0].value + a[n-1].value + h)
    // max_f = std::max(a[n-3].value + a[n-2].value (if n > 2), a[n-2].value + a[n-1].value + h)
    //
    // If n=2: a[0] in group 1, a[1] in group 2. Only f(a[0], a[1]) = a[0].value + a[1].value + h.
    // min_f = max_f = a[0].value + a[1].value + h. Goodness = 0.
    // This is handled by the general logic below.

    long long current_min_f_case3;
    if (n == 2) {
        current_min_f_case3 = a[0].value + a[1].value + h;
    } else {
        current_min_f_case3 = std::min(a[0].value + a[1].value, a[0].value + a[n - 1].value + h);
    }

    long long current_max_f_case3;
    if (n == 2) {
        current_max_f_case3 = a[0].value + a[1].value + h;
    } else {
        current_max_f_case3 = std::max(a[n - 3].value + a[n - 2].value, a[n - 2].value + a[n - 1].value + h);
    }

    long long current_goodness_case3 = current_max_f_case3 - current_min_f_case3;

    if (current_goodness_case3 < min_goodness) {
        min_goodness = current_goodness_case3;
        for (int i = 0; i < n - 1; ++i) {
            best_partition[a[i].original_index] = 1;
        }
        best_partition[a[n - 1].original_index] = 2;
    }

    // Case 4: a[0] and a[n-1] in one subsequence, a[1...n-2] in another
    // This case is only relevant if n >= 3.
    if (n >= 3) {
        // Group 1: {a[0], a[n-1]}
        // Group 2: {a[1], ..., a[n-2]}
        //
        // Values of f:
        // 1. a[0] + a[n-1] (same group)
        // 2. a[i] + a[j] for i,j in [1, n-2] (same group)
        // 3. a[0] + a[j] + h for j in [1, n-2] (different groups)
        // 4. a[n-1] + a[j] + h for j in [1, n-2] (different groups)
        //
        // min_f:
        //   - a[0] + a[n-1]
        //   - a[1] + a[2] (if n-2 >= 2, i.e., n >= 4)
        //   - a[0] + a[1] + h
        //   - a[1] + a[n-1] + h
        //
        // max_f:
        //   - a[0] + a[n-1]
        //   - a[n-3] + a[n-2] (if n-2 >= 2, i.e., n >= 4)
        //   - a[0] + a[n-2] + h
        //   - a[n-2] + a[n-1] + h

        long long current_min_f_case4 = a[0].value + a[1].value + h; // Smallest cross-group sum
        if (n >= 4) { // If group 2 has at least two elements
            current_min_f_case4 = std::min(current_min_f_case4, a[1].value + a[2].value); // Smallest within group 2
        }
        current_min_f_case4 = std::min(current_min_f_case4, a[0].value + a[n - 1].value); // Smallest within group 1

        long long current_max_f_case4 = a[n - 2].value + a[n - 1].value + h; // Largest cross-group sum
        if (n >= 4) { // If group 2 has at least two elements
            current_max_f_case4 = std::max(current_max_f_case4, a[n - 3].value + a[n - 2].value); // Largest within group 2
        }
        current_max_f_case4 = std::max(current_max_f_case4, a[0].value + a[n - 1].value); // Largest within group 1

        long long current_goodness_case4 = current_max_f_case4 - current_min_f_case4;

        if (current_goodness_case4 < min_goodness) {
            min_goodness = current_goodness_case4;
            best_partition[a[0].original_index] = 1;
            best_partition[a[n - 1].original_index] = 1;
            for (int i = 1; i < n - 1; ++i) {
                best_partition[a[i].original_index] = 2;
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All target tracks covered
            return true;
        }

        long long current_h = h[h_idx];
        long long left_reach = current_h - T;
        long long right_reach = current_h + T;

        // If the current head cannot reach the current target track p[p_idx]
        // even by moving right, then this head cannot cover it.
        // We need to find a head that can cover p[p_idx].
        // If p[p_idx] is too far to the right of current_h + T, this head is useless for p[p_idx]
        // and subsequent heads might be too far as well.
        // However, the problem states heads can change relative order.
        // The greedy approach is to use the current head h_idx to cover as many
        // *remaining* target tracks as possible, starting from p[p_idx].

        // If p[p_idx] is to the left of current_h - T, this head cannot cover p[p_idx]
        // without moving left more than T. Since heads are sorted, this head
        // is the best candidate for p[p_idx] among heads that are to its left or at its position.
        // If p[p_idx] is too far left for current_h, then no subsequent head can cover it.
        // This is not true. A head h_k where k > h_idx might be able to cover p[p_idx]
        // if h_k is close enough to p[p_idx].
        // The greedy strategy should be:
        // For the current head h_idx, find the first target track p[p_idx] that it can cover.
        // If it can cover p[p_idx], then it can cover all tracks in [p[p_idx], right_reach].
        // Advance p_idx past all tracks covered by this head.

        // Find the first p[p_idx] that current_h can reach.
        // If p[p_idx] is already covered by a previous head, or if current_h is too far right
        // to cover p[p_idx] (i.e., p[p_idx] < left_reach), then this head cannot cover p[p_idx].
        // We need to find a head that can cover p[p_idx].
        // The current head h_idx can cover any track in [left_reach, right_reach].
        // We want to cover p[p_idx] using h_idx.
        // If p[p_idx] is outside [left_reach, right_reach], this head cannot cover it.
        // Specifically, if p[p_idx] > right_reach, this head cannot cover it.
        // If p[p_idx] < left_reach, this head cannot cover it.
        // But since h and p are sorted, and we process p_idx sequentially,
        // p[p_idx] will always be >= the last covered track.
        // So we only need to worry about p[p_idx] > right_reach.

        // If p[p_idx] is too far to the left for the current head h_idx to cover,
        // i.e., p[p_idx] < left_reach, then this head cannot cover p[p_idx].
        // Since h is sorted, all subsequent heads h_k (k > h_idx) will be even further
        // to the right, so they also cannot cover p[p_idx].
        // Thus, if p[p_idx] < left_reach, it's impossible to cover p[p_idx] with any remaining head.
        // This means T is too small.
        if (p[p_idx] < left_reach) {
            return false;
        }

        // If p[p_idx] is within reach of current_h, then current_h can cover it.
        // Now, current_h can cover all tracks up to right_reach.
        // Advance p_idx past all tracks that current_h can cover.
        while (p_idx < m && p[p_idx] <= right_reach) {
            p_idx++;
        }
    }

    return p_idx == m; // All target tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible difference between p_i and h_i is ~10^10.
                               // A single head might need to move from 1 to 10^10.
                               // Max p_m - min h_1 or max h_n - min p_1.
                               // Max value of p_i or h_i is 10^10.
                               // So max T could be 10^10.
                               // 2e10 + 7 is a safe upper bound.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        int min_x = -100000;
        int max_x = 100000;
        int min_y = -100000;
        int max_y = 100000;

        for (int i = 0; i < n; ++i) {
            int x, y, f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1: can move left (x-1, y)
            // If f1 is 0, robot cannot move left. So target X must be >= current x.
            // This means X must be >= x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }

            // f2: can move up (x, y+1)
            // If f2 is 0, robot cannot move up. So target Y must be <= current y.
            // This means Y must be <= y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }

            // f3: can move right (x+1, y)
            // If f3 is 0, robot cannot move right. So target X must be <= current x.
            // This means X must be <= x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }

            // f4: can move down (x, y-1)
            // If f4 is 0, robot cannot move down. So target Y must be >= current y.
            // This means Y must be >= y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

