#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation needed for this element.
        // The flags `has_pos_one` and `has_neg_one` are updated based on elements a[0]...a[i-1]
        // because only elements with index < i can modify a[i].
        // However, the problem states "choose any pair of indexes (i, j) such that 1 <= i < j <= n".
        // This means a[k] for k < current_i can be used to modify a[current_i].
        // The `has_pos_one` and `has_neg_one` flags should reflect the presence of 1s and -1s
        // in the prefix a[0...i-1].
        // The current logic updates these flags based on a[i] itself, which is incorrect for future elements.
        // Let's correct this: the flags should be maintained for the prefix.

        // Re-evaluating the logic:
        // The `has_pos_one` and `has_neg_one` flags should track if there's a 1 or -1
        // *before* the current index `i`.
        // So, these flags should be updated *after* checking `a[i]` vs `b[i]`,
        // but *before* moving to the next `i`.

        // The initial `has_pos_one` and `has_neg_one` are for the entire array `a`.
        // We need to track if there's a 1 or -1 in `a[0...k-1]` when considering `a[k]`.
    }

    // Corrected logic:
    // We need to iterate and maintain the prefix information.
    has_pos_one = (a[0] == 1);
    has_neg_one = (a[0] == -1);

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // Update flags for the next iteration (for a[i+1])
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    std::cout << "YES\n";
}

