int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) { // Only consider off-diagonal elements
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1. If so, it means the corresponding p_i should be n.
    // This is because if p_i = n, then max_{j!=i} min(p_i, p_j) = max_{j!=i} p_j = n-1.
    // If no element in p is n-1, it means n is not present in the current p values.
    // In this case, the maximum value in p must be n-1, and we need to replace it with n.
    bool n_minus_1_found = false;
    for (int val : p) {
        if (val == n - 1) {
            n_minus_1_found = true;
            break;
        }
    }

    if (!n_minus_1_found) {
        // If n-1 is not found in p, it means the true value n was not assigned.
        // This happens when all p_i are less than n, and the maximum value in the permutation is n-1.
        // In this case, the maximum value in the current p array (which is n-1) should be n.
        // Find the first occurrence of n-1 and change it to n.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_stair_cells = 1; // Cells for a 1-stair staircase
        long long n_val = 1; // n for the current staircase (1, 3, 7, 15, ...)

        while (x >= current_stair_cells) {
            x -= current_stair_cells;
            count++;
            n_val = n_val * 2 + 1; // Next n for a nice staircase (1 -> 3 -> 7 -> 15 ...)
            // Calculate cells for the next nice staircase: n_val * (n_val + 1) / 2
            // This is equivalent to (2*n_val + 1) * (n_val + 1) / 2 for the previous n_val
            // Or, more simply, current_stair_cells = current_stair_cells * 2 + (n_val + 1) / 2
            // Let's derive it:
            // Cost(n) = n * (n+1) / 2
            // Cost(2k+1) = (2k+1) * (2k+2) / 2 = (2k+1) * (k+1)
            // If n_prev = k, then n_curr = 2k+1
            // Cost(n_curr) = (2*n_prev + 1) * (n_prev + 1)
            // This is not quite right.
            // The sequence of costs is:
            // n=1: 1*(1+1)/2 = 1
            // n=3: 3*(3+1)/2 = 6
            // n=7: 7*(7+1)/2 = 28
            // n=15: 15*(15+1)/2 = 120
            // The recurrence relation for costs is:
            // C(n_k) = C(n_{k-1}) * 2 + (n_k + 1) / 2
            // C(n_k) = C(n_{k-1}) * 2 + (2^k + 1)
            // Let's use the direct formula for n_val:
            // current_stair_cells = n_val * (n_val + 1) / 2;
            // This can overflow if n_val is large.
            // n_val can go up to 2*10^9 (approx sqrt(2*10^18)).
            // n_val * (n_val + 1) / 2 can be up to 2*10^18.
            // So n_val itself can be up to 2*10^9.
            // n_val * (n_val + 1) can be up to 4*10^18. This fits in long long.
            // The next n_val is 2*n_val_prev + 1.
            // The next cost is (2*n_val_prev + 1) * (2*n_val_prev + 2) / 2
            // = (2*n_val_prev + 1) * (n_val_prev + 1)
            // This is the correct recurrence for the cost.
            // current_stair_cells = (2 * (n_val_prev) + 1) * (n_val_prev + 1)
            // where n_val_prev is the n_val from the previous iteration.
            // Let's use n_val to represent the current n for which we are calculating the cost.
            // Initial: n_val = 1, current_stair_cells = 1
            // Loop 1: x -= 1, count = 1. Next n_val = 2*1+1 = 3.
            //         Next current_stair_cells = (2*1+1)*(1+1) = 3*2 = 6.
            // Loop 2: x -= 6, count = 2. Next n_val = 2*3+1 = 7.
            //         Next current_stair_cells = (2*3+1)*(3+1) = 7*4 = 28.
            // This is correct.
            current_stair_cells = (2 * n_val + 1) * (n_val + 1);
            // Check for overflow before division, though n_val+1 is even, so no issue.
            // The maximum value for current_stair_cells is 2 * 10^18.
            // If n_val is around 2*10^9, then (2*n_val+1)*(n_val+1) is around 4*10^18.
            // This fits in long long.
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_r_pos is -1, it means the frog is at cell 0.
                             // If last_r_pos is i, it means the frog is at cell i.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed).
                // The distance from the last 'R' (or 0) to this 'R' is (i+1) - (last_r_pos + 1) + 1
                // which simplifies to (i+1) - (last_r_pos + 1) + 1 = i - last_r_pos.
                // No, it's simpler: the distance from last_r_pos to i+1 is (i+1) - last_r_pos.
                // Example: last_r_pos = -1 (cell 0), current 'R' at s[0] (cell 1). Gap is 1 - (-1) = 2.
                // Example: last_r_pos = 2 (cell 3), current 'R' at s[4] (cell 5). Gap is 5 - 3 = 2.
                max_gap = std::max(max_gap, (i + 1) - (last_r_pos + 1) + 1);
                last_r_pos = i; // Update last_r_pos to the current 'R' cell index (0-indexed string index)
            }
        }

        // After the loop, consider the jump from the last 'R' (or 0 if no 'R's) to n+1.
        // The last 'R' was at s[last_r_pos], which is cell last_r_pos + 1.
        // The target is cell n+1.
        // The distance is (n + 1) - (last_r_pos + 1) + 1.
        // Example: last_r_pos = -1 (cell 0). Target n+1. Gap is (n+1) - 0 = n+1.
        // Example: last_r_pos = 2 (cell 3). Target n+1. Gap is (n+1) - (2+1) = n+1-3.
        max_gap = std::max(max_gap, (n + 1) - (last_r_pos + 1) + 1);

        std::cout << max_gap << "\n";
    }
    return 0;
}

