}

// Function to check if Box 2 can be the special box
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // Box 2: (-1, 0)
    // Final value must be negative and magnitude < 1.
    // This requires an odd number of negative factors.
    // And all factors must have magnitude < 1, or we can make the product of magnitudes < 1.

    // Case 1: Final value is negative.
    // This means (A + B) must be odd.
    if ((A + B) % 2 == 0) {
        return false; // Even number of negative factors, result is positive.
    }

    // Case 2: Final value has magnitude < 1.
    // This is always possible if we have at least one toy from B or C.
    // If B > 0 or C > 0, we can pick a toy with magnitude < 1.
    // We can choose values for toys in A and D to be very close to 1 or -1 (e.g., -1.001 or 1.001).
    // And choose values for toys in B and C to be very small (e.g., -0.001 or 0.001).
    // If we have at least one toy from B or C, we can make the final product's magnitude < 1.
    // If B=0 and C=0, then all initial toys have magnitude >= 1 (from A or D).
    // The product of any number of toys with magnitude >= 1 will always have magnitude >= 1.
    // So, if B=0 and C=0, we can never get a toy in Box 2 (or Box 3).
    if (B == 0 && C == 0) {
        return false;
    }

    // So, (A+B) must be odd AND (B > 0 or C > 0).
    // This condition is sufficient.
    // Example: A=1, B=2, C=0, D=1. (A+B)=3 (odd). B=2>0.
    // Toys: {-3}, {-0.33, -0.25}, {}, {3}
    // (-3 * -0.33) = 0.99 (Box 3)
    // (0.99 * 3) = 2.97 (Box 4)
    // (2.97 * -0.25) = -0.7425 (Box 2) -> Yes.

    return true;
}

// Function to check if Box 3 can be the special box
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // Box 3: (0, 1)
    // Final value must be positive and magnitude < 1.
    // This requires an even number of negative factors.
    // And all factors must have magnitude < 1, or we can make the product of magnitudes < 1.

    // Case 1: Final value is positive.
    // This means (A + B) must be even.
    if ((A + B) % 2 != 0) {
        return false; // Odd number of negative factors, result is negative.
    }

    // Case 2: Final value has magnitude < 1.
    // Similar to Box 2, if B=0 and C=0, we can never get a toy in Box 3.
    if (B == 0 && C == 0) {
        return false;
    }

    // So, (A+B) must be even AND (B > 0 or C > 0).
    // This condition is sufficient.
    return true;
}

// Function to check if Box 4 can be the special box
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // Box 4: [1, inf)
    // Final value must be positive and magnitude >= 1.
    // This requires an even number of negative factors.
    // And at least one factor with magnitude >= 1, or multiple factors with magnitude > 1 whose product is >= 1.

    // Case 1: Final value is positive.
    // This means (A + B) must be even.
    if ((A + B) % 2 != 0) {
        return false; // Odd number of negative factors, result is negative.
    }

    // Case 2: Final value has magnitude >= 1.
    // Similar to Box 1, if A=0 and D=0, we can never get a toy in Box 4.
    if (A == 0 && D == 0) {
        return false;
    }

    // So, (A+B) must be even AND (A > 0 or D > 0).
    // This condition is sufficient.
    return true;
}

