#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;

    // Iterate through each point as the first point (x_i) of a potential triplet.
    // For each x_i, we need to find how many pairs (x_j, x_k) exist such that
    // i < j < k and x_k - x_i <= d.
    // Since x is sorted, x_j and x_k will automatically satisfy x_j - x_i <= d
    // and x_k - x_j <= d if x_k - x_i <= d.
    // The condition x_k - x_i <= d implies x_k <= x_i + d.
    // We need to find all points x_p such that x_i < x_p <= x_i + d.
    // Let's say these points are x_{i+1}, ..., x_R.
    // The number of such points is R - (i+1) + 1 = R - i.
    // From these R - i points, we need to choose 2 points to form x_j and x_k.
    // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

    for (int i = 0; i < n; ++i) {
        // Find the rightmost index 'R' such that x[R] <= x[i] + d.
        // std::upper_bound returns an iterator to the first element
        // that is greater than x[i] + d.
        // So, all elements from x[i+1] up to (but not including) the one
        // pointed to by upper_bound satisfy the condition.
        auto it = std::upper_bound(x.begin() + i + 1, x.end(), x[i] + d);

        // The index of the first element greater than x[i] + d.
        // All elements from x[i+1] to x[R-1] satisfy the condition.
        // So, R is the index of the first element *not* satisfying the condition.
        // The number of points available to be x_j or x_k (excluding x_i)
        // is (it - x.begin()) - (i + 1).
        // Let's call this count 'm'.
        long long m = (it - x.begin()) - (i + 1);

        // If m < 2, we cannot choose two distinct points for x_j and x_k.
        if (m >= 2) {
            // Number of ways to choose 2 points from m points is m * (m - 1) / 2.
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

