#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort array A in ascending order
    std::sort(a.begin(), a.end());

    // Sort array B_elements in ascending order based on their values
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    std::vector<long long> a_prime(m);

    // The optimal strategy is to pair the largest A_i with the largest B_j,
    // the second largest A_i with the second largest B_j, and so on.
    // This is because F(n, k) = (n+1)/(k+1).
    // To maximize sum( (A_i + 1) / (B_i + 1) ), we should pair larger A_i with smaller B_i.
    // However, the problem statement implies F(n, k) is the expectation of the minimal element.
    // The formula for the expectation of the minimum of k elements chosen from [1, ..., n] is (n+1)/(k+1).
    // Let's re-derive or confirm this.
    // E[min] = sum_{x=1}^{n-k+1} P(min >= x)
    // P(min >= x) = C(n-x+1, k) / C(n, k)
    // E[min] = sum_{x=1}^{n-k+1} C(n-x+1, k) / C(n, k)
    // Using the identity sum_{i=r}^N C(i, r) = C(N+1, r+1)
    // Let j = n-x+1. When x=1, j=n. When x=n-k+1, j=k.
    // The sum becomes sum_{j=k}^n C(j, k) / C(n, k)
    // This is C(n+1, k+1) / C(n, k)
    // C(n+1, k+1) / C(n, k) = ((n+1)! / ((k+1)! * (n-k)!)) / (n! / (k! * (n-k)!))
    // = (n+1)! * k! * (n-k)! / ((k+1)! * (n-k)! * n!)
    // = (n+1) * n! * k! / ((k+1) * k! * n!)
    // = (n+1) / (k+1)
    // So, F(n, k) = (n+1) / (k+1).

    // We want to maximize sum_{i=1}^m (A'_i + 1) / (B_i + 1).
    // Let X_i = A'_i + 1 and Y_i = B_i + 1.
    // We want to maximize sum_{i=1}^m X_i / Y_i.
    // We have sorted A (which means sorted X_i values) and sorted B (which means sorted Y_i values).
    // Let a_1 <= a_2 <= ... <= a_m be the sorted A values.
    // Let b_1 <= b_2 <= ... <= b_m be the sorted B values.
    // The rearrangement inequality states that for two sequences x_1 <= ... <= x_m and y_1 <= ... <= y_m,
    // sum(x_i * y_{m-i+1}) <= sum(x_i * y_{pi}) <= sum(x_i * y_i) for any permutation p.
    // This applies to products. For sums of ratios, it's different.
    // Consider two pairs (x1, y1) and (x2, y2).
    // We want to compare x1/y1 + x2/y2 with x1/y2 + x2/y1.
    // Assume x1 < x2 and y1 < y2.
    // x1/y1 + x2/y2 - (x1/y2 + x2/y1)
    // = x1(1/y1 - 1/y2) - x2(1/y1 - 1/y2)
    // = (x1 - x2)(1/y1 - 1/y2)
    // Since x1 < x2, (x1 - x2) is negative.
    // Since y1 < y2, 1/y1 > 1/y2, so (1/y1 - 1/y2) is positive.
    // Thus, (x1 - x2)(1/y1 - 1/y2) is negative.
    // So, x1/y1 + x2/y2 < x1/y2 + x2/y1.
    // This means to maximize the sum, we should pair the largest X with the smallest Y,
    // the second largest X with the second smallest Y, and so on.
    // In other words, sort A in ascending order, and sort B in descending order, then pair them.
    // Or, sort A in descending order, and sort B in ascending order, then pair them.

    // Our `a` is sorted ascending.
    // Our `b_elements` is sorted ascending by value.
    // To pair largest A with smallest B, we should pair `a[m-1]` with `b_elements[0].value`,
    // `a[m-2]` with `b_elements[1].value`, and so on.
    // This means `a[m-1-i]` should be paired with `b_elements[i].value`.
    // The result `a_prime` should store `a[m-1-i]` at the original index of `b_elements[i]`.

    for (int i = 0; i < m; ++i) {
        a_prime[b_elements[i].original_index] = a[m - 1 - i];
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

