// Function to check if a sub-array is a permutation
// `arr` is the original array
// `start_idx` is the starting index of the sub-array (inclusive)
// `end_idx` is the ending index of the sub-array (inclusive)
// `expected_len` is the length the permutation should have
bool is_permutation(const std::vector<int>& arr, int start_idx, int end_idx, int expected_len) {
    if (expected_len <= 0) { // A permutation must have non-zero length
        return false;
    }
    if (end_idx - start_idx + 1 != expected_len) { // Length mismatch
        return false;
    }

    std::vector<bool> seen(expected_len + 1, false);
    int max_val = 0;

    for (int i = start_idx; i <= end_idx; ++i) {
        int val = arr[i];
        if (val <= 0 || val > expected_len) { // Value out of range [1, expected_len]
            return false;
        }
        if (seen[val]) { // Duplicate value
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }

    // All values from 1 to expected_len must be present
    // We already checked for duplicates and range.
    // If max_val is not expected_len, then some number is missing.
    // This check is redundant if we iterate seen[1...expected_len]
    // but it's a quick check.
    if (max_val != expected_len) {
        return false;
    }

    // Final check: ensure all numbers from 1 to expected_len are seen
    for (int i = 1; i <= expected_len; ++i) {
        if (!seen[i]) {
            return false;
        }
    }

    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute max prefix and max suffix values
    std::vector<int> max_prefix(n);
    std::vector<int> max_suffix(n);

    max_prefix[0] = a[0];
    for (int i = 1; i < n; ++i) {
        max_prefix[i] = std::max(max_prefix[i-1], a[i]);
    }

    max_suffix[n-1] = a[n-1];
    for (int i = n - 2; i >= 0; --i) {
        max_suffix[i] = std::max(max_suffix[i+1], a[i]);
    }

    // Precompute prefix permutation validity
    std::vector<bool> is_prefix_perm(n + 1, false); // is_prefix_perm[L] means prefix of length L is a perm
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max_prefix = 0;
    bool possible_prefix = true;
    for (int L = 1; L <= n; ++L) {
        int val = a[L-1];
        if (val <= 0 || val > L || seen_prefix[val]) {
            possible_prefix = false;
        }
        if (possible_prefix) {
            seen_prefix[val] = true;
            current_max_prefix = std::max(current_max_prefix, val);
            if (current_max_prefix == L) {
                is_prefix_perm[L] = true;
            }
        }
    }

    // Precompute suffix permutation validity
    std::vector<bool> is_suffix_perm(n + 1, false); // is_suffix_perm[L] means suffix of length L is a perm
    std::vector<bool> seen_suffix(n + 1, false);
    int current_max_suffix = 0;
    bool possible_suffix = true;
    for (int L = 1; L <= n; ++L) {
        int val = a[n-L];
        if (val <= 0 || val > L || seen_suffix[val]) {
            possible_suffix = false;
        }
        if (possible_suffix) {
            seen_suffix[val] = true;
            current_max_suffix = std::max(current_max_suffix, val);
            if (current_max_suffix == L) {
                is_suffix_perm[L] = true;
            }
        }
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 ranges from 1 to n-1
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check if prefix a[0...l1-1] is a permutation of length l1
        // Check if suffix a[l1...n-1] is a permutation of length l2
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

