#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_score = 0;
        int wins_count = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                wins_count++;
                if (i > 0 && s[i-1] == 'W') {
                    initial_score += 2;
                } else {
                    initial_score += 1;
                }
            }
        }

        if (wins_count == 0) { // All 'L's
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                // Change k 'L's to 'W's. Best to make them consecutive.
                // k 'W's give 1 + 2*(k-1) points.
                std::cout << 1 + std::max(0, k - 1) * 2 << "\n";
            }
            continue;
        }

        // If there are already wins, we want to fill gaps between them or extend them.
        // Calculate the number of 'L's we need to change to 'W's to connect blocks.
        std::vector<int> gaps;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) first_W = i;
                last_W = i;
            }
        }

        // Collect gaps between 'W's
        if (first_W != -1) { // Should always be true if wins_count > 0
            int current_gap_len = 0;
            for (int i = first_W + 1; i <= last_W; ++i) {
                if (s[i] == 'L') {
                    current_gap_len++;
                } else { // s[i] == 'W'
                    if (current_gap_len > 0) {
                        gaps.push_back(current_gap_len);
                    }
                    current_gap_len = 0;
                }
            }
        }
        std::sort(gaps.begin(), gaps.end());

        int current_k = k;
        int additional_score = 0;

        // Fill smallest gaps first
        for (int gap_len : gaps) {
            if (current_k >= gap_len) {
                current_k -= gap_len;
                // Each 'L' in the gap becomes 'W'.
                // It connects two 'W's, so it gets 2 points.
                // The 'L's themselves contribute 2*gap_len points.
                // The two 'W's at the ends of the gap were already counted.
                // When a gap of length `g` is filled, `g` 'L's become 'W's.
                // Each of these `g` 'W's will be preceded by a 'W' (either the one before the gap, or another 'W' within the filled gap).
                // So each of these `g` 'W's contributes 2 points.
                additional_score += 2 * gap_len;
            } else {
                break;
            }
        }

        // Remaining k can be used to extend existing blocks or create new ones.
        // Extending existing blocks is always better than creating new ones.
        // Each 'L' changed to 'W' adjacent to an existing 'W' gives 2 points.
        // Each 'L' changed to 'W' not adjacent to an existing 'W' gives 1 point.
        // Since we already have wins, we can always find an 'L' adjacent to a 'W' (at the ends of the whole W-block).
        // So, each remaining k gives 2 points.
        additional_score += 2 * current_k;

        std::cout << initial_score + additional_score << "\n";
    }
    return 0;
}

