long long solve() {
    long long n;
    std::cin >> n;

    if (n % 2 != 0) { // N is odd
        return (n + 1) / 2;
    } else { // N is even
        // Check if N is a power of 2
        if ((n & (n - 1)) == 0) { // N is a power of 2
            return n / 2;
        } else { // N is even but not a power of 2
            return n;
        }
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

