    while (t--) {
        int n;
        std::cin >> n;
        long long current_sum = 0;
        long long current_xor_sum = 0;
        for (int i = 0; i < n; ++i) {
            long long a;
            std::cin >> a;
            current_sum += a;
            current_xor_sum ^= a;
        }

        // We need S' = 2 * X'
        // Let's try to append at most 3 elements.
        // The problem guarantees a solution exists with at most 3 elements.
        // A simple strategy is to append two elements: X and S+X.
        // Or, if S != 2X, append X, then S+X.
        // Let's try to append two elements: current_xor_sum and current_sum + current_xor_sum.
        // Let X = current_xor_sum
        // Let S = current_sum
        // We append b1 = X and b2 = S + X.
        // New XOR sum X' = X ^ b1 ^ b2 = X ^ X ^ (S + X) = S + X.
        // New SUM S' = S + b1 + b2 = S + X + (S + X) = 2S + 2X.
        // We need S' = 2 * X'.
        // Is 2S + 2X = 2 * (S + X)? Yes, it is.
        // This strategy always works and uses 2 elements.
        // The only edge case is if the array is already good.
        // If current_sum == 2 * current_xor_sum, we don't need to append anything.

        if (current_sum == 2 * current_xor_sum) {
            std::cout << 0 << "\n\n";
        } else {
            std::cout << 2 << "\n";
            std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
        }
