}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::vector<int> w(k);
        for (int i = 0; i < k; ++i) {
            std::cin >> w[i];
        }

        std::sort(a.begin(), a.end());
        std::sort(w.begin(), w.end());

        long long total_happiness = 0;
        int a_ptr_left = 0;
        int a_ptr_right = n - 1;

        // Friends with w_i = 1: they get one number, happiness is 2 * number.
        // To maximize, give them the largest available numbers.
        for (int i = k - 1; i >= 0; --i) {
            if (w[i] == 1) {
                total_happiness += 2 * a[a_ptr_right];
                a_ptr_right--;
            } else {
                // All friends with w_i > 1 are processed later.
                // Since w is sorted, all remaining w[i] will be > 1.
                // We can break here as we've processed all w_i = 1.
                break;
            }
        }

        // Friends with w_i > 1: they get w_i numbers. Happiness is max_val + min_val.
        // To maximize, give them the largest available numbers as max_val,
        // and the smallest available numbers as min_val.
        // The w array is sorted, so w[0] is the smallest w_i > 1, w[k-1] is the largest w_i > 1.
        // We iterate from smallest w_i to largest w_i.
        // Smallest w_i (that are > 1) should get the smallest available numbers as min_val.
        // Largest w_i (that are > 1) should get the largest available numbers as max_val.
        // The largest available numbers for max_val are already taken by w_i=1 friends or will be taken by these friends.
        // The largest available numbers for max_val should be given to friends with w_i > 1.
        // The smallest available numbers for min_val should be given to friends with w_i > 1.

        // Iterate through friends with w_i > 1.
        // These are the friends from index 0 up to the point where w[i] was 1.
        // Since w is sorted, these are w[0], w[1], ..., up to the first w_i that was 1.
        // Or, more simply, iterate from i=0 to k-1. If w[i] > 1, process it.
        // The largest numbers (a_ptr_right down to a_ptr_left) are for max_val.
        // The smallest numbers (a_ptr_left up) are for min_val.

        // Give the largest remaining numbers as max_val to friends with w_i > 1.
        // Iterate from the largest w_i (that is > 1) down to the smallest w_i (that is > 1).
        // This ensures that the largest available numbers are used as max_val.
        for (int i = k - 1; i >= 0; --i) {
            if (w[i] > 1) {
                total_happiness += a[a_ptr_right]; // Max value for this friend
                a_ptr_right--;
            }
        }

        // Now, give the smallest remaining numbers as min_val to friends with w_i > 1.
        // Iterate from the smallest w_i (that is > 1) up to the largest w_i (that is > 1).
        // This ensures that the smallest available numbers are used as min_val.
        for (int i = 0; i < k; ++i) {
            if (w[i] > 1) {
                total_happiness += a[a_ptr_left]; // Min value for this friend
                a_ptr_left += (w[i] - 1); // Consume w[i]-1 smallest numbers for this friend
            }
        }

        std::cout << total_happiness << "\n";
    }
    return 0;
}

#include <iostream>
