#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will generate 'count_a' operations
            // with this 'b' (if it's the first 'b' it encounters)
            // or with the 'b's that were generated from previous 'b's.
            // The 'count_a' represents the number of 'a's that are currently
            // to the left of the current 'b' (or the 'b's that were generated
            // from 'b's to the right of the current 'b').
            // When an 'a' moves past a 'b', it generates one operation.
            // The 'a' then effectively doubles the number of 'b's it needs to pass
            // for the next 'a' to its left.
            // So, if we have 'count_a' 'a's to the left, and we encounter a 'b',
            // this 'b' will cause 'count_a' operations.
            // After these operations, this 'b' effectively becomes two 'b's
            // for the 'a's further to the left.
            // So, the number of 'a's that need to be considered for the next 'b'
            // (or for the 'b's generated by this 'b') doubles.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually
            // need to move past all 'b's to its right.
            // The 'count_a' variable keeps track of how many 'a's are
            // effectively "active" and need to be moved past 'b's.
            // When we see an 'a', we increment this count.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

