int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        std::string s;
        std::cin >> s;
        int count_L = 0;
        int count_R = 0;
        int count_U = 0;
        int count_D = 0;

        for (char c : s) {
            if (c == 'L') {
                count_L++;
            } else if (c == 'R') {
                count_R++;
            } else if (c == 'U') {
                count_U++;
            } else if (c == 'D') {
                count_D++;
            }
        }

        int horiz_moves = std::min(count_L, count_R);
        int vert_moves = std::min(count_U, count_D);

        std::string result = "";
        int total_moves = 0;

        if (horiz_moves == 0 && vert_moves == 0) {
            total_moves = 0;
        } else if (horiz_moves == 0) { // Only vertical moves possible
            if (vert_moves > 0) {
                total_moves = 2;
                result = "UD";
            } else {
                total_moves = 0;
            }
        } else if (vert_moves == 0) { // Only horizontal moves possible
            if (horiz_moves > 0) {
                total_moves = 2;
                result = "LR";
            } else {
                total_moves = 0;
            }
        } else { // Both horizontal and vertical moves possible
            total_moves = 2 * horiz_moves + 2 * vert_moves;
            for (int i = 0; i < horiz_moves; ++i) {
                result += 'L';
            }
            for (int i = 0; i < vert_moves; ++i) {
                result += 'U';
            }
            for (int i = 0; i < horiz_moves; ++i) {
                result += 'R';
            }
            for (int i = 0; i < vert_moves; ++i) {
                result += 'D';
            }
        }

        std::cout << total_moves << "\n";
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long s;
    std::cin >> n >> s;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2;

    // The median element must be s.
    // Cost to change a[mid_idx] to s.
    operations += std::abs(a[mid_idx] - s);

    // Elements to the left of the median must be <= s.
    // If any a[i] < s for i < mid_idx, we don't need to change it.
    // If any a[i] > s for i < mid_idx, we must decrease it to s.
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of the median must be >= s.
    // If any a[i] > s for i > mid_idx, we don't need to change it.
    // If any a[i] < s for i > mid_idx, we must increase it to s.
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

