#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // If s[i] is '0', then w[i-x] (if exists) and w[i+x] (if exists) must be '0'.
    // This is the only way to definitively set characters in w.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if the constructed w can produce the given s.
    // Build a candidate s_prime from w using the given rules.
    std::string s_prime(n, '0');
    for (int i = 0; i < n; ++i) {
        // Check w[i-x]
        if (i - x >= 0 && w[i - x] == '1') {
            s_prime[i] = '1';
        }
        // Check w[i+x]
        if (i + x < n && w[i + x] == '1') {
            s_prime[i] = '1';
        }
    }

    // Compare s_prime with the original s.
    if (s_prime == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

