#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int p = 0; p <= 9; ++p) { // p is the pivot digit
        int last1 = -1;
        int last2 = -1;
        bool possible_for_p = true;

        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < p) {
                // Must be color 1
                if (digit < last1) {
                    possible_for_p = false;
                    break;
                }
                result[i] = '1';
                last1 = digit;
            } else if (digit > p) {
                // Must be color 2
                if (digit < last2) {
                    possible_for_p = false;
                    break;
                }
                result[i] = '2';
                last2 = digit;
            } else { // digit == p
                // Can be color 1 or color 2
                // Try to put it in color 2 if possible, to keep color 1 as small as possible
                if (digit >= last2) {
                    result[i] = '2';
                    last2 = digit;
                } else if (digit >= last1) { // If cannot be color 2, try color 1
                    result[i] = '1';
                    last1 = digit;
                } else { // Cannot be either
                    possible_for_p = false;
                    break;
                }
            }
        }

        if (possible_for_p) {
            // Check the final condition: last1 <= first2
            // This is implicitly handled by the logic:
            // If a digit `d` is colored 1, it must be >= `last1`.
            // If a digit `d` is colored 2, it must be >= `last2`.
            // All digits colored 1 are <= p. All digits colored 2 are >= p.
            // So, `last1` (max of color 1 digits) will be <= p.
            // And `first2` (min of color 2 digits) will be >= p.
            // Thus, `last1 <= p <= first2` is guaranteed if the individual sequences are sorted.
            // The only edge case is if `last1` is from a digit `d < p` and `first2` is from a digit `d' > p`.
            // But if `d=p` is colored 1, `last1` could be `p`. If `d=p` is colored 2, `first2` could be `p`.
            // The logic `digit >= last2` for `digit == p` prioritizes putting `p` into `S2`.
            // This ensures that if `S1` contains `p`, it's because `S2` couldn't take it (i.e., `p < last2`).
            // If `p < last2`, then `last1` (which would be `p`) is indeed less than `last2`.
            // If `p >= last2`, then `p` goes to `S2`, and `last1` remains smaller than `p`.
            // So the condition `last1 <= first2` is maintained.

            found_solution = true;
            std::cout << result << "\n";
            break;
        }
    }

    if (!found_solution) {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    // Step 1: Propagate known characters within k-periodic sequences
    // For each j from 0 to k-1, all s[j], s[j+k], s[j+2k], ... must be the same.
    // If any character in such a sequence is '0' or '1', all '?' in that sequence
    // must be replaced by that character. If there's a conflict (e.g., '0' and '1'
    // in the same sequence), it's impossible.
    for (int j = 0; j < k; ++j) {
        char fixed_char = '?';
        for (int i = j; i < n; i += k) {
            if (s[i] != '?') {
                if (fixed_char == '?') {
                    fixed_char = s[i];
                } else if (fixed_char != s[i]) {
                    // Conflict detected: '0' and '1' in the same k-periodic sequence
                    std::cout << "NO\n";
                    return;
                }
            }
        }
        // If a fixed_char was found, update all '?' in this sequence
        if (fixed_char != '?') {
            for (int i = j; i < n; i += k) {
                s[i] = fixed_char;
            }
        }
    }

    // Step 2: Check if every substring of length k can be k-balanced
    // After propagation, for each j from 0 to k-1, s[j], s[j+k], s[j+2k], ... are either
    // all '0', all '1', or all '?'.
    // We only need to check the first k characters s[0...k-1] because of the k-periodicity.
    // If s[0...k-1] can be made k-balanced, then all other k-length substrings will also be.
    // For example, s[1...k] will have s[1], s[2], ..., s[k-1], s[k].
    // Since s[k] == s[0], this substring is effectively a cyclic shift of s[0...k-1]
    // (if we consider s[k] as s[0]).
    // More formally, if s[0...k-1] has k/2 zeros and k/2 ones, and s[i] == s[i+k],
    // then s[p...p+k-1] will also have k/2 zeros and k/2 ones.
    // So, we count '0's, '1's, and '?'s in the first k characters.
    int zeros_count = 0;
    int ones_count = 0;
    int q_marks_count = 0;

    for (int i = 0; i < k; ++i) {
        if (s[i] == '0') {
            zeros_count++;
        } else if (s[i] == '1') {
            ones_count++;
        } else {
            q_marks_count++;
        }
    }

    // We need k/2 zeros and k/2 ones.
    // If we have too many zeros or too many ones already, it's impossible.
    if (zeros_count > k / 2 || ones_count > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // The remaining '?'s must be filled to satisfy the k/2 requirement.
    // We need (k/2 - zeros_count) more zeros and (k/2 - ones_count) more ones.
    // The total number of '?'s must be exactly equal to the sum of these needed counts.
    if (q_marks_count == (k / 2 - zeros_count) + (k / 2 - ones_count)) {
        std::cout << "YES\n";
    } else {
        // This case should ideally not be reached if the logic is sound,
        // as q_marks_count is always k - zeros_count - ones_count.
        // So the condition q_marks_count == (k/2 - zeros_count) + (k/2 - ones_count)
        // simplifies to k - zeros_count - ones_count == k - zeros_count - ones_count,
        // which is always true.
        // The actual check is just zeros_count <= k/2 and ones_count <= k/2.
        // If those pass, then it's always possible to fill the '?'s.
        std::cout << "YES\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    long long correct_sequence_length = 0;
    long long total_elements_in_correct_sequence = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        if (m == 0) continue; // Should not happen based on constraints (m_i >= 1)

        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // Check if the chain starts with 1 and continues as 1 -> 2 -> ...
        if (chain[0] == 1) {
            long long current_correct_len = 0;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == j + 1) {
                    current_correct_len++;
                } else {
                    break;
                }
            }
            correct_sequence_length = current_correct_len;
            total_elements_in_correct_sequence = current_correct_len;
        }
    }

    // Total operations = (disassemble all incorrect parts) + (assemble all parts)
    // Disassemble:
    // Each element not part of the 1->2->...->L sequence needs to be taken out.
    // If a chain is a_1 -> a_2 -> ... -> a_m, it has m-1 direct nestings.
    // To disassemble it completely, it takes m-1 operations.
    // Total elements = n.
    // Elements in the correct sequence (1->2->...->L) don't need to be disassembled.
    // So, n - total_elements_in_correct_sequence elements need to be disassembled.
    // Each disassembly operation frees one element from its parent.
    // The number of disassembly operations is (n - 1) - (correct_sequence_length - 1)
    // which simplifies to n - correct_sequence_length.
    // This is the number of 'incorrect' direct nestings that need to be broken.
    // Example: 1->3->4. n=3. correct_sequence_length=0. Disassembly = 3.
    // 1->2->3. n=3. correct_sequence_length=3. Disassembly = 0.
    // The number of disassembly operations is (total number of initial nestings) - (number of correct initial nestings).
    // Total initial nestings = n - k (since k chains, each chain of length m has m-1 nestings, sum(m-1) = sum(m) - sum(1) = n - k)
    // Number of correct initial nestings = correct_sequence_length - 1 (if correct_sequence_length > 0, else 0)
    // So, disassembly operations = (n - k) - (correct_sequence_length > 0 ? correct_sequence_length - 1 : 0)

    // Let's re-evaluate.
    // Total elements = n.
    // Elements that are part of the 1->2->...->L prefix are already in place.
    // These are L elements.
    // The remaining n-L elements need to be moved.
    // Each of these n-L elements needs to be taken out of its current nesting (if any) and then put into its correct place.
    // Taking out an element: 1 operation.
    // Putting in an element: 1 operation.
    // So, for each of the n-L elements, we need 2 operations.
    // Total operations for these n-L elements = 2 * (n - correct_sequence_length).

    // However, the problem states:
    // "Having a matryoshka a directly contained in matryoshka b, such that b is not nested in any other matryoshka, you may get a out of b."
    // "Having a matryoshka a that isn't nested in any other matryoshka and a matryoshka b, such that b doesn't contain any other matryoshka and is not nested in any other matryoshka, you may put a in b;"

    // Let's count operations more carefully.
    // Target: 1 -> 2 -> ... -> n. This requires n-1 direct nestings.
    // We have `correct_sequence_length` elements already in the correct prefix `1 -> 2 -> ... -> L`.
    // This means `L-1` nestings are already correct.
    // We need to create `(n-1) - (L-1)` new nestings, which is `n-L` new nestings.
    // Each new nesting `i -> i+1` requires `i` to be free and `i+1` to be free and not containing anything.
    // This costs 1 operation per nesting. So, `n-L` operations for assembly.

    // What about disassembly?
    // All elements from `L+1` to `n` are currently in some chains.
    // They need to be "freed" from their current positions.
    // Consider all `k` chains.
    // The chain containing `1` has `L` elements `1, 2, ..., L` correctly nested.
    // The remaining `m_1 - L` elements in this chain (if any) are `L+1, ...`. These need to be disassembled.
    // This means `m_1 - L` disassembly operations for the first chain (if `m_1 > L`).
    // For all other `k-1` chains, they are completely "incorrect" relative to the target `1->...->n` structure.
    // Each of these `k-1` chains has `m_i` elements. To completely disassemble a chain of `m_i` elements, it takes `m_i - 1` operations.
    // Total elements in these `k-1` chains is `n - L - (m_1 - L)` if `m_1 > L`, or `n - L` if `m_1 = L`.
    // No, total elements in these `k-1` chains is `n - m_1`.
    // Total disassembly operations:
    // Sum of (m_i - 1) for all chains, MINUS (L-1) for the correct prefix.
    // Total initial nestings = (n - k).
    // Number of correct nestings = (correct_sequence_length > 0 ? correct_sequence_length - 1 : 0).
    // Disassembly operations = (n - k) - (correct_sequence_length > 0 ? correct_sequence_length - 1 : 0).
    // This is the number of "incorrect" direct nestings that need to be broken.

    // Let's use the example: 7 3, chains: 3 1 3 7, 2 2 5, 2 4 6
    // n=7, k=3
    // Chain 1: 1 3 7. Starts with 1. But 1->3 is not 1->2. So L=1. correct_sequence_length = 1.
    // Chain 2: 2 5.
    // Chain 3: 4 6.
    // L = 1.
    // Disassembly operations:
    // Chain 1 (1->3->7): 2 nestings. 1->3 and 3->7. Both are incorrect.
    // Chain 2 (2->5): 1 nesting. 2->5. Incorrect.
    // Chain 3 (4->6): 1 nesting. 4->6. Incorrect.
    // Total incorrect nestings = 2 + 1 + 1 = 4.
    // This is (n-k) - (L-1) = (7-3) - (1-1) = 4 - 0 = 4. This matches.
    // So, 4 disassembly operations.

    // Assembly operations:
    // We need to form 1->2->3->4->5->6->7.
    // We have 1 already.
    // We need to nest 1 into 2. (1 op)
    // We need to nest 2 into 3. (1 op)
    // ...
    // We need to nest 6 into 7. (1 op)
    // Total n-1 nestings.
    // We already have L-1 nestings if L > 0.
    // So, (n-1) - (L-1) = n-L assembly operations.
    // In example: n-L = 7-1 = 6 assembly operations.

    // Total operations = Disassembly + Assembly
    // Total operations = ((n - k) - (correct_sequence_length > 0 ? correct_sequence_length - 1 : 0)) + (n - correct_sequence_length)
    // If correct_sequence_length = 0, then (n-k) + n.
    // If correct_sequence_length > 0, then (n-k - correct_sequence_length + 1) + (n - correct_sequence_length)
    // = n - k - correct_sequence_length + 1 + n - correct_sequence_length
    // = 2*n - k - 2*correct_sequence_length + 1

    // Let's test with example 1: 3 2, chains: 2 1 2, 1 3
    // n=3, k=2
    // Chain 1: 1 2. Starts with 1. 1->2 is correct. L=2. correct_sequence_length = 2.
    // Chain 2: 3.
    // L = 2.
    // Disassembly operations:
    // (n-k) - (L-1) = (3-2) - (2-1) = 1 - 1 = 0.
    // Assembly operations:
    // n-L = 3-2 = 1. (Nest 2 into 3)
    // Total = 0 + 1 = 1. Matches example output.

    // Let's test with example 2: 7 3, chains: 3 1 3 7, 2 2 5, 2 4 6
    // n=7, k=3
    // Chain 1: 1 3 7. Starts with 1. 1->3 is not 1->2. So L=1. correct_sequence_length = 1.
    // L = 1.
    // Disassembly operations:
    // (n-k) - (L-1) = (7-3) - (1-1) = 4 - 0 = 4.
    // Assembly operations:
    // n-L = 7-1 = 6.
    // Total = 4 + 6 = 10. Matches example output.

    // The formula seems to be:
    // (n - k) - (correct_sequence_length > 0 ? correct_sequence_length - 1 : 0)  // Disassembly
    // + (n - correct_sequence_length)                                            // Assembly

    // Simplify:
    // If correct_sequence_length == 0:
    // (n - k) + n = 2*n - k
    // If correct_sequence_length > 0:
    // (n - k - correct_sequence_length + 1) + (n - correct_sequence_length)
    // = 2*n - k - 2*correct_sequence_length + 1

    // This can be written as:
    // (n - k) + (n - correct_sequence_length) - (correct_sequence_length > 0 ? correct_sequence_length - 1 : 0) + (correct_sequence_length > 0 ? correct_sequence_length - 1 : 0)
    // No, this is not simplifying.

    // Let's use the derived formula directly:
    long long disassembly_ops = (n - k);
    if (correct_sequence_length > 0) {
        disassembly_ops -= (correct_sequence_length - 1);
    }
    long long assembly_ops = (n - correct_sequence_length);

    long long total_ops = disassembly_ops + assembly_ops;

    std::cout << total_ops << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (result.length() == k) {
            break;
        }

        if (c == '(') {
            if (open_count < k / 2) {
                result += '(';
                open_count++;
                balance++;
            }
        } else { // c == ')'
            if (close_count < k / 2 && balance > 0) {
                result += ')';
                close_count++;
                balance--;
            }
        }
    }

    std::cout << result << std::endl;

    return 0;
}

