}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;
    long long MOD = 1000000007;

    // Calculate sum_k = sum_{k=1}^{a} (k * b + 1)
    // sum_k = b * sum_{k=1}^{a} k + sum_{k=1}^{a} 1
    // sum_k = b * (a * (a + 1) / 2) + a
    // All calculations modulo MOD

    long long sum_k_term1_factor_b = b % MOD;
    long long sum_k_term1_factor_a_a_plus_1_div_2;

    long long a_val = a % MOD;
    long long a_plus_1_val = (a + 1) % MOD;

    if (a % 2 == 0) {
        sum_k_term1_factor_a_a_plus_1_div_2 = (a_val / 2) % MOD * a_plus_1_val % MOD;
    } else {
        sum_k_term1_factor_a_a_plus_1_div_2 = a_val % MOD * (a_plus_1_val / 2) % MOD;
    }

    long long sum_k_term1 = sum_k_term1_factor_b * sum_k_term1_factor_a_a_plus_1_div_2 % MOD;
    long long sum_k_term2 = a_val;

    long long sum_k = (sum_k_term1 + sum_k_term2) % MOD;

    // Calculate sum_r = sum_{r=1}^{b-1} r
    // sum_r = (b-1) * b / 2
    // All calculations modulo MOD

    long long b_minus_1_val = (b - 1) % MOD;
    long long b_val = b % MOD;

    long long sum_r;
    if ((b - 1) % 2 == 0) {
        sum_r = (b_minus_1_val / 2) % MOD * b_val % MOD;
    } else {
        sum_r = b_minus_1_val % MOD * (b_val / 2) % MOD;
    }

    // Total sum = sum_r * sum_k
    long long total_sum = sum_r * sum_k % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> L(n);
    std::deque<int> dq;

    for (int i = 0; i < n; ++i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long prev_max_h = dq.empty() ? 0 : h[dq.back()];
        L[i] = h[i] - prev_max_h;
        dq.push_back(i);
    }

    dq.clear();
    std::vector<long long> R(n);
    for (int i = n - 1; i >= 0; --i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long prev_max_h = dq.empty() ? 0 : h[dq.back()];
        R[i] = h[i] - prev_max_h;
        dq.push_back(i);
    }

    long long max_val = 0;
    for (int i = 0; i < n; ++i) {
        max_val = std::max(max_val, std::min(L[i], R[i]));
    }

    std::cout << max_val << std::endl;

    return 0;
}

