#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_val_0 = 0;   // What 0 becomes after all operations
    int current_val_1023 = 1023; // What 1023 becomes after all operations

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val_0 &= x;
            current_val_1023 &= x;
        } else if (op_char == '|') {
            current_val_0 |= x;
            current_val_1023 |= x;
        } else if (op_char == '^') {
            current_val_0 ^= x;
            current_val_1023 ^= x;
        }
    }

    int final_and_mask = 1023; // Represents the constant for '&' operation
    int final_or_mask = 0;     // Represents the constant for '|' operation
    int final_xor_mask = 0;    // Represents the constant for '^' operation

    for (int j = 0; j < 10; ++j) { // Iterate through bits 0 to 9
        int bit_0_result = (current_val_0 >> j) & 1;
        int bit_1_result = (current_val_1023 >> j) & 1;

        if (bit_0_result == 0 && bit_1_result == 0) {
            // If input bit is 0, output bit is 0. If input bit is 1, output bit is 0.
            // This means the bit is always 0, regardless of input.
            // Achieved by ANDing with 0 at this bit position.
            final_and_mask &= ~(1 << j);
        } else if (bit_0_result == 1 && bit_1_result == 1) {
            // If input bit is 0, output bit is 1. If input bit is 1, output bit is 1.
            // This means the bit is always 1, regardless of input.
            // Achieved by ORing with 1 at this bit position.
            final_or_mask |= (1 << j);
        } else if (bit_0_result == 0 && bit_1_result == 1) {
            // If input bit is 0, output bit is 0. If input bit is 1, output bit is 1.
            // This means the bit is unchanged.
            // Achieved by ANDing with 1, ORing with 0, XORing with 0.
            // No change to final_and_mask, final_or_mask, final_xor_mask for this bit.
        } else { // bit_0_result == 1 && bit_1_result == 0
            // If input bit is 0, output bit is 1. If input bit is 1, output bit is 0.
            // This means the bit is flipped.
            // Achieved by XORing with 1 at this bit position.
            final_xor_mask |= (1 << j);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_mask != 1023) { // If any bit was forced to 0
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) {     // If any bit was forced to 1
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) {    // If any bit was flipped
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total possible substrings
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // If m ones, there are m+1 possible blocks of zeros
        // To minimize substrings of all zeros, distribute zeros as evenly as possible
        // among these m+1 blocks.
        // Let k be the number of blocks of zeros.
        // If m > 0, k = m + 1.
        // If m = 0, k = 1 (the whole string is one block of zeros).
        // The problem statement guarantees m >= 0. We handled m=0 above.
        // So, for m > 0, k = m + 1.

        long long k = m + 1; // Number of blocks of zeros

        // Distribute num_zeros into k blocks as evenly as possible
        long long q = num_zeros / k; // Minimum length of a zero block
        long long r = num_zeros % k; // Number of blocks with length q+1

        // Calculate sum of (len * (len + 1) / 2) for these blocks
        long long sum_zero_substrings = 0;

        // r blocks of length q+1
        if (r > 0) {
            sum_zero_substrings += r * (q + 1) * (q + 2) / 2;
        }

        // (k - r) blocks of length q
        if (k - r > 0) {
            sum_zero_substrings += (k - r) * q * (q + 1) / 2;
        }

        std::cout << total_substrings - sum_zero_substrings << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Operation 1: Make a[0]...a[n-2] divisible by n
    // For each a[i] (0 <= i < n-1), we want to add a multiple of n to make it 0 mod n.
    // The segment is [1, n]. Length is n.
    // We add (n - (a[i] % n)) % n * n to a[i].
    // This is equivalent to adding (n - (a[i] % n)) % n * n to a[i]
    // or simply -a[i] + k*n such that -a[i] is a multiple of n.
    // A simpler way: add (n - (a[i] % n + n) % n) * n to a[i].
    // Or, if a[i] % n != 0, add (n - a[i] % n) * n to a[i].
    // If a[i] % n == 0, add 0.
    // This makes a[i] become a[i] + (n - (a[i] % n + n) % n) * n.
    // The new a[i] will be a multiple of n.
    // The value to add is (n - (a[i] % n + n) % n) * n.
    // Let's use a different approach:
    // We want to add x_i such that x_i is a multiple of n and a[i] + x_i is a multiple of n.
    // The simplest x_i is (n - (a[i] % n + n) % n) * n.
    // This makes a[i] become a[i] + (n - (a[i] % n + n) % n) * n.
    // This is not what we want. We want to make a[i] become a[i] + k*n.
    // The problem states we can add a multiple of len.
    // So, for a[i], we want to add `val_i` such that `val_i` is a multiple of `n`.
    // And `a[i] + val_i` becomes `0`. This is not possible if `a[i]` is not a multiple of `n`.
    // The strategy is:
    // 1. Make all elements `a[0]...a[n-2]` divisible by `n`.
    //    Segment `[1, n-1]` (indices `0` to `n-2`). Length `n-1`.
    //    This is not good if `n=1`.
    //
    // Let's use the standard solution for n > 1:
    // Operation 1: Segment [1, n-1]. Length is n-1.
    // For each a[i] from i=0 to n-2:
    // We want to add x_i such that x_i is a multiple of (n-1) and a[i] + x_i is a multiple of n.
    // This is not directly possible.
    //
    // The standard solution for n > 1:
    // 1. Make a[0]...a[n-2] divisible by n.
    //    Segment [1, n]. Length n.
    //    For each a[i] (0 <= i < n-1):
    //    We want to add x_i such that x_i is a multiple of n, and a[i] + x_i is a multiple of n.
    //    This is always true if x_i is a multiple of n.
    //    We want to add x_i such that a[i] + x_i becomes a multiple of n.
    //    The simplest x_i is (n - (a[i] % n + n) % n) * n.
    //    This makes a[i] become a[i] + (n - (a[i] % n + n) % n) * n.
    //    This is not what we want. We want to add x_i such that a[i] + x_i is a multiple of n.
    //    The value to add is `(n - (a[i] % n + n) % n)`. This is not a multiple of n.
    //
    // Let's re-read: "add a multiple of len".
    // So, for a[i], we add `k_i * len`.
    //
    // Case n = 1:
    // Op 1: l=1, r=1. len=1. Add -a[0]. a[0] becomes 0.
    // Op 2: l=1, r=1. len=1. Add 0.
    // Op 3: l=1, r=1. len=1. Add 0.
    if (n == 1) {
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        std::cout << "1 1\n";
        std::cout << "0\n";
        std::cout << "1 1\n";
        std::cout << "0\n";
        return 0;
    }

    // For n > 1:
    // Operation 1: Make a[0]...a[n-2] divisible by n.
    // Segment [1, n-1]. Length is n-1.
    // For each a[i] (0 <= i < n-1):
    // We want to add x_i such that x_i is a multiple of (n-1).
    // And a[i] + x_i becomes a multiple of n.
    // Let a[i]' = a[i] + x_i. We want a[i]' % n == 0.
    // x_i = k * (n-1).
    // So a[i] + k * (n-1) = 0 (mod n).
    // a[i] + k * (-1) = 0 (mod n).
    // k = a[i] (mod n).
