    // The value to add is ((a[i] % n + n) % n) * (n-1).
    // After this operation, a[i] becomes a[i] + ((a[i] % n + n) % n) * (n-1).
    // This new a[i] is a multiple of n.
    // Let's store the values to add.
    std::cout << "1 " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long remainder = (a[i] % n + n) % n; // a[i] mod n, always positive
        long long to_add = remainder * (n - 1);
        std::cout << to_add << (i == n - 2 ? "" : " ");
        a[i] += to_add; // Update a[i]
    }
    std::cout << "\n";

    // Operation 2: Make a[n-1] divisible by n.
    // Segment [n, n]. Length is 1.
    // For a[n-1]:
    // We want to add x_{n-1} such that x_{n-1} is a multiple of 1.
    // And a[n-1] + x_{n-1} becomes a multiple of n.
    // The value to add is (n - (a[n-1] % n + n) % n).
    // This is not a multiple of 1. It is just the value to make it a multiple of n.
    // The value to add is (n - (a[n-1] % n + n) % n).
    // This is a multiple of 1.
    // After this operation, a[n-1] becomes a[n-1] + (n - (a[n-1] % n + n) % n).
    // This new a[n-1] is a multiple of n.
    std::cout << n << " " << n << "\n";
    long long remainder_n_minus_1 = (a[n - 1] % n + n) % n;
    long long to_add_n_minus_1 = remainder_n_minus_1;
    std::cout << to_add_n_minus_1 << "\n";
    a[n - 1] += to_add_n_minus_1; // Update a[n-1]

    // Operation 3: Make all elements zero.
    // Now all a[i] are multiples of n.
    // Segment [1, n]. Length is n.
    // For each a[i] (0 <= i < n):
    // We want to add x_i such that x_i is a multiple of n.
    // And a[i] + x_i becomes 0.
    // Since a[i] is already a multiple of n, we can just add -a[i].
    // -a[i] is a multiple of n.
    std::cout << "1 " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
