int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (only endpoints)
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_zero_dist(n); // Distance to nearest 0 on the left (inclusive)
    std::vector<int> right_zero_dist(n); // Distance to nearest 0 on the right (inclusive)
    std::vector<int> left_one_dist(n);  // Distance to nearest 1 on the left (inclusive)
    std::vector<int> right_one_dist(n); // Distance to nearest 1 on the right (inclusive)

    // Calculate distances
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            left_zero_dist[i] = 0;
            left_one_dist[i] = n + 1; // Effectively infinity
        } else { // a[i] == 1
            left_zero_dist[i] = (i > 0 ? left_zero_dist[i - 1] + 1 : n + 1);
            left_one_dist[i] = 0;
        }
    }

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 0) {
            right_zero_dist[i] = 0;
            right_one_dist[i] = n + 1;
        } else { // a[i] == 1
            right_zero_dist[i] = (i < n - 1 ? right_zero_dist[i + 1] + 1 : n + 1);
            right_one_dist[i] = 0;
        }
    }

    int max_steps = 0;
    std::vector<int> final_a = a;

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // Current element is 0
            // It can become 1 if it's surrounded by 1s.
            // The number of steps for a 0 to become 1 is min(dist_to_left_1, dist_to_right_1)
            // where dist_to_left_1 is (i - index_of_nearest_1_left)
            // and dist_to_right_1 is (index_of_nearest_1_right - i)
            // If it's not surrounded by 1s, it remains 0.

            // left_one_dist[i] is 0 if a[i]=1, or distance to nearest 1 on left if a[i]=0.
            // We need distance to nearest 1 on left *from* i.
            // If a[i] is 0, left_one_dist[i] is the distance to the nearest 1 on its left.
            // If a[i] is 0, right_one_dist[i] is the distance to the nearest 1 on its right.

            int dist_to_left_1 = left_one_dist[i];
            int dist_to_right_1 = right_one_dist[i];

            if (dist_to_left_1 == n + 1 || dist_to_right_1 == n + 1) {
                // No 1s on one or both sides, this 0 will remain 0.
                // max_steps doesn't change based on this 0.
            } else {
                int steps_to_change = std::min(dist_to_left_1, dist_to_right_1);
                max_steps = std::max(max_steps, steps_to_change);
                if (steps_to_change <= dist_to_left_1 && steps_to_change <= dist_to_right_1) {
                    // This 0 will eventually become 1
                    final_a[i] = 1;
                }
            }
        } else { // Current element is 1
            // It can become 0 if it's surrounded by 0s.
            // The number of steps for a 1 to become 0 is min(dist_to_left_0, dist_to_right_0)

            int dist_to_left_0 = left_zero_dist[i];
            int dist_to_right_0 = right_zero_dist[i];

            if (dist_to_left_0 == n + 1 || dist_to_right_0 == n + 1) {
                // No 0s on one or both sides, this 1 will remain 1.
            } else {
                int steps_to_change = std::min(dist_to_left_0, dist_to_right_0);
                max_steps = std::max(max_steps, steps_to_change);
                if (steps_to_change <= dist_to_left_0 && steps_to_change <= dist_to_right_0) {
                    // This 1 will eventually become 0
                    final_a[i] = 0;
                }
            }
        }
    }

    std::cout << max_steps << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

