struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // delta_sum[j] stores the sum of d_i for all type 1 operations
    // that affect index j up to the current point in the simulation.
    // This is used to calculate the current value of a[j] relative to its initial value.
    std::vector<long long> delta_sum(n, 0);

    // min_initial_val[j] stores the maximum possible value for initial_a[j]
    // based on type 2 operations.
    // If initial_a[j] + current_delta_sum[j] <= m_i, then initial_a[j] <= m_i - current_delta_sum[j].
    // We want to find the largest possible initial_a[j] that satisfies all such constraints.
    std::vector<long long> min_initial_val(n, 2000000000LL); // Initialize with a large value (10^9 + some margin)

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                delta_sum[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                min_initial_val[j] = std::min(min_initial_val[j], ops[i].val - delta_sum[j]);
            }
        }
    }

    // Now we have a candidate initial array `initial_a` where `initial_a[j] = min_initial_val[j]`.
    // We need to verify if this array satisfies all type 2 constraints.
    // Specifically, for each type 2 operation (l, r, m), we must have:
    // max_{j=l to r} (initial_a[j] + current_delta_sum[j]) == m.
    // We already ensured max_{j=l to r} (initial_a[j] + current_delta_sum[j]) <= m
    // by setting initial_a[j] <= m - current_delta_sum[j].
    // So we only need to check if max_{j=l to r} (initial_a[j] + current_delta_sum[j]) >= m.

    // Reset delta_sum for re-simulation
    std::fill(delta_sum.begin(), delta_sum.end(), 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                delta_sum[j] += ops[i].val;
            }
        } else { // type 2
            long long current_max = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_max = std::max(current_max, min_initial_val[j] + delta_sum[j]);
            }
            if (current_max != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << min_initial_val[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1); // a[0] unused, a[1] is the initial i
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> dp_y(n + 1, 0);
    std::vector<long long> dp_x(n + 1, 0);
    std::vector<bool> visited(n + 1, false);
    std::vector<bool> in_stack(n + 1, false);

    for (int i = 1; i <= n; ++i) {
        if (visited[i]) {
            continue;
        }

        std::vector<int> path;
        int current_x_val = i;

        while (current_x_val >= 1 && current_x_val <= n && !visited[current_x_val] && !in_stack[current_x_val]) {
            in_stack[current_x_val] = true;
            path.push_back(current_x_val);

            long long val_a_x = a[current_x_val];
            long long next_x_val = current_x_val + val_a_x;

            if (next_x_val <= 0 || next_x_val > n) { // Terminates after first step
                dp_y[current_x_val] = val_a_x;
                dp_x[current_x_val] = next_x_val;
                visited[current_x_val] = true;
                in_stack[current_x_val] = false;
                current_x_val = -1; // Mark as terminated
            } else { // Continues to second step
                long long final_x_after_step = next_x_val - val_a_x;
                long long final_y_after_step = val_a_x + a[next_x_val];

                if (final_x_after_step <= 0 || final_x_after_step > n) { // Terminates after second step
                    dp_y[current_x_val] = final_y_after_step;
                    dp_x[current_x_val] = final_x_after_step;
                    visited[current_x_val] = true;
                    in_stack[current_x_val] = false;
                    current_x_val = -1; // Mark as terminated
                } else { // Continues to next iteration
                    dp_y[current_x_val] = final_y_after_step;
                    dp_x[current_x_val] = final_x_after_step;
                    current_x_val = final_x_after_step;
                }
            }
        }

        if (current_x_val != -1) { // If loop didn't terminate, it either hit a visited node or a cycle
            if (current_x_val >= 1 && current_x_val <= n && visited[current_x_val]) {
                // Hit an already computed node
                // Propagate values back up the path
                for (int j = path.size() - 1; j >= 0; --j) {
                    int node = path[j];
                    if (dp_x[node] == current_x_val) { // This node's next state is current_x_val
                        dp_y[node] += dp_y[current_x_val];
                        dp_x[node] = dp_x[current_x_val];
                    }
                    visited[node] = true;
                    in_stack[node] = false;
                    current_x_val = node; // For the next iteration of the loop
                }
            } else { // Cycle detected or out of bounds from current_x_val
                // All nodes in the current path are part of a cycle or lead to one
                // Mark all nodes in the path that are still in_stack as -1
                for (int node : path) {
                    if (in_stack[node]) { // If it's still in the stack, it's part of the cycle
                        dp_y[node] = -1;
                        dp_x[node] = -1;
                        visited[node] = true;
                        in_stack[node] = false;
                    }
                }
            }
        }
    }

    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for the current run
        long long current_x = 1;
        long long current_y = 0;

        long long val_a_x = a[current_x];
        long long next_x_val = current_x + val_a_x;

        if (next_x_val <= 0 || next_x_val > n) {
            current_y += val_a_x;
            std::cout << current_y << "\n";
        } else {
            current_y += val_a_x;
            current_y += a[next_x_val];
            current_x = next_x_val - val_a_x;

            if (current_x <= 0 || current_x > n) {
                std::cout << current_y << "\n";
            } else {
                if (dp_y[current_x] == -1) {
                    std::cout << -1 << "\n";
                } else {
                    std::cout << current_y + dp_y[current_x] << "\n";
                }
            }
        }
    }

    return 0;
}

