struct Child {
    long long v, d, p;
    int original_idx;
    bool in_queue; // To mark if child is still in queue

    Child(long long v_val, long long d_val, long long p_val, int idx)
        : v(v_val), d(d_val), p(p_val), original_idx(idx), in_queue(true) {}
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children;
    children.reserve(n);
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children.emplace_back(v_val, d_val, p_val, i + 1);
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_queue) {
            continue;
        }

        // Child i goes to the doctor
        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_queue = false; // Mark as left the queue

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_chain = 0;

        // Apply current_v_cry and check for chain reactions
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_queue) {
                continue;
            }

            // Apply cry from child i
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply accumulated d_cry from previous chain reactions
            children[j].p -= total_d_cry_from_chain;

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                if (children[j].in_queue) { // Ensure we only add d_cry once per child
                    total_d_cry_from_chain += children[j].d;
                    children[j].in_queue = false;
                }
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

