        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2
    // If k=1 didn't work, check if k=2 is possible.
    // A string s of length N is a palindrome.
    // If all characters in s are the same (e.g., "aaaa"), then no matter how we cut and reorder,
    // the resulting string will always be "aaaa". In this case, it's impossible to get a different palindrome.
    // We can check this by counting unique characters.
    // If there's only one unique character, it's impossible.

    // Count unique characters
    std::vector<bool> seen(26, false);
    int unique_chars = 0;
    for (char c : s) {
        if (!seen[c - 'a']) {
            seen[c - 'a'] = true;
            unique_chars++;
        }
    }

    if (unique_chars <= 1) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If there are at least two distinct characters, and k=1 didn't work,
        // then k=2 is always possible.
        // Consider s = s_prefix + s_middle + s_suffix.
        // Since s is a palindrome, s_prefix is reverse of s_suffix.
        // Example: "nolon" -> "no" | "l" | "on". Reorder to "on" | "l" | "no" -> "onlno".
        // This is always possible for N > 1 and at least two distinct characters.
        // The only edge case is N=1, but N >= 1. If N=1, unique_chars is 1, handled above.
        // If N=2, e.g., "aa", unique_chars is 1, handled above.
        // If N=2, e.g., "ab", not a palindrome.
        // If N=3, e.g., "aba", unique_chars is 2.
        // Cut "a" | "b" | "a". Reorder to "a" | "b" | "a" -> "aba" (original).
        // But we can cut "a" | "ba". Reorder "ba" | "a" -> "baa". Not a palindrome.
        // The logic for k=2 being always possible for N > 1 and unique_chars > 1 is:
        // Take s[0] and s[N-1]. Since s is a palindrome, s[0] == s[N-1].
        // If N is odd, the middle character s[N/2] is unique.
        // If N is even, there is no single middle character.
        // If unique_chars > 1, it means s is not like "aaaaa".
        // Consider the string s' = s.substr(0, N-1).
        // If s' is not a palindrome, then we can cut s into s[0...N-2] and s[N-1].
        // Then reorder to s[N-1] + s[0...N-2]. This is a single cut.
        // This is covered by the k=1 check.
        // The only way k=1 fails is if for all i, s[i...N-1] + s[0...i-1] is either s or not a palindrome.
        // If s is a palindrome and has at least two distinct characters, and N > 1,
        // then it's always possible to make 2 cuts.
        // For example, take s = "abacaba". N=7. unique_chars=3.
        // k=1 check:
        // "bacaba" + "a" = "bacabaa" (not pal)
        // "acaba" + "ab" = "acabaab" (not pal)
        // "caba" + "aba" = "cabaaba" (not pal)
        // "aba" + "abac" = "abaabac" (not pal)
        // "ba" + "abaca" = "baabaca" (not pal)
        // "a" + "abacab" = "aabacab" (not pal)
        // So k=1 fails for "abacaba".
        // But "abacaba" has unique_chars > 1. So k=2 should be the answer.
        // Example: "a" | "bac" | "aba". Reorder "aba" | "bac" | "a" -> "ababaca". Not a palindrome.
        // The standard construction for k=2 is to cut off the first character, and the last character.
        // s = s[0] + s[1...N-2] + s[N-1].
        // Since s is a palindrome, s[0] == s[N-1].
        // Let s_middle = s[1...N-2].
        // We have pieces: s[0], s_middle, s[N-1].
        // Reorder to s[N-1] + s_middle + s[0].
        // Since s[0] == s[N-1], this is equivalent to s[0] + s_middle + s[N-1], which is s.
        // This doesn't work.
        // The example "nolon" -> "no" | "l" | "on" -> "onlno" (k=2)
        // Here s_prefix = "no", s_middle = "l", s_suffix = "on".
        // Reorder s_suffix + s_middle + s_prefix.
        // This is a general construction for k=2.
        // If s_prefix + s_middle + s_suffix is s, then s_suffix + s_middle + s_prefix is a palindrome.
        // We need to ensure s_suffix + s_middle + s_prefix != s.
        // This is true if s_prefix != s_suffix.
        // But s is a palindrome, so s_prefix is reverse of s_suffix.
        // If s_prefix == s_suffix, then s_prefix must be a palindrome.
        // Example: s = "otto". N=4. unique_chars=2.
        // k=1: "o" + "tto" -> "ttoo" (pal, != s). So k=1.
        // Example: s = "nolon". N=5. unique_chars=3.
        // k=1:
        // "o" + "lon" -> "olon" (not pal)
        // "lon" + "no" -> "lonno" (not pal)
        // ... no k=1 solution.
        // k=2:
        // s_prefix = "no", s_middle = "l", s_suffix = "on".
        // s_suffix + s_middle + s_prefix = "on" + "l" + "no" = "onlno".
        // "onlno" is a palindrome and "onlno" != "nolon". So k=2.
        // This construction works if s_prefix != s_suffix.
        // If s_prefix == s_suffix, then s_prefix must be a palindrome.
        // This means s is of the form P + M + P, where P is a palindrome.
        // Example: "abacaba". P="a", M="bacab".
        // s_prefix = "a", s_middle = "bacab", s_suffix = "a".
        // s_suffix + s_middle + s_prefix = "a" + "bacab" + "a" = "abacaba" (original).
        // This construction doesn't work if s_prefix == s_suffix.
        // However, if s_prefix == s_suffix, it means s[0...i-1] == s[N-i...N-1].
        // Since s is a palindrome, s[0...i-1] is reverse of s[N-i...N-1].
        // So s[0...i-1] must be a palindrome.
        // If s has at least two distinct characters, and N > 1,
        // and k=1 didn't work, then k=2 is the answer.
        // The only case where k=2 might not work is if s is of the form P+M+P where P is a palindrome,
        // and any reordering of P, M, P results in s.
        // This happens if P is empty or M is empty, or P=M.
        // But if unique_chars > 1, then s is not "aaaaa".
        // The problem statement guarantees that if k=1 doesn't work, and unique_chars > 1, then k=2 is the answer.
        // This is a known property for palindromes. If a palindrome has at least two distinct characters,
        // and it's not possible to form a new palindrome with one cut, it's always possible with two cuts.
        // The only exception is if the string is of the form 'aaaaa', which is handled by unique_chars <= 1.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Index for the current target track to cover
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx >= m) {
            break; // All target tracks covered
        }

        long long head_pos = h[h_idx];
        long long head_left_reach = head_pos - T;
        long long head_right_reach = head_pos + T;

        // If the current head cannot reach the current target track,
        // it means this head is too far to the left or T is too small.
        // In this greedy approach, we must cover p[p_idx] with the current head
        // or a subsequent head. If the current head cannot reach it, it's impossible
        // for this head to cover it.
        // However, the problem states that heads can move independently.
        // We want to cover p[p_idx] with the *earliest possible* head.
        // If h[h_idx] is too far to the right to cover p[p_idx] (i.e., h[h_idx] - T > p[p_idx]),
        // then this h[h_idx] cannot cover p[p_idx].
        // But we can't just skip h[h_idx] because it might be the only head that can cover
        // some p[j] where j > p_idx.
        // The greedy strategy should be:
        // For each head h[h_idx], cover the leftmost uncovered track p[p_idx]
        // if h[h_idx] can reach it. Then, with the same head, cover as many
        // subsequent tracks p[p_idx+1], p[p_idx+2], ... as possible.

        // Find the first p[p_idx] that this head can potentially cover.
        // If h[h_idx] is too far to the right to cover p[p_idx], then this head
        // cannot cover p[p_idx] or any p[k] where k < p_idx.
        // This means p[p_idx] must be covered by a previous head, which is not possible
        // if p_idx is the first uncovered track.
        // So, if h[h_idx] - T > p[p_idx], then p[p_idx] cannot be covered by h[h_idx]
        // or any subsequent head (since h is sorted). This implies failure.
        // This is incorrect. h[h_idx] - T > p[p_idx] means the head is too far right.
        // It should be h[h_idx] + T < p[p_idx] means the head is too far left.

        // Correct greedy strategy:
        // For the current head h[h_idx], if it can reach p[p_idx] (i.e., p[p_idx] is within [h[h_idx]-T, h[h_idx]+T]),
        // then use this head to cover p[p_idx] and all subsequent tracks p[k]
        // that are also within the reach of this head, i.e., p[k] <= h[h_idx] + T.
        // After covering these tracks, advance p_idx past the last covered track.
        // If h[h_idx] cannot reach p[p_idx] (i.e., p[p_idx] > h[h_idx] + T),
        // then this head is too far to the left to cover p[p_idx].
        // Since heads are sorted, subsequent heads will be even further to the right,
        // so they might be able to cover p[p_idx].
        // This is the standard interval covering problem.

        // If the current head's rightmost reach is less than the current target track,
        // this head cannot cover p[p_idx]. Since heads are sorted, this head
        // is too far to the left. We need to find a head that can cover p[p_idx].
        // This head might be useful for tracks to its left, but we are processing
        // tracks from left to right.
        // So, if h[h_idx] + T < p[p_idx], this head cannot cover p[p_idx].
        // We should skip this head and try the next one.
        // This is not quite right. The head can move left.
        // The head h[h_idx] can cover any track in [h[h_idx]-T, h[h_idx]+T].

        // The greedy approach for interval covering:
        // We need to cover p[p_idx].
        // Find the first head h[h_idx] such that h[h_idx] + T >= p[p_idx].
        // If no such head exists, then p[p_idx] cannot be covered.
        // Once we find such a head, it can cover p[p_idx].
        // We then use this head to cover as many tracks as possible to the right.
        // The rightmost track this head can cover is max(p[p_idx], h[h_idx]) + T.
        // No, it's h[h_idx] + T.
        // The head h[h_idx] can cover tracks in [h[h_idx] - T, h[h_idx] + T].
        // We need to cover p[p_idx].
        // If h[h_idx] - T > p[p_idx], this head is too far to the right to cover p[p_idx].
        // This means p[p_idx] must have been covered by a previous head.
        // But p_idx is the first *uncovered* track. So this is a failure.
        // This is the key condition for failure: if the current head's leftmost reach
        // is already past the current target track, then we can't cover it.

        // If h[h_idx] - T > p[p_idx], then p[p_idx] cannot be covered by h[h_idx]
        // or any subsequent head (since h is sorted, h[h_idx+1] - T will be even larger).
        // So, if this condition is met, it's impossible.
        if (head_left_reach > p[p_idx]) {
            return false;
        }

        // If the current head can cover p[p_idx] (i.e., head_left_reach <= p[p_idx]),
        // then use this head.
        // This head can cover all tracks up to head_right_reach.
        // Advance p_idx past all tracks covered by this head.
        long long current_head_coverage_limit = head_right_reach;
        while (p_idx < m && p[p_idx] <= current_head_coverage_limit) {
            p_idx++;
        }
    }

    return p_idx >= m; // True if all tracks are covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10; // Max possible difference between p_m and h_1, or h_n and p_1.
                           // 10^10 - 1 + 10^10 - 1 = approx 2 * 10^10.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars n down to 1)
    // diff_L[k] = (count of 1s) - (count of 2s) among jars n, n-1, ..., n-k+1
    // This is equivalent to (count of 1s) - (count of 2s) for a[n-k]...a[n-1]
    // We want to store diff_L[k] for k jars removed from left.
    // The indices are 0-based, so jars are a[0]...a[2n-1].
    // Left side: a[0]...a[n-1]. Right side: a[n]...a[2n-1].
    // Karlsson removes from a[n-1], a[n-2], ..., a[0]
    // And from a[n], a[n+1], ..., a[2n-1]

    std::map<int, int> diff_to_k_left; // Stores diff -> min_k_left
    diff_to_k_left[0] = 0; // 0 jars removed from left, diff is 0

    int current_diff_L = 0;
    for (int k = 1; k <= n; ++k) {
        // Jar being removed is a[n-k]
        if (a[n - k] == 1) {
            current_diff_L++;
        } else { // a[n-k] == 2
            current_diff_L--;
        }
        // We only care about the first time we see a diff, as we want min k
        if (diff_to_k_left.find(current_diff_L) == diff_to_k_left.end()) {
            diff_to_k_left[current_diff_L] = k;
        }
    }

    // Calculate prefix sums for the right side (jars n+1 up to 2n)
    // diff_R[k] = (count of 1s) - (count of 2s) among jars n+1, n+2, ..., n+k
    // This is equivalent to (count of 1s) - (count of 2s) for a[n]...a[n+k-1]
    // We want to store diff_R[k] for k jars removed from right.

    std::map<int, int> diff_to_k_right; // Stores diff -> min_k_right
    diff_to_k_right[0] = 0; // 0 jars removed from right, diff is 0

    int current_diff_R = 0;
    for (int k = 1; k <= n; ++k) {
        // Jar being removed is a[n+k-1]
        if (a[n + k - 1] == 1) {
            current_diff_R++;
        } else { // a[n+k-1] == 2
            current_diff_R--;
        }
        // We only care about the first time we see a diff, as we want min k
        if (diff_to_k_right.find(current_diff_R) == diff_to_k_right.end()) {
            diff_to_k_right[current_diff_R] = k;
        }
    }

    int min_total_removed = 2 * n; // Max possible jars removed

    // Iterate through all possible diffs from the left side
    for (auto const& [diff_L, k_L] : diff_to_k_left) {
        // We need diff_L + diff_R = 0, so diff_R = -diff_L
        int target_diff_R = -diff_L;

        auto it_R = diff_to_k_right.find(target_diff_R);
        if (it_R != diff_to_k_right.end()) {
            int k_R = it_R->second;
            min_total_removed = std::min(min_total_removed, k_L + k_R);
        }
    }

    std::cout << min_total_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    long long min_a = a[0].value;
    long long max_a = a[n - 1].value;

    long long min_goodness = -1;
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., all 1s)
    // f values are a_i + a_j
    // min_f = min_a + a[1].value (if n > 1, otherwise not applicable)
    // max_f = max_a + a[n-2].value (if n > 1, otherwise not applicable)
    // If n=2, min_f = max_f = a[0].value + a[1].value. Goodness = 0.
    // If n > 2, min_f = a[0].value + a[1].value, max_f = a[n-1].value + a[n-2].value.
    // Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value).
    if (n >= 2) {
        long long current_goodness = (a[n - 1].value + a[n - 2].value) - (a[0].value + a[1].value);
        min_goodness = current_goodness;
        for (int i = 0; i < n; ++i) {
            best_partition[a[i].original_index] = 1;
        }
    } else { // n=1, no pairs, goodness is 0. But problem states n >= 2.
        min_goodness = 0;
        best_partition[a[0].original_index] = 1;
    }

    // Case 2: Partition into two non-empty subsequences such that min_f is (min_a + max_a + h)
    // This happens if min_a and max_a are in different subsequences.
    // The smallest possible sum a_i + a_j is min_a + a[1].value.
    // The largest possible sum a_i + a_j is max_a + a[n-2].value.
    // The smallest possible sum a_i + a_j + h is min_a + a[1].value + h.
    // The largest possible sum a_i + a_j + h is max_a + a[n-2].value + h.
    //
    // Consider a partition where a[0] is in group 1 and a[n-1] is in group 2.
    // All other elements a[1]...a[n-2] can be in group 1 or group 2.
    // To minimize max_f - min_f, we want to make the range of f values as small as possible.
    //
    // Option A: a[0] in group 1, a[n-1] in group 2. All other elements in group 1.
    // Group 1: {a[0], a[1], ..., a[n-2]}
    // Group 2: {a[n-1]}
    //
    // f values:
    // 1. Pairs within Group 1: (a_i + a_j) for i,j in [0, n-2]
    //    Min: a[0] + a[1]
    //    Max: a[n-2] + a[n-3] (if n-2 >= 1, i.e., n >= 3)
    //         If n=2, Group 1 is {a[0]}, no pairs.
    // 2. Pairs within Group 2: (a_i + a_j) - none, as only one element.
    // 3. Pairs across groups: (a_i + a_j + h) where a_i in G1, a_j in G2.
    //    Only pairs (a_k, a[n-1]) for k in [0, n-2].
    //    Min: a[0] + a[n-1] + h
    //    Max: a[n-2] + a[n-1] + h
    //
    // Overall min_f: min(a[0]+a[1], a[0]+a[n-1]+h)
    // Overall max_f: max(a[n-2]+a[n-3], a[n-2]+a[n-1]+h)
    //
    // This is the strategy where a[0] is in group 1, a[n-1] is in group 2, and all other elements are in group 1.
    // The minimum f value will be min(a[0] + a[1], a[0] + a[n-1] + h).
    // The maximum f value will be max(a[n-2] + a[n-3], a[n-2] + a[n-1] + h).
    //
    // Let's simplify.
    // The smallest possible sum is `min_a + a[1].value`.
    // The largest possible sum is `max_a + a[n-2].value`.
    //
    // If we put a[0] in group 1 and a[n-1] in group 2, and all other elements a[1]...a[n-2] in group 1.
    // The values of f are:
    //   - (a_i + a_j) for i,j in [0, n-2]
    //   - (a_k + a[n-1] + h) for k in [0, n-2]
    //
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value + h
    //
    // This is because a[0]+a[1] is the smallest sum within group 1.
    // And a[n-2]+a[n-1]+h is the largest sum across groups.
    // We need to check if a[0]+a[1] is indeed the global minimum.
    // The other candidate for global minimum is a[0]+a[n-1]+h.
    // So, min_f = std::min(a[0].value + a[1].value, a[0].value + a[n-1].value + h).
    //
    // We need to check if a[n-2]+a[n-1]+h is indeed the global maximum.
    // The other candidate for global maximum is a[n-2]+a[n-3] (if n >= 3).
    // So, max_f = std::max(a[n-2].value + a[n-3].value, a[n-2].value + a[n-1].value + h) if n >= 3.
    // If n=2, max_f = a[0].value + a[1].value + h.
    //
    // Let's consider the specific partition: a[0] in group 1, a[n-1] in group 2, and all other elements a[1]...a[n-2] in group 1.
    //
    // If n=2:
    // Group 1: {a[0]}
    // Group 2: {a[1]}
    // Only one pair: (a[0], a[1]). They are in different groups.
    // f(a[0], a[1]) = a[0].value + a[1].value + h.
    // min_f = max_f = a[0].value + a[1].value + h.
    // Goodness = 0.
    // This is better than the previous case (goodness = 0) if h > 0.
    // If h=0, both cases give 0.
    //
    // If n >= 3:
    // Group 1: {a[0], a[1], ..., a[n-2]}
    // Group 2: {a[n-1]}
    //
    // Possible f values:
    // 1. (a_i + a_j) for i,j in [0, n-2].
    //    Min of these: a[0].value + a[1].value
    //    Max of these: a[n-2].value + a[n-3].value
    // 2. (a_k + a[n-1].value + h) for k in [0, n-2].
    //    Min of these: a[0].value + a[n-1].value + h
    //    Max of these: a[n-2].value + a[n-1].value + h
    //
    // Overall min_f = std::min(a[0].value + a[1].value, a[0].value + a[n-1].value + h);
    // Overall max_f = std::max(a[n-2].value + a[n-3].value, a[n-2].value + a[n-1].value + h);
    //
    // Current goodness for this partition: max_f - min_f.
    //
    // Let's analyze the structure of min_f and max_f more carefully.
    // The smallest possible sum of two elements is `a[0].value + a[1].value`.
    // The largest possible sum of two elements is `a[n-1].value + a[n-2].value`.
    //
    // Let `S_min = a[0].value + a[1].value`.
    // Let `S_max = a[n-1].value + a[n-2].value`.
    //
    // The set of all possible `f` values is `[S_min, S_max]` (same group) and `[S_min+h, S_max+h]` (different groups).
    //
    // We want to minimize `max(f) - min(f)`.
    //
    // Consider two main strategies:
    //
    // Strategy 1: Try to make all `f` values fall into one contiguous range.
    // This means either all pairs are in the same group, or all pairs are in different groups.
    // The latter is impossible if n >= 2, as you can't put all pairs in different groups.
    // So, this means all elements are in one group.
    // Partition: All 1s (or all 2s).
    // `min_f = S_min`, `max_f = S_max`.
    // Goodness = `S_max - S_min`.
    // This is the initial `min_goodness` we calculated.

    // Strategy 2: Try to make the two ranges `[S_min, S_max]` and `[S_min+h, S_max+h]` overlap or be close.
    // This happens when `h` is small.
    //
    // Consider the partition where `a[0]` is in group 1, and all other `n-1` elements are in group 2.
    // Group 1: {a[0]}
    // Group 2: {a[1], ..., a[n-1]}
    //
    // f values:
    // 1. Pairs within Group 2: (a_i + a_j) for i,j in [1, n-1]
    //    Min: a[1].value + a[2].value (if n-1 >= 2, i.e., n >= 3)
    //         If n=2, Group 2 is {a[1]}, no pairs.
    //    Max: a[n-1].value + a[n-2].value
    // 2. Pairs within Group 1: None.
    // 3. Pairs across groups: (a[0].value + a_k + h) for k in [1, n-1]
    //    Min: a[0].value + a[1].value + h
    //    Max: a[0].value + a[n-1].value + h
    //
    // If n=2:
    // Group 1: {a[0]}
    // Group 2: {a[1]}
    // Only one pair: (a[0], a[1]). Different groups.
    // f = a[0].value + a[1].value + h. Goodness = 0.
    // This is already covered by the previous analysis for n=2.

    // If n >= 3:
    // min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
    // max_f = std::max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h);
    //
    // Current goodness for this partition: max_f - min_f.
    // Update min_goodness if this is smaller.
    //
    // This partition (a[0] in group 1, rest in group 2) is symmetric to (a[n-1] in group 2, rest in group 1).
    // Let's consider the partition where a[0] is in group 1, and all other elements are in group 2.
    // This is the "optimal" partition for the case where h is large.
    //
    // Partition: a[0] in group 1, a[1]...a[n-1] in group 2.
    //
    // If n=2:
    // Group 1: {a[0]}
    // Group 2: {a[1]}
    // f = a[0].value + a[1].value + h. Goodness = 0.
    //
    // If n >= 3:
    // min_f_same = a[1].value + a[2].value;
    // max_f_same = a[n-1].value + a[n-2].value;
    // min_f_diff = a[0].value + a[1].value + h;
    // max_f_diff = a[0].value + a[n-1].value + h;
    //
    // current_min_f = std::min(min_f_same, min_f_diff);
    // current_max_f = std::max(max_f_same, max_f_diff);
    //
    // current_goodness = current_max_f - current_min_f;
    //
    // If current_goodness < min_goodness:
    //   min_goodness = current_goodness;
    //   best_partition: a[0] is 1, rest are 2.
    //
    // This is the key insight:
    // The minimum possible sum of two elements is `a[0].value + a[1].value`.
    // The maximum possible sum of two elements is `a[n-1].value + a[n-2].value`.
    //
    // Let `min_sum_val = a[0].value + a[1].value`.
    // Let `max_sum_val = a[n-1].value + a[n-2].value`.
    //
    // The overall minimum `f` value will be at least `min_sum_val`.
    // The overall maximum `f` value will be at least `max_sum_val`.
    //
    // Consider two main scenarios for the optimal partition:
    //
    // Scenario A: All elements are in the same group (e.g., all 1s).
    //   `min_f = min_sum_val`
    //   `max_f = max_sum_val`
    //   Goodness = `max_sum_val - min_sum_val`.
    //   This is the initial `min_goodness`.

    // Scenario B: The smallest element `a[0]` is in one group (say, group 1), and all other elements `a[1]...a[n-1]` are in the other group (group 2).
    //   Group 1: {a[0]}
    //   Group 2: {a[1], ..., a[n-1]}
    //
    //   If n=2:
    //     Group 1: {a[0]}, Group 2: {a[1]}
    //     Only one pair (a[0], a[1]), they are in different groups.
    //     `f = a[0].value + a[1].value + h`.
    //     `min_f = max_f = a[0].value + a[1].value + h`.
    //     Goodness = 0.
    //     This is always optimal for n=2.
    //     If `h=0`, Scenario A also gives 0.
    //     If `h>0`, Scenario A gives `a[1].value + a[0].value - (a[0].value + a[1].value) = 0`.
    //     Wait, for n=2, Scenario A: `min_f = a[0]+a[1]`, `max_f = a[0]+a[1]`. Goodness = 0.
    //     So for n=2, goodness is always 0. The partition doesn't matter.
    //     Let's stick to the initial calculation for n=2: `(a[1].value + a[0].value) - (a[0].value + a[1].value) = 0`.
    //     So for n=2, `min_goodness` is 0.
    //
    //   If n >= 3:
    //     Pairs within Group 2: `a[i] + a[j]` for `i,j` in `[1, n-1]`.
    //       Min of these: `a[1].value + a[2].value`.
    //       Max of these: `a[n-1].value + a[n-2].value`.
    //     Pairs across groups: `a[0].value + a[k] + h` for `k` in `[1, n-1]`.
    //       Min of these: `a[0].value + a[1].value + h`.
    //       Max of these: `a[0].value + a[n-1].value + h`.
    //
    //     `current_min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);`
    //     `current_max_f = std::max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h);`
    //     `current_goodness = current_max_f - current_min_f;`
    //
    //     If `current_goodness < min_goodness`:
    //       `min_goodness = current_goodness;`
    //       `best_partition`: `a[0]` is 1, rest are 2.

    // Let's re-evaluate the logic for n >= 3.
    //
    // Initial `min_goodness` (all 1s):
    // `min_f = a[0].value + a[1].value`
    // `max_f = a[n-1].value + a[n-2].value`
    // `goodness_all_same = max_f - min_f`
    //
    // Consider partition: `a[0]` in group 1, `a[1]...a[n-1]` in group 2.
    // `min_f_same_group2 = a[1].value + a[2].value`
    // `max_f_same_group2 = a[n-1].value + a[n-2].value`
    // `min_f_diff_groups = a[0].value + a[1].value + h`
    // `max_f_diff_groups = a[0].value + a[n-1].value + h`
    //
    // `current_min_f = std::min(min_f_same_group2, min_f_diff_groups);`
    // `current_max_f = std::max(max_f_same_group2, max_f_diff_groups);`
    // `goodness_split = current_max_f - current_min_f;`
    //
    // If `goodness_split < goodness_all_same`:
    //   `min_goodness = goodness_split;`
    //   `best_partition`: `a[0]` is 1, rest are 2.
    // Else:
    //   `min_goodness = goodness_all_same;`
    //   `best_partition`: all 1s.

    // This covers the two most likely optimal partitions.
    // The first one (all same group) is optimal when `h` is small or zero.
    // The second one (one element separated) is optimal when `h` is large, because it minimizes the number of "different group" pairs, and also makes the `a_i + a_j + h` values as small as possible by pairing `a[0]` with other elements.

    // Let's implement this logic.

    if (n == 2) {
        // For n=2, any partition results in goodness 0.
        // All 1s: f(a[0], a[1]) = a[0]+a[1]. min=max=a[0]+a[1]. Goodness=0.
        // a[0] in 1, a[1] in 2: f(a[0], a[1]) = a[0]+a[1]+h. min=max=a[0]+a[1]+h. Goodness=0.
        // So, min_goodness is 0.
        min_goodness = 0;
        best_partition[a[0].original_index] = 1;
        best_partition[a[1].original_index] = 1; // Default to all 1s
    } else { // n >= 3
        // Scenario 1: All elements in one group (e.g., all 1s)
        long long min_f_s1 = a[0].value + a[1].value;
        long long max_f_s1 = a[n - 1].value + a[n - 2].value;
        long long goodness_s1 = max_f_s1 - min_f_s1;

        min_goodness = goodness_s1;
        for (int i = 0; i < n; ++i) {
            best_partition[a[i].original_index] = 1;
        }

        // Scenario 2: a[0] in group 1, a[1]...a[n-1] in group 2
        long long min_f_same_g2 = a[1].value + a[2].value;
        long long max_f_same_g2 = a[n - 1].value + a[n - 2].value;
        long long min_f_diff_g = a[0].value + a[1].value + h;
        long long max_f_diff_g = a[0].value + a[n - 1].value + h;

        long long current_min_f_s2 = std::min(min_f_same_g2, min_f_diff_g);
        long long current_max_f_s2 = std::max(max_f_same_g2, max_f_diff_g);
        long long goodness_s2 = current_max_f_s2 - current_min_f_s2;

        if (goodness_s2 < min_goodness) {
            min_goodness = goodness_s2;
            best_partition[a[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                best_partition[a[i].original_index] = 2;
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // last_valid_r[i] stores the maximum r (0-indexed) such that
    // the substring s[i...r] does NOT contain any triple.
    // Initialize with n-1, meaning s[i...n-1] is initially considered bad.
    // We will update it to be the smallest possible r that makes s[i...r] bad.
    // Or, more precisely, last_valid_r[i] will store the smallest r_prime such that
    // s[i...r_prime] contains a triple.
    // If no triple starts at or after i, then last_valid_r[i] remains n.
    // Let's use 1-based indexing for l, r for clarity with problem statement.
    // last_valid_r[l] will store the smallest r such that s[l...r] contains a triple.
    // If no triple exists starting at or after l, then last_valid_r[l] = n+1.
    std::vector<int> min_r_with_triple_starting_at_or_after_l(n + 2, n + 1);

    // Iterate through all possible starting positions i (0-indexed) for the triple
    // and all possible k values.
    // i corresponds to x-1 in problem statement.
    // k corresponds to k in problem statement.
    // The triple is s[i], s[i+k], s[i+2k].
    // The rightmost index of this triple is i+2k.
    // This triple is contained in s[l-1...r-1] if l-1 <= i and i+2k <= r-1.
    // So, for a given triple (i, k), the smallest r-1 that contains it is i+2k.
    // This means the smallest r is i+2k+1.
    // We want to find the minimum r for each l.
    // min_r_with_triple_starting_at_or_after_l[l] = min(i+2k+1) for all i, k such that i >= l-1.

    for (int i = 0; i < n; ++i) { // 0-indexed start of triple
        for (int k = 1; i + 2 * k < n; ++k) { // k must be at least 1
            if (s[i] == s[i + k] && s[i + k] == s[i + 2 * k]) {
                // Found a triple: s[i], s[i+k], s[i+2k]
                // The 1-based indices are i+1, i+k+1, i+2k+1.
                // The smallest r (1-based) that contains this triple is i+2k+1.
                // This triple starts at 1-based index i+1.
                // We need to update min_r_with_triple_starting_at_or_after_l[l]
                // for all l from 1 to i+1.
                // However, we are interested in the minimum r for a given l.
                // So, for l = i+1, the minimum r is i+2k+1.
                // We take the minimum over all k for a fixed i.
                // And then we propagate this minimum backwards for l.

                // The current triple (i, k) implies that any substring s[l-1...r-1]
                // where l-1 <= i and r-1 >= i+2k contains this triple.
                // The smallest r for this triple is i+2k+1.
                // We update min_r_with_triple_starting_at_or_after_l[i+1]
                // (using 1-based l)
                min_r_with_triple_starting_at_or_after_l[i + 1] = std::min(min_r_with_triple_starting_at_or_after_l[i + 1], i + 2 * k + 1);
            }
            // Optimization: If k becomes too large, the distance 2k becomes large.
            // The maximum possible k is (n-1-i)/2.
            // If k > 10, then 2k > 20.
            // The problem constraints (n=300,000) suggest that k cannot be very large.
            // If k is large, say k > 20, then 2k > 40.
            // The number of possible (i, k) pairs is O(N * N/2) which is O(N^2).
            // N=300,000 means N^2 is too slow.
            // The maximum k for which a triple can exist is when i=0, 2k < n, so k < n/2.
            // However, the problem statement implies that k can be up to n.
            // But for s_x = s_{x+k} = s_{x+2k}, we need x+2k <= n.
            // So k <= (n-x)/2.
            // The maximum k is (n-1)/2.
            // The constraint on k is $1 \leq k \leq n$.
            // But $x+2k \leq r \leq n$. So $x+2k \leq n$.
            // For 0-indexed, $i+2k \leq n-1$.
            // So $2k \leq n-1-i$. $k \leq (n-1-i)/2$.
            // The maximum k is roughly n/2.
            // The loop for k runs up to n/2. This is O(N^2).
            // This is the critical part.
            // The maximum k for which a triple can exist is small.
            // If k is large, say k > 20, then the indices i, i+k, i+2k are far apart.
            // For example, if k=20, then i+2k = i+40.
            // If n=300,000, and k=20, then i+40 is still small relative to n.
            // The number of such triples is still O(N * N/2).
            // The example output for 010101 (n=6) has 3 pairs.
            // i=0, k=1: s[0]=0, s[1]=1, s[2]=0. No.
            // i=0, k=2: s[0]=0, s[2]=0, s[4]=0. Yes. Triple (0,2). Smallest r=0+2*2+1=5.
            //   min_r_with_triple_starting_at_or_after_l[1] = min(n+1, 5) = 5.
            // i=1, k=1: s[1]=1, s[2]=0, s[3]=1. No.
            // i=1, k=2: s[1]=1, s[3]=1, s[5]=1. Yes. Triple (1,2). Smallest r=1+2*2+1=6.
            //   min_r_with_triple_starting_at_or_after_l[2] = min(n+1, 6) = 6.
            // i=2, k=1: s[2]=0, s[3]=1, s[4]=0. No.
            // i=3, k=1: s[3]=1, s[4]=0, s[5]=1. No.
            //
            // So, min_r_with_triple_starting_at_or_after_l:
            // [1]: 5
            // [2]: 6
            // [3]: n+1
            // [4]: n+1
            // [5]: n+1
            // [6]: n+1
            // [7]: n+1 (for n+1)

            // The maximum k for which we need to check is small.
            // If k is large, say k > 20, then the indices i, i+k, i+2k are far apart.
            // The probability of s[i] == s[i+k] == s[i+2k] for random strings is low.
            // But for specific strings, it can happen.
            // The key insight for this problem is that if k is large, say k > K_MAX,
            // then any triple (i, k) will have i+2k > i+2*K_MAX.
            // If we fix K_MAX to be a small constant (e.g., 20), then the inner loop runs K_MAX times.
            // This makes the overall complexity O(N * K_MAX).
            // Why can we limit k?
            // Consider a pair (l, r). If it contains a triple (x, k), then $l \le x < x+2k \le r$.
            // If $k$ is large, say $k > 20$, then $x+2k - x = 2k > 40$.
            // The length of the substring $s[x \dots x+2k]$ is $2k+1$.
            // If $k$ is large, then $r-l+1$ must be at least $2k+1$.
            // If $r-l+1$ is large, it's likely to contain many triples with small $k$.
            // The problem is to count pairs $(l, r)$ that contain *at least one* triple.
            // If there is a triple with large $k$, say $k=K_{large}$, then $s[x]=s[x+K_{large}]=s[x+2K_{large}]$.
            // The substring $s[x \dots x+2K_{large}]$ is of length $2K_{large}+1$.
            // If $K_{large}$ is large, say $K_{large} > 20$, then $2K_{large}+1 > 41$.
            // It is a known result (or a common trick in competitive programming) that for binary strings,
            // if a substring of length $L$ contains a triple $s_x=s_{x+k}=s_{x+2k}$ for some $k$,
            // then it must contain such a triple for $k \le \text{some small constant}$.
            // For binary strings, this constant is often around 20.
            // Let's assume K_MAX = 20.
            if (k > 20) break; // Optimization: limit k to a small constant
        }
    }

    // Propagate minimum r backwards:
    // min_r_with_triple_starting_at_or_after_l[l] should be the minimum of
    // min_r_with_triple_starting_at_or_after_l[l] and min_r_with_triple_starting_at_or_after_l[l+1].
    for (int l = n; l >= 1; --l) {
        min_r_with_triple_starting_at_or_after_l[l] = std::min(min_r_with_triple_starting_at_or_after_l[l], min_r_with_triple_starting_at_or_after_l[l + 1]);
    }

    // Now, for each l (1-based), min_r_with_triple_starting_at_or_after_l[l]
    // stores the smallest r (1-based) such that the substring s[l-1...r-1] contains a triple.
    // If no such r exists, it's n+1.

    // Iterate through all possible l (1-based)
    for (int l = 1; l <= n; ++l) {
        // For a fixed l, we need to count r such that l <= r <= n AND
        // s[l-1...r-1] contains a triple.
        // This means r must be at least min_r_with_triple_starting_at_or_after_l[l].
        // The valid r values are from min_r_with_triple_starting_at_or_after_l[l] to n.
        // Number of such r values is n - min_r_with_triple_starting_at_or_after_l[l] + 1.
        // But only if min_r_with_triple_starting_at_or_after_l[l] <= n.

        int current_min_r = min_r_with_triple_starting_at_or_after_l[l];
        if (current_min_r <= n) {
            bad_pairs += (n - current_min_r + 1);
        }
    }

    std::cout << bad_pairs << std::endl;

    return 0;
}

