        std::cin >> n;
        // The strategy is to pick numbers of the form 2*k where k is odd,
        // specifically 2 * (2n-1), 2 * (2n-3), ..., 2 * 1.
        // This ensures all numbers are even, so gcd(a,b) >= 2.
        // Also, since they are 2 * odd_number, no number divides another.
