        // The largest number is 2 * (2n-1) = 4n-2.
        // The smallest number is 2 * 1 = 2.
        // All numbers are within [1, 4n].
        for (int i = 0; i < n; ++i) {
            std::cout << 2 * (2 * n - 1 - 2 * i) << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

