    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        }
    }

    // To form "one": needs 'o', 'n', 'e'
    // To form "zero": needs 'z', 'e', 'r', 'o'

    // Prioritize '1's (from "one") because they contribute more to the maximum number.
    // The number of '1's is limited by the minimum of 'n', 'o', 'e' counts.
    // Note: 'e' and 'o' are shared.
    // Let's count how many '1's we can make.
    // Each '1' uses one 'n', one 'o', one 'e'.
    // Each '0' uses one 'z', one 'e', one 'r', one 'o'.

    // The 'n' character is unique to "one". So, the number of '1's is directly count_n.
    int num_ones = count_n;

    // After forming num_ones, we use up:
    // num_ones 'o's
    // num_ones 'e's
    // num_ones 'n's (already accounted for by count_n)

    // Remaining characters for "zero":
    // count_o_remaining = count_o - num_ones
    // count_e_remaining = count_e - num_ones
    // count_z_remaining = count_z
    // count_r_remaining = count_r

    // The number of '0's is limited by the minimum of 'z', 'e_remaining', 'r', 'o_remaining'.
    // Since 'z' is unique to "zero", the number of '0's is directly count_z.
    int num_zeros = count_z;

    // Output '1's first, then '0's to form the maximum number.
    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    for (int i = 0; i < num_zeros; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }
    std::cout << std::endl;

    return 0;
}

