void solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<std::vector<int>> a(n, std::vector<int>(m));
    std::vector<bool> row_claimed(n, false);
    std::vector<bool> col_claimed(m, false);

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            std::cin >> a[i][j];
            if (a[i][j] == 1) {
                row_claimed[i] = true;
                col_claimed[j] = true;
            }
        }
    }

    int available_rows = 0;
    for (int i = 0; i < n; ++i) {
        if (!row_claimed[i]) {
            available_rows++;
        }
    }

    int available_cols = 0;
    for (int j = 0; j < m; ++j) {
        if (!col_claimed[j]) {
            available_cols++;
        }
    }

    // The number of moves possible in the game is min(available_rows, available_cols).
    // Each move claims one row and one column.
    // The game is equivalent to a game where players take turns removing one item
    // from a pile of min(available_rows, available_cols) items.
    // The player who takes the last item wins (normal play convention).
    // In this problem, the player who cannot make a move loses.
    // This is equivalent to Nim pile of size k, where k = min(available_rows, available_cols).
    // The first player wins if k is odd, the second player wins if k is even.

    int num_moves = std::min(available_rows, available_cols);

    if (num_moves % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

