int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1 and all other elements are less than n-1.
    // If so, it means the actual value for that p[i] should be n.
    // This happens if the original p[i] was n, then max_val_in_row would be n-1.
    // If no p[i] is n, then we need to find the one that should be n.
    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n is not present in the reconstructed p, it means the element that
        // was originally n in the permutation p_orig resulted in max_val_in_row = n-1.
        // All other elements p_orig[k] < n would result in max_val_in_row <= p_orig[k].
        // So, we need to find an element in p that is n-1 and change it to n.
        // If there are multiple n-1s, any one will do.
        // The problem guarantees a solution exists.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

