void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 0) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix_price = a[n - 1]; // Initialize with the last price, as it's the minimum for the suffix ending at n-1

    // Iterate from right to left, starting from the second to last element
    // The last element a[n-1] can never be a bad price because there are no days after it.
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix_price) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix_price, it means a[i] is
            // either equal to or less than the current minimum in the suffix.
            // So, a[i] becomes the new minimum for the suffix starting at i.
            min_suffix_price = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

