#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_stair_cells = 0;
        long long k = 1; // Represents the number of stairs in the current nice staircase (1, 3, 7, 15, ...)
        while (true) {
            // Calculate cells for a nice staircase with k stairs
            // A nice staircase with k stairs uses (k * (k + 1) / 2) cells.
            // This is the sum of 1 to k.
            // The sequence of k values for nice staircases is 1, 3, 7, 15, ...
            // These are of the form 2^p - 1.
            // The number of cells for such a staircase is (2^p - 1) * (2^p) / 2.
            // Let's use the formula derived: cells = (2^p * (2^p - 1)) / 2.
            // Or, more simply, cells = k * (k + 1) / 2.
            // The sequence of k values is 1, 3, 7, 15, ...
            // The sequence of cells for these k values is:
            // k=1: 1*(1+1)/2 = 1
            // k=3: 3*(3+1)/2 = 6
            // k=7: 7*(7+1)/2 = 28
            // k=15: 15*(15+1)/2 = 120
            // k=31: 31*(31+1)/2 = 496
            // The problem states that the cost of a staircase with n stairs is n*(n+1)/2.
            // The crucial observation is that the nice staircases are those with n = 2^p - 1 stairs.
            // Let's calculate the cells for the current nice staircase with k stairs.
            current_stair_cells = k * (k + 1) / 2;

            if (x >= current_stair_cells) {
                x -= current_stair_cells;
                count++;
                // Calculate the next k for the next nice staircase.
                // The sequence of k is 1, 3, 7, 15, ... which is 2^p - 1.
                // So, next k = 2 * k + 1.
                k = 2 * k + 1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

