int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            if (mid == 0) { // Handle the case where 0 teams are formed
                ans = std::max(ans, mid);
                low = mid + 1;
                continue;
            }
            // Check if 'mid' teams can be formed
            // Each team needs 1 coder, 1 mathematician, and 1 other.
            // We need 'mid' coders and 'mid' mathematicians.
            // The remaining 'mid' slots can be filled by any student.
            // Total students needed: 3 * mid
            // Coders available: c
            // Mathematicians available: m
            // Students without specialization available: x

            // If we form 'mid' teams, we use 'mid' coders and 'mid' mathematicians.
            // Remaining coders: c - mid
            // Remaining mathematicians: m - mid
            // Remaining students without specialization: x

            // The total number of "extra" students available to fill the third slot in each team is:
            // (c - mid) + (m - mid) + x

            // We need 'mid' students to fill the third slot in 'mid' teams.
            // So, (c - mid) + (m - mid) + x >= mid

            if (c >= mid && m >= mid && (c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number to use for generating k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between the smallest available number and the largest available number
    // from the range [1, k+1].
    // For example, if k=3, we use numbers 1, 2, 3, 4.
    // Sequence: 1, 4, 2, 3
    // Differences: |1-4|=3, |4-2|=2, |2-3|=1. Distinct differences: {1, 2, 3}.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index, take from left (smallest available)
            p[i] = left;
            left++;
        } else { // Odd index, take from right (largest available)
            p[i] = right;
            right--;
        }
    }

    // The remaining numbers are k+2, k+3, ..., n.
    // To ensure no new distinct differences are introduced (or only difference 1),
    // we can simply append them in increasing order.
    // This will only produce a difference of 1.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // Since p[k] is already set, the next number is k+2, then k+3, etc.
                      // The numbers used so far are from 1 to k+1.
                      // The next available number is k+2.
                      // If p[k] was the last number from the alternating sequence,
                      // and it was `left` (e.g., k+1), then the next number is `k+2`.
                      // If p[k] was `right` (e.g., 1 or 2), then the next number is `k+2`.
                      // The `left` variable correctly holds the next available number.
        p[i] = left;
        left++;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_values;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_values.insert(q[0]);

    // For i from 1 to n-1 (p_2 to p_n)
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            p[i] = q[i];
            if (used_values.count(q[i])) {
                // This should not happen if q is valid, as q_i > q_{i-1} implies q_i is a new value
                // and q_i is always <= n.
                // But as a safety check for permutation validity.
                possible = false;
                break;
            }
            used_values.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, p_i must be some value less than or equal to q_i (which is q_{i-1})
            // and not yet used. We need to find the largest available value that is less than q_i.
            // The largest available value not yet used and less than q_i is (q_i - 1) if not used,
            // then (q_i - 2) if not used, and so on.
            // We can iterate downwards from q_i - 1 to find the largest available number.
            // Or, more efficiently, use a set of available numbers.
            // The numbers available are those from 1 to n that are not in used_values.
            // We need the largest available number that is strictly less than q_i.

            // Find the largest number in [1, q_i-1] that is not in used_values.
            // A simple way is to iterate downwards from q_i-1.
            int found_val = -1;
            for (int val_to_try = q[i] - 1; val_to_try >= 1; --val_to_try) {
                if (!used_values.count(val_to_try)) {
                    found_val = val_to_try;
                    break;
                }
            }

            if (found_val != -1) {
                p[i] = found_val;
                used_values.insert(found_val);
            } else {
                // No suitable number found. This means it's impossible.
                possible = false;
                break;
            }
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

