    // Find the rightmost index 'i' such that a[i] < a[i+1]
    // This marks the end of the initial non-increasing suffix
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now, a[i...n-1] is a non-increasing suffix.
    // If i is 0, the whole array is non-increasing.

    // Find the rightmost index 'j' such that a[j] > a[j+1]
    // This marks the end of the initial non-decreasing suffix
    int j = i; // Start from 'i' because we only care about elements before the non-increasing suffix
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now, a[j...i-1] is a non-decreasing suffix.
    // If j is 0, then a[0...i-1] is non-decreasing.

