#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    // For m=1, the segment is just [1]. This is always possible.
    // The segment is p[pos[1]...pos[1]]. Length is 1. Min is 1, Max is 1.
    // So 1 is always beautiful.
    result[0] = '1';

    // min_idx and max_idx will track the minimum and maximum indices
    // encountered for numbers 1 to current_m.
    // Initially, for m=1, the range is just pos[1].
    int min_idx = pos[1];
    int max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Update min_idx and max_idx to include the position of 'm'
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // If the current segment [min_idx, max_idx] contains all numbers
        // from 1 to m, and its length is exactly m, then m is beautiful.
        // The length of the segment is (max_idx - min_idx + 1).
        if ((max_idx - min_idx + 1) == m) {
            result[m - 1] = '1';
        }
    }

    std::cout << result << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, int> counts;
    for (char c : s) {
        counts[c]++;
    }

    int horizontal_moves = std::min(counts['L'], counts['R']);
    int vertical_moves = std::min(counts['U'], counts['D']);

    std::string result = "";

    if (horizontal_moves == 0 && vertical_moves == 0) {
        // No moves possible
        std::cout << 0 << std::endl;
        std::cout << std::endl;
        return;
    }

    if (horizontal_moves == 0) {
        // Only vertical moves possible, must be U and D.
        // To form a valid path, we need at least one U and one D.
        // If vertical_moves > 0, it means we have at least one U and one D.
        // The path would be U...UD...D.
        // But the problem states "no cell (except (0,0)) is visited twice".
        // If we only have U and D, the path is (0,0) -> (0,1) -> ... -> (0,k) -> ... -> (0,1) -> (0,0).
        // This means (0,1) is visited twice if k > 1.
        // The only valid path with only U and D is "UD" or "DU".
        // So, if horizontal_moves is 0, we can only use "UD" if vertical_moves >= 1.
        // If vertical_moves is 0, we can only use "LR" if horizontal_moves >= 1.
        // If both are 0, we already handled it.
        // If horizontal_moves is 0, we can only use "UD" if vertical_moves >= 1.
        // If vertical_moves is 0, we can only use "LR" if horizontal_moves >= 1.
        // This logic is wrong. The problem states "UD" is valid.
        // "UUDD" is invalid because (0,1) is visited twice.
        // This implies that if we only have vertical moves, we can only use one 'U' and one 'D'.
        // Similarly for horizontal moves.
        // So if horizontal_moves == 0, we can only use "UD" if vertical_moves >= 1.
        // If vertical_moves == 0, we can only use "LR" if horizontal_moves >= 1.
        // This means if horizontal_moves is 0, we can use at most 2 moves: "UD" or "DU".
        // If vertical_moves is 0, we can use at most 2 moves: "LR" or "RL".

        // Corrected logic:
        // If horizontal_moves is 0, we can't move left/right.
        // If vertical_moves is 0, we can't move up/down.
        // If both are 0, length is 0.
        // If horizontal_moves is 0, we can only use vertical moves.
        // To return to (0,0) and not revisit cells (except (0,0)), we can only use one 'U' and one 'D'.
        // So, if vertical_moves > 0, we can form "UD" (length 2).
        // If vertical_moves == 0, we can't form "UD".
        // Similarly for horizontal_moves.

        if (vertical_moves > 0) { // horizontal_moves is 0
            result = "UD";
        } else { // both horizontal_moves and vertical_moves are 0
            result = "";
        }
    } else if (vertical_moves == 0) { // horizontal_moves > 0
        if (horizontal_moves > 0) {
            result = "LR";
        } else { // both horizontal_moves and vertical_moves are 0
            result = "";
        }
    } else { // Both horizontal_moves > 0 and vertical_moves > 0
        // We can form a path like U...UR...RD...DL...L
        // Example: UURRDDLL
        // This path is valid because it forms a rectangle.
        // The path is (0,0) -> (0,1) -> ... -> (0,V) -> (1,V) -> ... -> (H,V) -> (H,V-1) -> ... -> (H,0) -> (H-1,0) -> ... -> (0,0)
        // No intermediate cell is visited twice.
        // The length will be 2 * horizontal_moves + 2 * vertical_moves.
        for (int i = 0; i < vertical_moves; ++i) result += 'U';
        for (int i = 0; i < horizontal_moves; ++i) result += 'R';
        for (int i = 0; i < vertical_moves; ++i) result += 'D';
        for (int i = 0; i < horizontal_moves; ++i) result += 'L';
    }

    std::cout << result.length() << std::endl;
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int last_diff_type = 0; // 0: no active diff, 1: active 0->1, -1: active 1->0

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0') { // a[i] is '0', b[i] is '1'. Needs to become '1'.
                if (last_diff_type == -1) { // Previous was 1->0, current is 0->1. Can swap.
                    cost++; // Cost of 1 for the swap
                    last_diff_type = 0; // Both resolved
                } else { // No active 1->0, or active 0->1. Start/continue 0->1.
                    last_diff_type = 1;
                }
            } else { // a[i] is '1', b[i] is '0'. Needs to become '0'.
                if (last_diff_type == 1) { // Previous was 0->1, current is 1->0. Can swap.
                    cost++; // Cost of 1 for the swap
                    last_diff_type = 0; // Both resolved
                } else { // No active 0->1, or active 1->0. Start/continue 1->0.
                    last_diff_type = -1;
                }
            }
        } else { // a[i] == b[i]
            if (last_diff_type != 0) { // An active mismatch was not resolved by a swap. Must flip.
                cost++; // Cost of 1 for the flip
                last_diff_type = 0; // Resolved
            }
        }
    }

    // After loop, if there's any remaining active mismatch, it must be flipped.
    if (last_diff_type != 0) {
        cost++;
    }

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks to minimize the absolute difference between medians.
        // With 2n students, if we sort all students' skill levels,
        // the optimal strategy is to assign the first n students to one class
        // and the remaining n students to the other class.
        // This is because the median of a class of size 2k+1 is the (k+1)-th element.
        // If we have 2n students in total, and we want to split them into two classes
        // of odd sizes S1 and S2 such that S1 + S2 = 2n.
        // The smallest possible odd size for a class is 1.
        // The largest possible odd size for a class is 2n-1.
        //
        // Consider the sorted array a[0], a[1], ..., a[2n-1].
        // If we pick the first n elements for one class and the last n elements for the other,
        // this is not necessarily valid because n might be even.
        //
        // However, the problem statement implies that the median of a class of size 2k+1
        // is the (k+1)-th element.
        //
        // Let's re-read the problem carefully: "each class has odd number of students".
        // The total number of students is 2n.
        //
        // The key insight for this type of problem is often that the medians will be
        // adjacent elements in the globally sorted array.
        //
        // If we sort all 2n skill levels: a[0], a[1], ..., a[2n-1].
        //
        // Consider the case where n=1. Total students = 2.
        // Each class must have an odd number of students.
        // The only possible partition is Class 1 has 1 student, Class 2 has 1 student.
        // Medians are a[0] and a[1]. Difference is |a[1] - a[0]|.
        //
        // Consider the case where n=3. Total students = 6.
        // Possible odd sizes: (1, 5) or (3, 3) or (5, 1).
        //
        // The problem asks for the minimum possible absolute difference.
        //
        // The crucial observation is that to minimize the difference between two medians,
        // these medians should be as close as possible in the overall sorted list.
        //
        // If we sort the entire array `a`, the median of any subset of `a` will be one of the elements in `a`.
        //
        // Let the two classes be C1 and C2.
        // Let their sizes be $S_1 = 2k_1+1$ and $S_2 = 2k_2+1$.
        // $S_1 + S_2 = 2n$.
        //
        // The median of C1 will be some $a_i$ and the median of C2 will be some $a_j$.
        // We want to minimize $|a_i - a_j|$.
        //
        // The smallest possible difference is achieved when $a_i$ and $a_j$ are adjacent in the sorted array.
        //
        // Consider the elements $a_{n-1}$ and $a_n$ in the sorted array.
        // These are the two "middle" elements of the entire $2n$ students.
        //
        // Can we always form two classes of odd sizes such that $a_{n-1}$ is the median of one class
        // and $a_n$ is the median of the other class?
        //
        // If we make $a_{n-1}$ the median of Class 1, we need $k_1$ elements smaller than or equal to $a_{n-1}$
        // and $k_1$ elements larger than or equal to $a_{n-1}$ within Class 1.
        //
        // If we make $a_n$ the median of Class 2, we need $k_2$ elements smaller than or equal to $a_n$
        // and $k_2$ elements larger than or equal to $a_n$ within Class 2.
        //
        // The elements $a_0, \dots, a_{n-1}$ are $n$ elements.
        // The elements $a_n, \dots, a_{2n-1}$ are $n$ elements.
        //
        // If we assign $a_0, \dots, a_{n-1}$ to Class 1 and $a_n, \dots, a_{2n-1}$ to Class 2,
        // then each class has $n$ students.
        // If $n$ is odd, then this is a valid partition.
        // In this case, the median of Class 1 (elements $a_0, \dots, a_{n-1}$) would be $a_{(n-1)/2}$.
        // The median of Class 2 (elements $a_n, \dots, a_{2n-1}$) would be $a_{n + (n-1)/2}$.
        // This is not $a_{n-1}$ and $a_n$.
        //
        // The problem is simpler than trying to construct the classes.
        // The median of a set of $2k+1$ elements is the $(k+1)$-th element.
        //
        // Consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        // The $n$-th element is $a_{n-1}$. The $(n+1)$-th element is $a_n$.
        //
        // We can always form a class with $a_{n-1}$ as its median and another class with $a_n$ as its median.
        //
        // For example, take Class 1 to be $\{a_0, a_1, \dots, a_{n-1}\}$ and Class 2 to be $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // Each class has $n$ students.
        // If $n$ is odd, this is a valid partition.
        // The median of Class 1 is $a_{(n-1)/2}$.
        // The median of Class 2 is $a_{n + (n-1)/2}$.
        // The difference is $|a_{n + (n-1)/2} - a_{(n-1)/2}|$. This is not necessarily $a_n - a_{n-1}$.
        //
        // The problem statement is a bit tricky. It says "each class has odd number of students".
        // It does NOT say that the two classes must have the same number of students.
        //
        // Let's consider the example: n=3, 2n=6. Skills: 1 2 3 4 5 6.
        // Sorted: [1, 2, 3, 4, 5, 6].
        // $a_{n-1} = a_2 = 3$. $a_n = a_3 = 4$.
        // The example output is 1. This is $|4-3|$.
        //
        // How can we achieve this?
        // Class 1: [6, 4, 2]. Sorted: [2, 4, 6]. Median is 4. (k=1, 2k+1=3, (k+1)-th is 2nd)
        // Class 2: [5, 1, 3]. Sorted: [1, 3, 5]. Median is 3. (k=1, 2k+1=3, (k+1)-th is 2nd)
        // Difference: |4-3| = 1.
        //
        // Notice that in this example, the medians are $a_2=3$ and $a_3=4$ from the globally sorted array.
        //
        // This suggests that the minimum difference is always $a_n - a_{n-1}$.
        //
        // Let's prove this.
        // We want to find two sets $C_1, C_2$ such that $C_1 \cup C_2 = \{a_0, \dots, a_{2n-1}\}$, $C_1 \cap C_2 = \emptyset$.
        // $|C_1| = 2k_1+1$, $|C_2| = 2k_2+1$.
        // Let $m_1 = \text{median}(C_1)$ and $m_2 = \text{median}(C_2)$.
        // We want to minimize $|m_1 - m_2|$.
        //
        // Let $m_1$ be the $(k_1+1)$-th element of $C_1$ and $m_2$ be the $(k_2+1)$-th element of $C_2$.
        //
        // Consider the elements $a_{n-1}$ and $a_n$.
        // We can construct Class 1 with $a_{n-1}$ as its median and Class 2 with $a_n$ as its median.
        //
        // Class 1: Take $a_{n-1}$. We need $k_1$ elements smaller than or equal to $a_{n-1}$ and $k_1$ elements larger than or equal to $a_{n-1}$.
        // We can take $k_1$ elements from $a_0, \dots, a_{n-2}$ (there are $n-1$ such elements).
        // We can take $k_1$ elements from $a_n, \dots, a_{2n-1}$ (there are $n$ such elements).
        //
        // Let's try to make $a_{n-1}$ and $a_n$ the medians.
        //
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        // Each class has $n$ elements.
        // If $n$ is odd, this is a valid partition.
        // Median of Class 1 is $a_{(n-1)/2}$. Median of Class 2 is $a_{n + (n-1)/2}$.
        // The difference is $a_{n + (n-1)/2} - a_{(n-1)/2}$.
        // This is not $a_n - a_{n-1}$ unless $n=1$.
        // For $n=1$, $a_0, a_1$. Medians are $a_0, a_1$. Diff $a_1-a_0$.
        // For $n=3$, $a_0, a_1, a_2$ and $a_3, a_4, a_5$. Medians are $a_1$ and $a_4$. Diff $a_4-a_1$.
        // But the example output for $n=3$ is $a_3-a_2$.
        //
        // This means the partition in the example is not simply splitting the sorted array into two halves.
        //
        // The problem is that we need to select students for each class.
        //
        // Let $m_1$ and $m_2$ be the medians.
        // Suppose $m_1 < m_2$.
        // For $m_1$ to be the median of $C_1$ (size $2k_1+1$), there must be at least $k_1$ elements in $C_1$ that are $\le m_1$
        // and at least $k_1$ elements in $C_1$ that are $\ge m_1$.
        // More precisely, if $m_1$ is the $(k_1+1)$-th element, then there are $k_1$ elements $\le m_1$ and $k_1$ elements $\ge m_1$.
        //
        // Similarly for $m_2$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        //
        // Let's try to construct the classes for $a_n - a_{n-1}$.
        // We want $a_{n-1}$ to be the median of one class, and $a_n$ to be the median of the other.
        //
        // Class 1 (median $a_{n-1}$):
        // We need $k_1$ elements $\le a_{n-1}$ and $k_1$ elements $\ge a_{n-1}$.
        // We can pick $a_{n-1}$ itself.
        // We can pick $k_1$ elements from $a_0, \dots, a_{n-2}$.
        // We can pick $k_1$ elements from $a_n, \dots, a_{2n-1}$.
        //
        // Class 2 (median $a_n$):
        // We need $k_2$ elements $\le a_n$ and $k_2$ elements $\ge a_n$.
        // We can pick $a_n$ itself.
        // We can pick $k_2$ elements from $a_0, \dots, a_{n-1}$.
        // We can pick $k_2$ elements from $a_{n+1}, \dots, a_{2n-1}$.
        //
        // The total number of students is $2n$.
        //
        // Consider the partition where Class 1 consists of $a_0, \dots, a_{n-1}$ and Class 2 consists of $a_n, \dots, a_{2n-1}$.
        // Each class has $n$ students.
        // If $n$ is odd, this is a valid partition.
        // The median of Class 1 is $a_{(n-1)/2}$.
        // The median of Class 2 is $a_{n + (n-1)/2}$.
        // The difference is $a_{n + (n-1)/2} - a_{(n-1)/2}$.
        //
        // What if $n$ is even?
        // For example, $n=2$, $2n=4$. Students $a_0, a_1, a_2, a_3$.
        // $a_{n-1} = a_1$. $a_n = a_2$.
        // The only possible odd sizes are (1, 3) or (3, 1).
        //
        // If Class 1 has 1 student, Class 2 has 3 students.
        // Class 1: $\{a_i\}$. Median is $a_i$.
        // Class 2: $\{a_j, a_k, a_l\}$. Median is $a_k$ (middle element).
        //
        // Let's try to make $a_1$ and $a_2$ the medians.
        // Can we make $a_1$ the median of a class of size 1? Yes, just $\{a_1\}$.
        // Then the remaining students are $\{a_0, a_2, a_3\}$.
        // Sorted: $[a_0, a_2, a_3]$. Median is $a_2$.
        // So, Class 1: $\{a_1\}$, median $a_1$.
        // Class 2: $\{a_0, a_2, a_3\}$, median $a_2$.
        // Difference: $|a_2 - a_1|$.
        // This works for $n=2$.
        //
        // This strategy seems to work for all $n$.
        // We can always form a class $C_1$ with $a_{n-1}$ as its median and a class $C_2$ with $a_n$ as its median.
        //
        // To make $a_{n-1}$ the median of $C_1$:
        // We need $C_1$ to have $2k_1+1$ elements.
        // We can choose $C_1 = \{a_{n-1}\}$. Then $k_1=0$. This is a valid class of size 1.
        // The remaining $2n-1$ students form $C_2$.
        // $2n-1$ is always odd. So $C_2$ is a valid class.
        // The median of $C_2$ would be the $((2n-1-1)/2 + 1)$-th element, i.e., the $n$-th element of $C_2$.
        // The elements in $C_2$ are $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$.
        // If we sort these $2n-1$ elements, the $n$-th element will be $a_n$.
        // (Because there are $n-1$ elements smaller than $a_n$ in $C_2$, namely $a_0, \dots, a_{n-2}$,
        // and $n-1$ elements larger than $a_n$ in $C_2$, namely $a_{n+1}, \dots, a_{2n-1}$).
        //
        // So, one possible partition is:
        // Class 1: $\{a_{n-1}\}$ (median $a_{n-1}$)
        // Class 2: $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$ (median $a_n$)
        // The absolute difference is $|a_n - a_{n-1}|$.
        //
        // Can we achieve a smaller difference?
        // Suppose we have two medians $m_1$ and $m_2$.
        // Let $m_1 = a_i$ and $m_2 = a_j$ for some $i, j$.
        // Without loss of generality, assume $i < j$.
        //
        // For $a_i$ to be the median of $C_1$ (size $2k_1+1$), there must be at least $k_1$ elements in $C_1$ that are $\le a_i$
        // and at least $k_1$ elements in $C_1$ that are $\ge a_i$.
        // This means $C_1$ must contain $a_i$, $k_1$ elements from $\{a_0, \dots, a_{i-1}\}$ and $k_1$ elements from $\{a_{i+1}, \dots, a_{2n-1}\}$.
        //
        // For $a_j$ to be the median of $C_2$ (size $2k_2+1$), there must be at least $k_2$ elements in $C_2$ that are $\le a_j$
        // and at least $k_2$ elements in $C_2$ that are $\ge a_j$.
        // This means $C_2$ must contain $a_j$, $k_2$ elements from $\{a_0, \dots, a_{j-1}\}$ and $k_2$ elements from $\{a_{j+1}, \dots, a_{2n-1}\}$.
        //
        // The total number of elements is $2n$.
        // The total number of elements less than $a_i$ is $i$.
        // The total number of elements greater than $a_j$ is $2n-1-j$.
        //
        // The number of elements in $C_1$ that are $\le a_i$ is $k_1+1$.
        // The number of elements in $C_2$ that are $\le a_j$ is $k_2+1$.
        //
        // The total number of elements $\le a_i$ is $i+1$.
        // The total number of elements $\ge a_j$ is $2n-j$.
        //
        // The elements $a_0, \dots, a_i$ must contain $k_1+1$ elements from $C_1$.
        // The elements $a_j, \dots, a_{2n-1}$ must contain $k_2+1$ elements from $C_2$.
        //
        // The total number of elements in $C_1$ that are $\le a_i$ is $k_1+1$.
        // The total number of elements in $C_2$ that are $\le a_j$ is $k_2+1$.
        //
        // Sum of elements $\le a_i$ in $C_1$ and $\le a_j$ in $C_2$:
        // $(k_1+1) + (k_2+1) = k_1+k_2+2$.
        //
        // The total number of elements in the entire set that are $\le a_i$ is $i+1$.
        // The total number of elements in the entire set that are $\le a_j$ is $j+1$.
        //
        // The number of elements in $C_1$ that are $\ge a_i$ is $k_1+1$.
        // The number of elements in $C_2$ that are $\ge a_j$ is $k_2+1$.
        //
        // The total number of elements in the entire set that are $\ge a_i$ is $2n-i$.
        // The total number of elements in the entire set that are $\ge a_j$ is $2n-j$.
        //
        // Consider the elements $a_0, \dots, a_{i-1}$. These are $i$ elements.
        // They must be distributed between $C_1$ and $C_2$.
        // $C_1$ needs $k_1$ elements from this range (or smaller).
        // $C_2$ needs $k_2$ elements from this range (or smaller).
        //
        // The total number of elements in $C_1$ that are $\le a_i$ is $k_1+1$.
        // The total number of elements in $C_2$ that are $\ge a_j$ is $k_2+1$.
        //
        // The elements $a_0, \dots, a_{i-1}$ are $i$ elements.
        // The elements $a_{j+1}, \dots, a_{2n-1}$ are $2n-1-j$ elements.
        //
        // The elements $a_i, \dots, a_j$ are $j-i+1$ elements.
        //
        // The total number of elements in $C_1$ that are $\le a_i$ is $k_1+1$.
        // The total number of elements in $C_2$ that are $\ge a_j$ is $k_2+1$.
        //
        // The sum of elements in $C_1$ that are $\le a_i$ and elements in $C_2$ that are $\ge a_j$ is $(k_1+1) + (k_2+1) = k_1+k_2+2$.
        //
        // The total number of elements in the entire set that are $\le a_i$ is $i+1$.
        // The total number of elements in the entire set that are $\ge a_j$ is $2n-j$.
        //
        // The elements $a_0, \dots, a_{i-1}$ are $i$ elements.
        // The elements $a_{j+1}, \dots, a_{2n-1}$ are $2n-1-j$ elements.
        //
        // The elements $a_i, \dots, a_j$ are $j-i+1$ elements.
        //
        // The number of elements in $C_1$ that are $\le a_i$ is $k_1+1$.
        // The number of elements in $C_2$ that are $\ge a_j$ is $k_2+1$.
        //
        // The total number of elements in $C_1$ is $2k_1+1$.
        // The total number of elements in $C_2$ is $2k_2+1$.
        //
        // $2k_1+1 + 2k_2+1 = 2n \implies 2(k_1+k_2+1) = 2n \implies k_1+k_2+1 = n$.
        //
        // So $k_1+k_2 = n-1$.
        //
        // The number of elements in $C_1$ that are $\le a_i$ is $k_1+1$.
        // The number of elements in $C_2$ that are $\ge a_j$ is $k_2+1$.
        //
        // These two sets of elements must be disjoint.
        // The elements $\le a_i$ in $C_1$ are $k_1+1$ elements.
        // The elements $\ge a_j$ in $C_2$ are $k_2+1$ elements.
        //
        // The total number of elements in the entire array that are $\le a_i$ is $i+1$.
        // The total number of elements in the entire array that are $\ge a_j$ is $2n-j$.
        //
        // The elements $a_0, \dots, a_{i-1}$ are $i$ elements.
        // The elements $a_{j+1}, \dots, a_{2n-1}$ are $2n-1-j$ elements.
        //
        // $C_1$ must contain $a_i$ and $k_1$ elements from $a_0, \dots, a_{i-1}$ and $k_1$ elements from $a_{i+1}, \dots, a_{2n-1}$.
        // $C_2$ must contain $a_j$ and $k_2$ elements from $a_0, \dots, a_{j-1}$ and $k_2$ elements from $a_{j+1}, \dots, a_{2n-1}$.
        //
        // The elements $a_0, \dots, a_{i-1}$ are $i$ elements.
        // The elements $a_{j+1}, \dots, a_{2n-1}$ are $2n-1-j$ elements.
        //
        // The total number of elements available for $C_1$ to pick from $a_0, \dots, a_{i-1}$ is $i$.
        // The total number of elements available for $C_2$ to pick from $a_{j+1}, \dots, a_{2n-1}$ is $2n-1-j$.
        //
        // So, $k_1 \le i$ and $k_2 \le 2n-1-j$.
        //
        // Summing these inequalities: $k_1+k_2 \le i + (2n-1-j)$.
        // We know $k_1+k_2 = n-1$.
        // So, $n-1 \le i + 2n-1-j$.
        // $n-1 \le i - j + 2n-1$.
        // $0 \le i - j + n$.
        // $j - i \le n$.
        //
        // This means the difference in indices $j-i$ can be at most $n$.
        //
        // This doesn't directly prove $j-i \ge 1$.
        //
        // Let's use a simpler argument.
        // Let $m_1$ and $m_2$ be the medians. Assume $m_1 \le m_2$.
        // $m_1$ is the $(k_1+1)$-th element of $C_1$. This means there are $k_1$ elements in $C_1$ that are $\le m_1$ (excluding $m_1$ itself)
        // and $k_1$ elements in $C_1$ that are $\ge m_1$ (excluding $m_1$ itself).
        //
        // $m_2$ is the $(k_2+1)$-th element of $C_2$. This means there are $k_2$ elements in $C_2$ that are $\le m_2$ (excluding $m_2$ itself)
        // and $k_2$ elements in $C_2$ that are $\ge m_2$ (excluding $m_2$ itself).
        //
        // Total elements $2n$. $k_1+k_2 = n-1$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$. There are $n$ such elements.
        // Consider the elements $a_n, \dots, a_{2n-1}$. There are $n$ such elements.
        //
        // The median $m_1$ must be one of $a_0, \dots, a_{2n-1}$.
        // The median $m_2$ must be one of $a_0, \dots, a_{2n-1}$.
        //
        // The number of elements in $C_1$ that are $\le m_1$ is $k_1+1$.
        // The number of elements in $C_2$ that are $\le m_2$ is $k_2+1$.
        //
        // Since $m_1 \le m_2$, all $k_1+1$ elements of $C_1$ that are $\le m_1$ are also $\le m_2$.
        //
        // The total number of elements $\le m_2$ in the entire set is at least $(k_1+1) + (k_2+1) = n+1$.
        // This means $m_2$ must be at least $a_n$. (Because $a_n$ is the $(n+1)$-th element in the sorted array).
        // So $m_2 \ge a_n$.
        //
        // Similarly, the number of elements in $C_1$ that are $\ge m_1$ is $k_1+1$.
        // The number of elements in $C_2$ that are $\ge m_2$ is $k_2+1$.
        //
        // Since $m_1 \le m_2$, all $k_2+1$ elements of $C_2$ that are $\ge m_2$ are also $\ge m_1$.
        //
        // The total number of elements $\ge m_1$ in the entire set is at least $(k_1+1) + (k_2+1) = n+1$.
        // This means $m_1$ must be at most $a_{2n-(n+1)} = a_{n-1}$. (Because $a_{n-1}$ is the $n$-th element from the start, or $(n+1)$-th element from the end).
        // So $m_1 \le a_{n-1}$.
        //
        // Combining these, we have $m_1 \le a_{n-1}$ and $m_2 \ge a_n$.
        // Since $m_1 \le m_2$, we have $m_2 - m_1 \ge a_n - a_{n-1}$.
        //
        // We have already shown a construction that achieves $a_n - a_{n-1}$.
        // Class 1: $\{a_{n-1}\}$ (median $a_{n-1}$)
        // Class 2: $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$ (median $a_n$)
        // Both classes have odd sizes (1 and $2n-1$).
        //
        // Therefore, the minimum possible absolute difference is $a_n - a_{n-1}$.

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
