struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    std::sort(a_elements.begin(), a_elements.end(), compareElements);
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    std::vector<long long> result_a(m);
    for (int i = 0; i < m; ++i) {
        result_a[b_elements[i].original_index] = a_elements[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long d;
    std::cin >> n >> d;
    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point that satisfies x[right_ptr] - x[i] <= d

    for (int i = 0; i < n; ++i) {
        // Advance right_ptr until x[right_ptr] - x[i] > d or right_ptr reaches end
        // The condition is x[right_ptr] <= x[i] + d
        while (right_ptr < n && x[right_ptr] <= x[i] + d) {
            right_ptr++;
        }
        // At this point, all points from x[i+1] to x[right_ptr-1] satisfy the condition with x[i]
        // We need to choose two more points (j, k) such that i < j < k <= right_ptr - 1.
        // The number of available points for j and k is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let m = right_ptr - 1 - i. These are the points x[i+1], ..., x[right_ptr-1].
        // We need to choose 2 points from these m points.
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        long long m = right_ptr - 1 - i;
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> is_suffix_perm(n + 1, false);

    // Check prefixes
    std::vector<bool> seen_prefix(n + 1, false);
    int max_val_prefix = 0;
    int distinct_count_prefix = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] > n || seen_prefix[a[i]]) { // a[i] > n is an optimization, max possible value is n-1
            break;
        }
        seen_prefix[a[i]] = true;
        distinct_count_prefix++;
        max_val_prefix = std::max(max_val_prefix, a[i]);
        if (distinct_count_prefix == i + 1 && max_val_prefix == i + 1) {
            is_prefix_perm[i + 1] = true;
        }
    }

    // Check suffixes
    std::vector<bool> seen_suffix(n + 1, false);
    int max_val_suffix = 0;
    int distinct_count_suffix = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || seen_suffix[a[i]]) { // a[i] > n is an optimization, max possible value is n-1
            break;
        }
        seen_suffix[a[i]] = true;
        distinct_count_suffix++;
        max_val_suffix = std::max(max_val_suffix, a[i]);
        if (distinct_count_suffix == n - i && max_val_suffix == n - i) {
            is_suffix_perm[n - i] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, l2 must be at least 1
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

