#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int calculate_score(const std::string& s) {
    int current_score = 0;
    if (s.empty()) {
        return 0;
    }
    if (s[0] == 'W') {
        current_score += 1;
    }
    for (size_t i = 1; i < s.length(); ++i) {
        if (s[i] == 'W') {
            if (s[i - 1] == 'W') {
                current_score += 2;
            } else {
                current_score += 1;
            }
        }
    }
    return current_score;
}

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    int initial_wins = 0;
    for (char c : s) {
        if (c == 'W') {
            initial_wins++;
        }
    }

    if (initial_wins + k >= n) { // Can make all games 'W'
        std::cout << calculate_score(std::string(n, 'W')) << std::endl;
        return;
    }

    // Strategy:
    // 1. Convert 'L's to 'W's to maximize consecutive 'W's.
    // 2. Prioritize filling gaps between existing 'W's.
    // 3. Then fill 'L's at the ends.
    // 4. Then fill any remaining 'L's.

    std::vector<int> gaps;
    int first_W = -1, last_W = -1;

    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            if (first_W == -1) {
                first_W = i;
            }
            last_W = i;
        }
    }

    if (first_W == -1) { // No 'W's initially
        if (k == 0) {
            std::cout << 0 << std::endl;
        } else {
            // Change k 'L's to 'W's. Best to make them consecutive.
            // e.g., LLLLL, k=2 -> WWLLL. Score 1+2 = 3.
            // Score for k consecutive W's: 1 + (k-1)*2 = 2k-1
            std::cout << 2 * k - 1 << std::endl;
        }
        return;
    }

    // Collect gaps between 'W's
    int current_gap_len = 0;
    for (int i = first_W + 1; i <= last_W; ++i) {
        if (s[i] == 'L') {
            current_gap_len++;
        } else { // s[i] == 'W'
            if (current_gap_len > 0) {
                gaps.push_back(current_gap_len);
            }
            current_gap_len = 0;
        }
    }
    std::sort(gaps.begin(), gaps.end());

    // Fill internal gaps first
    for (int gap_len : gaps) {
        if (k >= gap_len) {
            k -= gap_len;
            // All 'L's in this gap become 'W's.
            // This converts a W...L...W to W...W...W.
            // The 'W's on either side were giving 1 point each (if previous was L)
            // or 2 points (if previous was W).
            // After filling, the 'W's in the gap give 2 points each.
            // The 'W' after the gap now gets 2 points instead of 1.
            // The 'W' before the gap was already giving 2 points if it was part of a chain.
            // The score calculation will handle this.
        } else {
            break; // Cannot fill this gap or larger ones
        }
    }

    // Create a modified string to calculate score
    std::string temp_s = s;
    int changes_made = 0;

    // Fill internal gaps
    for (int gap_len : gaps) {
        if (k == 0) break;
        if (gap_len <= k) {
            int current_idx = -1;
            for (int i = first_W + 1; i <= last_W; ++i) {
                if (temp_s[i] == 'L') {
                    current_idx = i;
                    int temp_gap_len = 0;
                    while (current_idx < n && temp_s[current_idx] == 'L') {
                        temp_gap_len++;
                        current_idx++;
                    }
                    if (temp_gap_len == gap_len) {
                        for (int j = i; j < i + gap_len; ++j) {
                            temp_s[j] = 'W';
                            changes_made++;
                        }
                        k -= gap_len;
                        break; // Move to next gap_len
                    }
                    i = current_idx - 1; // Continue search from after this gap
                }
            }
        }
    }

    // Fill 'L's at the ends
    // Fill from right to left (to make last_W get 2 points)
    for (int i = n - 1; i > last_W && k > 0; --i) {
        if (temp_s[i] == 'L') {
            temp_s[i] = 'W';
            k--;
            changes_made++;
        }
    }
    // Fill from left to right (to make first_W get 1 point, and subsequent get 2)
    for (int i = 0; i < first_W && k > 0; ++i) {
        if (temp_s[i] == 'L') {
            temp_s[i] = 'W';
            k--;
            changes_made++;
        }
    }

    std::cout << calculate_score(temp_s) << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;
    int a_ptr_left = 0;
    int a_ptr_right = n - 1;

    // First, handle friends who receive w_i = 1.
    // These friends should get the largest available numbers, as their happiness is 2 * number.
    // Since w is sorted, these are the friends with the smallest w_i values.
    // They should get the largest numbers from 'a'.
    for (int i = 0; i < k; ++i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_right];
            a_ptr_right--;
        }
    }

    // Now, handle friends who receive w_i > 1.
    // These friends need a max and a min.
    // To maximize the sum of happiness, we should give the remaining largest numbers as max_val
    // and the smallest available numbers as min_val.
    // The friends with larger w_i values (who need more numbers) should get their max_val from the remaining largest numbers.
    // The friends with smaller w_i values (who need fewer numbers, but still > 1) should get their max_val from the remaining largest numbers.
    // The friends with larger w_i values (who need more numbers) should get their min_val from the smallest available numbers.
    // The friends with smaller w_i values (who need fewer numbers, but still > 1) should get their min_val from the smallest available numbers.

    // Iterate through w in reverse order (from largest w_i to smallest w_i > 1).
    // These friends will take their max_val from a_ptr_right.
    // They will take their min_val from a_ptr_left.
    // The remaining w_i - 2 elements are taken from a_ptr_left, moving it forward.
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] > 1) {
            total_happiness += a[a_ptr_right]; // Max value for this friend
            a_ptr_right--;

            // This friend needs w[i] numbers.
            // One is a_ptr_right (max).
            // One will be a_ptr_left (min).
            // The remaining w[i] - 2 numbers are also taken from the left side.
            // So, a_ptr_left moves forward by w[i] - 1 positions in total.
            total_happiness += a[a_ptr_left]; // Min value for this friend
            a_ptr_left += (w[i] - 1);
        }
    }

    std::cout << total_happiness << std::endl;
}

