#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 == 1) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is better for Chanek
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 == 1 && n != 4) { // If N/2 is odd, taking N/2 leaves an odd number for opponent
                                                        // and opponent will take 1. This is good for Chanek.
                                                        // Exception: N=4. N/2=2. Opponent takes 1. Chanek takes 1.
                                                        // If Chanek takes N/2=2, N=2. Opponent takes 1. Chanek takes 1.
                                                        // Chanek gets 2.
                                                        // If Chanek takes 1, N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                                                        // Chanek gets 1+1=2.
                                                        // For N=4, both options give Chanek 2.
                                                        // The logic (n/2)%2==1 is for when taking N/2 is better.
                                                        // If N/2 is odd, opponent takes 1.
                                                        // If N/2 is even, opponent might take N/4.
                                                        // The optimal strategy for Chanek when N is even is to take N/2 if N/2 is odd,
                                                        // or if N/2 is even, take 1.
                                                        // This is equivalent to: if N is a power of 2, take 1. Otherwise, take N/2.
                                                        // The only power of 2 that is not handled by (n/2)%2==1 is when n is a power of 2.
                                                        // If n is a power of 2, n/2 is also a power of 2 (unless n=2).
                                                        // If n is a power of 2 (and n > 2), then n/2 is even.
                                                        // So (n/2)%2==1 is false.
                                                        // So if n is a power of 2 (and n > 2), Chanek takes 1.
                                                        // If n is not a power of 2, then n/2 might be odd or even.
                                                        // If n/2 is odd, Chanek takes n/2.
                                                        // If n/2 is even, Chanek takes 1.
                                                        // This is the same as: if n is a power of 2, take 1. Else take n/2.
                                                        // The only exception is N=2, where taking 1 is better.
                                                        // For N=4, Chanek takes 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek gets 2.
                                                        // If Chanek takes N/2=2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek gets 2.
                                                        // So for N=4, taking 1 or N/2 gives same result for Chanek.
                                                        // The condition (n & (n - 1)) == 0 checks if n is a power of 2.
                    if ((n & (n - 1)) == 0) { // N is a power of 2
                        chanek_coins += 1;
                        n -= 1;
                    } else { // N is even but not a power of 2
                        chanek_coins += n / 2;
                        n /= 2;
                    }
                } else { // N is even, N/2 is even, or N=4
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 == 1) { // N is odd
                n -= 1;
            } else { // N is even
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    n -= 1;
                } else { // N is even but not a power of 2
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

