int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int correct_consecutive_pairs = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        if (m == 0) continue; // Should not happen based on constraints (m_i >= 1)

        int prev_doll;
        std::cin >> prev_doll;

        for (int j = 1; j < m; ++j) {
            int current_doll;
            std::cin >> current_doll;
            if (current_doll == prev_doll + 1) {
                correct_consecutive_pairs++;
            }
            prev_doll = current_doll;
        }
    }

    // Total operations needed to achieve the target state (n-1 nestings)
    // is (n-1) "put" operations.
    // We save 2 operations for each correct_consecutive_pair:
    // 1 "get out" operation (to break it) and 1 "put" operation (to re-create it).
    // So, for each correct_consecutive_pair, we save 2 seconds.
    total_operations = (long long)(n - 1) - correct_consecutive_pairs; // Operations to create new nestings
    total_operations += (long long)(n - 1) - correct_consecutive_pairs; // Operations to break existing incorrect nestings

    std::cout << total_operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <cmath>
#include <set>

long long solve() {
    long long p, q;
    std::cin >> p >> q;

    if (p % q != 0) {
        return p;
    }

    // Find prime factors of q
    std::set<long long> q_prime_factors;
    long long temp_q = q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            q_prime_factors.insert(i);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        q_prime_factors.insert(temp_q);
    }

    long long max_x = 1;

    for (long long f : q_prime_factors) {
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= f;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

