#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> L(n), R(n);

    // Calculate L[i]: minimum height required for a block at (i, k) to have a left neighbor
    // This is effectively the maximum number of operations a block at (i, k) can survive
    // if only considering its left side and the floor.
    // L[i] = min(h[i], L[i-1] + 1)
    L[0] = h[0];
    for (int i = 1; i < n; ++i) {
        L[i] = std::min(h[i], L[i - 1] + 1);
    }

    // Calculate R[i]: minimum height required for a block at (i, k) to have a right neighbor
    // This is effectively the maximum number of operations a block at (i, k) can survive
    // if only considering its right side and the floor.
    // R[i] = min(h[i], R[i+1] + 1)
    R[n - 1] = h[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        R[i] = std::min(h[i], R[i + 1] + 1);
    }

    long long max_min_height = 0;
    for (int i = 0; i < n; ++i) {
        max_min_height = std::max(max_min_height, std::min(L[i], R[i]));
    }

    std::cout << max_min_height << std::endl;

    return 0;
}

