#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Operation 1: Make a[0]...a[n-2] divisible by n
    // This operation covers elements from index 0 to n-2 (1 to n-1 in 1-based indexing)
    // Length of segment is n-1.
    // For each a[i], we want to add x_i such that (a[i] + x_i) % n == 0.
    // x_i must be a multiple of (n-1).
    // We can make a[i] % n == 0 for i from 0 to n-2.
    // If n = 1, this segment is empty.
    if (n == 1) {
        // Special handling for n=1 to ensure 3 operations and correct output format
        // Op 1: [1,1], add -a[0]
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        a[0] = 0; // a[0] is now 0

        // Op 2: [1,1], add 0 (multiple of 1)
        std::cout << "1 1\n";
        std::cout << "0\n";

        // Op 3: [1,1], add 0 (multiple of 1)
        std::cout << "1 1\n";
        std::cout << "0\n";
    } else {
        // Operation 1: Target a[0]...a[n-2]
        std::cout << "1 " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long remainder = a[i] % n;
            long long to_add = (n - remainder) % n; // Amount needed to make a[i] divisible by n

            // We need to add a multiple of (n-1).
            // We want a[i] + k*(n-1) to be divisible by n.
            // a[i] + k*(n-1) = 0 (mod n)
            // a[i] - k = 0 (mod n)
            // k = a[i] (mod n)
            // So, k must be a[i] % n.
            // The actual value to add is k * (n-1).
            // If a[i] % n is 0, then k is 0, to_add_val is 0.
            long long k = remainder;
            if (k < 0) k += n; // Ensure k is non-negative

            long long add_val = k * (n - 1);
            std::cout << add_val << (i == n - 2 ? "" : " ");
            a[i] += add_val;
        }
        std::cout << "\n";

        // Operation 2: Target a[n-1]
        // This operation covers only the last element. Segment length is 1.
        std::cout << n << " " << n << "\n";
        long long remainder_last = a[n - 1] % n;
        long long to_add_last = (n - remainder_last) % n;

        // We need to add a multiple of 1.
        // We want a[n-1] + k*1 to be divisible by n.
        // a[n-1] + k = 0 (mod n)
        // k = -a[n-1] (mod n)
        // The actual value to add is k * 1.
        long long k_last = (n - remainder_last) % n;
        long long add_val_last = k_last * 1;
        std::cout << add_val_last << "\n";
        a[n - 1] += add_val_last;

        // At this point, all a[i] are divisible by n.
        // Operation 3: Make all a[i] zero.
        // This operation covers all elements. Segment length is n.
        std::cout << "1 " << n << "\n";
        for (int i = 0; i < n; ++i) {
            // Since a[i] is now a multiple of n, we can add -a[i] to make it 0.
            // -a[i] is a multiple of n, which is the segment length.
            std::cout << -a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // For each bit position (0-9), we track how an input bit 0 and an input bit 1
    // are transformed.
    // state[bit_idx][0] = final value of bit_idx if input bit was 0
    // state[bit_idx][1] = final value of bit_idx if input bit was 1
    // Initialize: identity transformation for all bits
    // If input bit is 0, output bit is 0. If input bit is 1, output bit is 1.
    std::vector<std::vector<int>> state(10, std::vector<int>(2));
    for (int i = 0; i < 10; ++i) {
        state[i][0] = 0; // 0 -> 0
        state[i][1] = 1; // 1 -> 1
    }

    for (int k = 0; k < n; ++k) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int i = 0; i < 10; ++i) {
            int bit_val = (val >> i) & 1; // The i-th bit of the constant 'val'

            if (op_char == '&') {
                state[i][0] &= bit_val;
                state[i][1] &= bit_val;
            } else if (op_char == '|') {
                state[i][0] |= bit_val;
                state[i][1] |= bit_val;
            } else { // op_char == '^'
                state[i][0] ^= bit_val;
                state[i][1] ^= bit_val;
            }
        }
    }

    // Now, we have the final transformation for each bit.
    // We need to find a sequence of at most 5 operations that achieves this.
    // The strategy is to use one OR, one AND, and one XOR operation.
    // OR operation: Sets bits to 1 if they should be 1 regardless of input.
    // AND operation: Sets bits to 0 if they should be 0 regardless of input.
    // XOR operation: Flips bits if they should be flipped relative to input.

    int or_const = 0;
    int and_const = 1023; // All 1s for 10 bits
    int xor_const = 0;

    for (int i = 0; i < 10; ++i) {
        // Case 1: Input bit 0 -> Output bit 0, Input bit 1 -> Output bit 0
        // This means the bit must become 0. Achieved by ANDing with 0.
        if (state[i][0] == 0 && state[i][1] == 0) {
            and_const &= ~(1 << i); // Set i-th bit of and_const to 0
        }
        // Case 2: Input bit 0 -> Output bit 1, Input bit 1 -> Output bit 1
        // This means the bit must become 1. Achieved by ORing with 1.
        else if (state[i][0] == 1 && state[i][1] == 1) {
            or_const |= (1 << i); // Set i-th bit of or_const to 1
        }
        // Case 3: Input bit 0 -> Output bit 0, Input bit 1 -> Output bit 1
        // This is identity. Achieved by XORing with 0.
        else if (state[i][0] == 0 && state[i][1] == 1) {
            // No change needed for or_const, and_const, xor_const for this bit
        }
        // Case 4: Input bit 0 -> Output bit 1, Input bit 1 -> Output bit 0
        // This is negation. Achieved by XORing with 1.
        else if (state[i][0] == 1 && state[i][1] == 0) {
            xor_const |= (1 << i); // Set i-th bit of xor_const to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (or_const != 0) {
        result_ops.push_back({'|', or_const});
    }
    if (and_const != 1023) { // If and_const is not all 1s, it means some bits were forced to 0
        result_ops.push_back({'&', and_const});
    }
    if (xor_const != 0) {
        result_ops.push_back({'^', xor_const});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
