int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;
        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }
        long long total_substrings = n * (n + 1) / 2;
        long long num_zeros = n - m;
        long long k = m + 1; // Number of blocks of zeros (including potential empty blocks at ends)

        long long q = num_zeros / k; // Minimum length of a zero block
        long long r = num_zeros % k; // Number of blocks with length q+1

        // Number of all-zero substrings contributed by blocks of length q+1
        long long substrings_from_q_plus_1 = r * (q + 1) * (q + 2) / 2;
        // Number of all-zero substrings contributed by blocks of length q
        long long substrings_from_q = (k - r) * q * (q + 1) / 2;

        long long all_zero_substrings = substrings_from_q_plus_1 + substrings_from_q;

        long long result = total_substrings - all_zero_substrings;
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // Store balances for prefixes of the left half (jars 0 to n-1)
    // balance_left[k] = balance of jars a[n-1] down to a[n-k]
    // This is equivalent to balance of jars a[0] to a[n-1] MINUS balance of jars a[0] to a[n-k-1]
    // Or, more simply, balance of jars a[n-k] to a[n-1]
    // We are interested in the balance of jars *removed* from the left.
    // If we remove k jars from the left, these are a[n-1], a[n-2], ..., a[n-k].
    // Let's define `left_prefix_balance[k]` as the balance of the first `k` jars from the left (a[0]...a[k-1]).
    // This is not what we need.
    // We need the balance of jars *remaining* on the left.
    // Or, the balance of jars *eaten* from the left.
    // If Karlsson eats `k_L` jars from the left, he eats `a[n-1], a[n-2], ..., a[n-k_L]`.
    // Let `left_eaten_balance[k_L]` be the balance of these `k_L` jars.
    // `left_eaten_balance[0] = 0`
    // `left_eaten_balance[k_L] = left_eaten_balance[k_L-1] + (a[n-k_L] == 1 ? 1 : -1)`
    // This is the balance of jars `a[n-k_L]` through `a[n-1]`.
    std::map<int, int> left_eaten_balances; // balance -> count of jars eaten
    left_eaten_balances[0] = 0; // 0 jars eaten, balance 0

    int current_left_balance = 0;
    for (int k_L = 1; k_L <= n; ++k_L) {
        int jar_idx = n - k_L; // Jar a[n-1] is eaten first, then a[n-2], etc.
        if (a[jar_idx] == 1) {
            current_left_balance++;
        } else {
            current_left_balance--;
        }
        if (left_eaten_balances.find(current_left_balance) == left_eaten_balances.end()) {
            left_eaten_balances[current_left_balance] = k_L;
        }
    }

    // Calculate balances for prefixes of the right half (jars n to 2n-1)
    // If Karlsson eats `k_R` jars from the right, he eats `a[n], a[n+1], ..., a[n+k_R-1]`.
    // Let `right_eaten_balance[k_R]` be the balance of these `k_R` jars.
    // `right_eaten_balance[0] = 0`
    // `right_eaten_balance[k_R] = right_eaten_balance[k_R-1] + (a[n+k_R-1] == 1 ? 1 : -1)`
    // This is the balance of jars `a[n]` through `a[n+k_R-1]`.
    std::map<int, int> right_eaten_balances; // balance -> count of jars eaten
    right_eaten_balances[0] = 0; // 0 jars eaten, balance 0

    int current_right_balance = 0;
    for (int k_R = 1; k_R <= n; ++k_R) {
        int jar_idx = n + k_R - 1; // Jar a[n] is eaten first, then a[n+1], etc.
        if (a[jar_idx] == 1) {
            current_right_balance++;
        } else {
            current_right_balance--;
        }
        if (right_eaten_balances.find(current_right_balance) == right_eaten_balances.end()) {
            right_eaten_balances[current_right_balance] = k_R;
        }
    }

    int min_jars_eaten = 2 * n; // Max possible jars eaten

    // Iterate through all possible balances of jars eaten from the left
    // For each `left_eaten_balance`, we need to find a `right_eaten_balance` such that
    // `initial_balance - left_eaten_balance - right_eaten_balance = 0`
    // which means `left_eaten_balance + right_eaten_balance = initial_balance`.
    // So, `right_eaten_balance = initial_balance - left_eaten_balance`.
    for (auto const& [l_bal, k_L] : left_eaten_balances) {
        int target_r_bal = initial_balance - l_bal;
        if (right_eaten_balances.count(target_r_bal)) {
            int k_R = right_eaten_balances[target_r_bal];
            min_jars_eaten = std::min(min_jars_eaten, k_L + k_R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> removal_order(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> removal_order[i];
        removal_order[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Process in reverse: add vertices one by one
    for (int step = n - 1; step >= 0; --step) {
        int k = removal_order[step]; // The vertex being "added" back

        active_vertices[k] = true;

        // Floyd-Warshall update step
        // Consider k as an intermediate vertex
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // Calculate sum of shortest paths for currently active vertices
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (active_vertices[i]) {
                for (int j = 0; j < n; ++j) {
                    if (active_vertices[j]) {
                        current_sum += dist[i][j];
                    }
                }
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (from first step to last)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
