#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // This child is now cured

        long long current_v_cry = children[i].v;
        long long hall_cry_sum = 0; // Accumulates d_j from children leaving the hall

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply hall_cry_sum first
            children[j].p -= hall_cry_sum;

            // Apply current_v_cry from the child in the office
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            if (children[j].p < 0) {
                children[j].in_line = false;
                hall_cry_sum += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // Convert to 0-based indexing
        ops[i].r--; // Convert to 0-based indexing
    }

    // Initialize b_i to a very large value, representing no upper bound yet.
    // b_i will store the maximum possible initial value for a[i]
    // such that all type 2 constraints are met.
    std::vector<long long> b(n, LLONG_MAX);

    // Process operations in reverse to determine initial upper bounds for b_i
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If we add d to a range [l, r], then to maintain the same
            // relative maximums, the initial values in that range must
            // effectively be d less.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                if (b[j] != LLONG_MAX) { // Only adjust if an upper bound was set
                    b[j] -= ops[i].val;
                }
            }
        } else { // type == 2
            // For a query (l, r, m), the current value of a[j] must be <= m.
            // This means the initial value a_initial[j] must be <= m - (sum of d's applied to j before this query).
            // Since b[j] stores the maximum possible initial value for a[j],
            // we update b[j] = min(b[j], m - (sum of d's applied to j before this query)).
            // In our reverse pass, b[j] already represents the maximum possible initial value
            // considering all *subsequent* operations. So, we just need to apply the current
            // operation's constraint.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val);
            }
        }
    }

    // If any b[j] is still LLONG_MAX, it means no type 2 operation ever constrained it.
    // We can set it to 0, as |a_i| <= 10^9 is allowed.
    // Or, more generally, any value within the allowed range. 0 is simple.
    for (int i = 0; i < n; ++i) {
        if (b[i] == LLONG_MAX) {
            b[i] = 0;
        }
    }

    // Now, b contains the proposed initial array.
    // We need to verify if this array satisfies all constraints.
    std::vector<long long> current_a = b;

    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_a[j] += op.val;
            }
        } else { // type == 2
            long long max_val = LLONG_MIN;
            for (int j = op.l; j <= op.r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

