        // This means h[head_idx] >= p[track_idx] - T
        while (head_idx < n && h[head_idx] < p[track_idx] - T) {
            head_idx++;
        }

        if (head_idx >= n) {
            return false; // No head can cover p[track_idx]
        }

        // Now, h[head_idx] is the first head that can reach p[track_idx] (or is past it)
        // If h[head_idx] is too far to the right, it cannot cover p[track_idx]
        // i.e., if h[head_idx] > p[track_idx] + T
        if (h[head_idx] > p[track_idx] + T) {
            return false; // The current head is too far right, and all subsequent heads are even further right
        }

        // This head h[head_idx] can cover p[track_idx].
        // Let's see how many subsequent tracks it can cover.
        // It can cover tracks up to h[head_idx] + T.
        long long current_head_reach = h[head_idx] + T;
        while (track_idx < m && p[track_idx] <= current_head_reach) {
            track_idx++;
        }
        head_idx++; // Move to the next head for the remaining tracks
    }
    return true;
}

