// Function to apply one step of median smoothing
std::vector<int> apply_median_smoothing(const std::vector<int>& a) {
    int n = a.size();
    std::vector<int> b(n);
    if (n == 0) return b;

    b[0] = a[0];
    if (n > 1) {
        b[n - 1] = a[n - 1];
    }

    for (int i = 1; i < n - 1; ++i) {
        int sum = a[i - 1] + a[i] + a[i + 1];
        b[i] = (sum >= 2) ? 1 : 0;
    }
    return b;
}

// Function to check if a sequence is stable
bool is_stable(const std::vector<int>& a) {
    int n = a.size();
    if (n <= 2) return true; // Sequences of length 1 or 2 are always stable by definition

    for (int i = 1; i < n - 1; ++i) {
        int sum = a[i - 1] + a[i] + a[i + 1];
        int expected_b_i = (sum >= 2) ? 1 : 0;
        if (expected_b_i != a[i]) {
            return false;
        }
    }
    return true;
}

