void solve() {
    int n, k1, k2;
    std::cin >> n >> k1 >> k2;

    bool p1_has_n = false;
    for (int i = 0; i < k1; ++i) {
        int card_val;
        std::cin >> card_val;
        if (card_val == n) {
            p1_has_n = true;
        }
    }

    // Read player 2's cards, but we only care if player 1 has 'n'
    for (int i = 0; i < k2; ++i) {
        int card_val;
        std::cin >> card_val;
        // No need to check if player 2 has 'n' because cards are unique
        // If p1_has_n is true, p2 cannot have 'n'.
    }

    if (p1_has_n) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

