            if (min_idx == -1 || a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long total_spells = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue;
            }
            // For each other pile a[i], we can add min_val to it
            // as long as a[i] + min_val <= k.
            // The number of times we can add min_val to a[i] is
            // (k - a[i]) / min_val.
            // Note: k - a[i] must be non-negative for any additions.
            // Since a[i] <= k initially, k - a[i] >= 0.
            // If min_val is 0, this would be division by zero, but problem constraints
            // state 1 <= a_i <= k, so min_val >= 1.
            total_spells += (k - a[i]) / min_val;
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

#include <iostream>
