#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    // We need to select n numbers from 1 to 4n.
    // The strategy is to select n even numbers, specifically multiples of 2,
    // such that no number divides another.
    // We can start from 2n and go downwards, picking every other even number.
    // This ensures that if we pick 2k, we don't pick k (which would be 2k/2)
    // and we don't pick 4k (which would be 2 * 2k).
    // By picking numbers like 2n, 2n-2, 2n-4, ..., 2n - 2*(n-1) = 2n - 2n + 2 = 2.
    // This sequence is 2n, 2n-2, ..., 2.
    // All these numbers are even, so gcd(a,b) >= 2 for any pair.
    // Also, no number in this sequence divides another.
    // For example, if we have 2k and 2j, and 2k divides 2j, then k divides j.
    // If we pick numbers in decreasing order, say 2n, 2n-2, ..., 2n-2(n-1).
    // The smallest number is 2. The largest is 2n.
    // If 2k divides 2j, then k divides j.
    // Since all numbers are distinct and in the range [2, 2n],
    // if k divides j, then k <= j.
    // If k < j, then 2k < 2j.
    // If 2k divides 2j, then 2j = m * 2k for some integer m >= 2 (since 2k != 2j).
    // This means j = m * k.
    // The sequence is 2n, 2n-2, ..., 2n-2(n-1).
    // Let's try a different sequence: 2n+2, 2n+4, ..., 4n.
    // This sequence has (4n - (2n+2))/2 + 1 = (2n-2)/2 + 1 = n-1+1 = n numbers.
    // All numbers are even, so gcd(a,b) >= 2.
    // No number divides another: if 2k divides 2j, then k divides j.
    // The numbers are 2(n+1), 2(n+2), ..., 2(2n).
    // If 2(n+i) divides 2(n+j) where i < j, then n+i divides n+j.
    // This implies n+j = m * (n+i) for some integer m.
    // Since n+i < n+j, m must be at least 2.
    // So n+j >= 2*(n+i) = 2n + 2i.
    // But n+j is at most 2n.
    // So 2n >= n+j >= 2n + 2i.
    // This implies 0 >= 2i, which is impossible since i >= 1.
    // So no number in this sequence divides another.
    // This sequence works.

    for (int i = 0; i < n; ++i) {
        std::cout << 2 * (n + 1 + i) << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

