    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // Total sticks required: k for torches + k * y for coal
        // Each torch needs 1 stick and 1 coal.
        // To get k coal, we need k * y sticks. This takes k trades.
        // So, total sticks needed = k + k * y = k * (y + 1)
        long long total_sticks_needed = k * (y + 1);

        // We start with 1 stick.
        // We need to acquire (total_sticks_needed - 1) additional sticks
        // using the first trade offer.
        // Each use of the first trade offer (1 stick -> x sticks)
        // gives a net gain of (x - 1) sticks.
        long long sticks_to_generate = total_sticks_needed - 1;

        // Number of stick trades needed to generate sticks_to_generate
        // (sticks_to_generate + (x - 1) - 1) / (x - 1) is equivalent to ceil(sticks_to_generate / (x - 1))
        long long num_stick_trades = (sticks_to_generate + (x - 1) - 1) / (x - 1);

        // Total trades = trades to get sticks + trades to get coal
        // Trades to get sticks = num_stick_trades
        // Trades to get coal = k (since each coal is 1 trade)
        long long total_trades = num_stick_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

