void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix_price = a[n - 1]; // Initialize with the last price

    // Iterate from the second to last day backwards
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix_price) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix_price,
            // it means a[i] is a new minimum for the suffix starting from i.
            // Update min_suffix_price to a[i] because any price before a[i]
            // will compare against a[i] if a[i] is smaller than previous min_suffix_price.
            min_suffix_price = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

