int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point (cell 0)

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // Current cell is i+1.
                // The distance from the last 'R' (or 0) to this 'R' is (i+1) - (last_r_pos + 1) + 1
                // which simplifies to (i+1) - last_r_pos.
                // Example: last_r_pos = -1 (cell 0), current 'R' at s[0] (cell 1). Gap is 1 - (-1) = 2.
                // Example: last_r_pos = 2 (cell 3), current 'R' at s[4] (cell 5). Gap is 5 - 3 = 2.
                max_gap = std::max(max_gap, (i + 1) - (last_r_pos + 1) + 1);
                last_r_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' to n+1.
        // If last_r_pos is -1, it means there were no 'R's in the string, so the frog must jump from 0 to n+1.
        // The distance is (n+1) - 0 = n+1.
        // If last_r_pos is not -1, the last 'R' was at cell (last_r_pos + 1).
        // The distance to n+1 is (n+1) - (last_r_pos + 1) + 1.
        max_gap = std::max(max_gap, (n + 1) - (last_r_pos + 1) + 1);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long l, r;
    std::cin >> l >> r;

    if (l == r) {
        std::cout << l << std::endl;
    } else {
        // For any range [l, r] where r > l, the number 2 will always be a divisor
        // for at least floor(r/2) - ceil(l/2) + 1 numbers.
        // Specifically, if l is even, it's r/2 - l/2 + 1.
        // If l is odd, it's r/2 - (l+1)/2 + 1.
        // This can be simplified to (r/2) - ((l+1)/2) + 1.
        //
        // Consider any other number 'k' (k > 2).
        // The count of multiples of 'k' in [l, r] is floor(r/k) - ceil(l/k) + 1.
        // This is floor(r/k) - floor((l-1)/k).
        //
        // For k=2, the count is floor(r/2) - floor((l-1)/2).
        //
        // If r >= 2*l, then the range [l, r] contains at least one multiple of 2 (if l=2, then 2 itself; if l=3, then 4; if l=4, then 4).
        // In fact, if r > l, there are always at least two consecutive numbers, one of which is even.
        // So, 2 will always be a divisor for at least one number in the range.
        //
        // If r >= 2*l, then the number '2' will appear as a divisor for many numbers.
        // For example, if l=19, r=29.
        // Multiples of 2: 20, 22, 24, 26, 28 (5 numbers)
        // Multiples of 3: 21, 24, 27 (3 numbers)
        // Multiples of 4: 20, 24, 28 (3 numbers)
        // Multiples of 5: 20, 25 (2 numbers)
        // ...
        // In this case, 2 is the answer.
        //
        // The only scenario where 2 might not be the answer is if the range [l, r] is very small
        // and contains only odd numbers, or if it contains only one even number and some other
        // prime has more occurrences.
        //
        // Example: [3, 6]
        // Multiples of 2: 4, 6 (2 numbers)
        // Multiples of 3: 3, 6 (2 numbers)
        // Here, 2 and 3 both appear 2 times. Either is a valid answer.
        //
        // Example: [7, 9]
        // Multiples of 2: 8 (1 number)
        // Multiples of 3: 9 (1 number)
        // Multiples of 7: 7 (1 number)
        // Here, 2, 3, 7, 8, 9 all appear 1 time. Any is valid.
        //
        // The problem asks for *any* integer that appears the maximum number of times.
        //
        // If r < 2*l, then any number k > r/2 (and k >= l) can only appear once (as a divisor of k itself).
        // For example, if l=7, r=9. r/2 = 4.5.
        // Numbers > 4.5 in [7,9] are 7, 8, 9.
        // 7 is a divisor of 7.
        // 8 is a divisor of 8.
        // 9 is a divisor of 9.
        //
        // The number 2 is a divisor of 8.
        // The number 3 is a divisor of 9.
        //
        // In general, for any range [l, r] where r > l, the number 2 will always be a divisor for at least one number.
        // If l is even, 2 is a divisor of l.
        // If l is odd, l+1 is even, so 2 is a divisor of l+1 (if l+1 <= r).
        // Since r > l, if l is odd, l+1 is always <= r.
        // So, 2 is always a divisor for at least one number in the range.
        //
        // The count of multiples of 2 in [l, r] is floor(r/2) - floor((l-1)/2).
        // The count of multiples of 3 in [l, r] is floor(r/3) - floor((l-1)/3).
        //
        // For any k > 2, floor(r/k) - floor((l-1)/k) <= floor(r/2) - floor((l-1)/2).
        // This is because for k > 2, r/k <= r/2 and (l-1)/k <= (l-1)/2.
        //
        // The only edge case where this might not hold is if the range is extremely small
        // and specifically structured.
        //
        // Example: l=3, r=6
        // Count for 2: floor(6/2) - floor(2/2) = 3 - 1 = 2 (numbers 4, 6)
        // Count for 3: floor(6/3) - floor(2/3) = 2 - 0 = 2 (numbers 3, 6)
        // Here, 2 and 3 both have count 2. Outputting 2 is fine.
        //
        // Example: l=19, r=29
        // Count for 2: floor(29/2) - floor(18/2) = 14 - 9 = 5 (numbers 20, 22, 24, 26, 28)
        // Count for 3: floor(29/3) - floor(18/3) = 9 - 6 = 3 (numbers 21, 24, 27)
        // Count for 4: floor(29/4) - floor(18/4) = 7 - 4 = 3 (numbers 20, 24, 28)
        // Count for 5: floor(29/5) - floor(18/5) = 5 - 3 = 2 (numbers 20, 25)
        // In this case, 2 is clearly the winner.
        //
        // It seems that 2 is always a valid answer if r > l.
        // The only case where it's not is if l=r, in which case l itself is the only divisor (excluding 1) if l is prime, or l and its factors if l is composite.
        // But the problem states "If there are multiple answers, print any of them."
        // And "Find the integer that we wrote down the maximum number of times."
        //
        // The number 2 will always have the highest or tied-highest frequency because it's the smallest prime.
        // Any number k > 2 will have fewer or equal multiples in any given range [l, r] compared to 2.
        // The number of multiples of x in [l, r] is floor(r/x) - floor((l-1)/x).
        // Since x < y implies floor(N/x) >= floor(N/y), it follows that
        // floor(r/x) - floor((l-1)/x) >= floor(r/y) - floor((l-1)/y) for x < y.
        //
        // Therefore, the smallest prime, 2, will always have the maximum count of occurrences as a divisor.
        // If l=r, the only number is l. Its divisors (excluding 1) are its prime factors and composite factors.
        // The problem asks for *the* integer. If l=r=2, answer is 2. If l=r=3, answer is 3. If l=r=4, answer is 2 (or 4).
        // But if l=r, the problem statement "For all integers from l to r, inclusive, we wrote down all of their integer divisors except 1."
        // means we only consider the divisors of 'l'.
        // If l=r=4, divisors are {2, 4}. Both appear once. Max is 2 (or 4).
