#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_values;
    std::vector<int> available_values;

    // Determine p_i for indices where q_i > q_{i-1}
    // These p_i values are fixed to q_i
    p[0] = q[0];
    used_values.insert(q[0]);

    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            p[i] = q[i];
            if (used_values.count(q[i])) {
                // This should not happen if q is valid, as q_i must be a new max
                // But as a safety check, if q_i was already used, it's impossible.
                // However, the problem guarantees q_i are prefix maximums,
                // so q_i > q_{i-1} implies q_i is a new value.
                // The only way this could be an issue is if q_i > n, but q_i <= n is guaranteed.
                // So this specific check is likely redundant for valid q inputs.
            }
            used_values.insert(q[i]);
        } else {
            p[i] = -1; // Placeholder for values to be filled later
        }
    }

    // Collect all numbers from 1 to n that have not been used yet
    for (int i = 1; i <= n; ++i) {
        if (!used_values.count(i)) {
            available_values.push_back(i);
        }
    }
    std::sort(available_values.rbegin(), available_values.rend()); // Sort in descending order

    // Fill in the remaining p_i values
    for (int i = 0; i < n; ++i) {
        if (p[i] == -1) { // If p_i was not determined by q_i > q_{i-1}
            if (available_values.empty()) {
                // This means we ran out of available numbers, but still have slots to fill.
                // This implies an impossible scenario.
                std::cout << -1 << "\n";
                return;
            }
            int val_to_assign = available_values.back(); // Get smallest available
            available_values.pop_back();

            if (val_to_assign > q[i]) {
                // If the smallest available number is greater than q_i,
                // then we cannot satisfy p_i <= q_i.
                // This means it's impossible.
                std::cout << -1 << "\n";
                return;
            }
            p[i] = val_to_assign;
        }
    }

    // Final check for validity (optional, but good for robustness)
    // Recompute prefix maximums and compare with q
    int current_max = 0;
    for (int i = 0; i < n; ++i) {
        current_max = std::max(current_max, p[i]);
        if (current_max != q[i]) {
            std::cout << -1 << "\n";
            return;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

