int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The numbers from 1 to k+1 will be used to generate k distinct differences.

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between the smallest available and largest available numbers
    // from the range [1, k+1].
    // For example, if k=4, we use 1, 5, 2, 4, 3.
    // Differences: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1.
    // This generates k distinct differences: k, k-1, ..., 1.
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, take from left (smallest available)
            p[i] = left;
            left++;
        } else { // Odd index, take from right (largest available)
            p[i] = right;
            right--;
        }
    }

    // The remaining numbers (from k+2 to n) can be appended in increasing order.
    // This will only introduce a difference of 1 (e.g., |(k+1) - (k+2)| = 1),
    // which is already among the k distinct differences generated.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

