    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (result.length() == k) {
            break;
        }

        if (c == '(') {
            if (open_count < k / 2) {
                result += '(';
                open_count++;
                balance++;
            }
        } else { // c == ')'
            if (close_count < k / 2 && balance > 0) {
                result += ')';
                close_count++;
                balance--;
            }
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i...n-1] is non-decreasing.
    // This is the suffix that is already sorted.
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }
    // Now a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost index `j` such that a[j...i-1] is non-increasing.
    // This is the suffix that is non-increasing, followed by a non-decreasing suffix.
    // We are looking for the first element that breaks this pattern from the right.
    // The elements a[j...n-1] form a "mountain" or "valley" shape.
    // More precisely, a[j...i-1] is non-increasing, and a[i...n-1] is non-decreasing.
    int j = i;
    while (j > 0 && a[j-1] >= a[j]) {
        j--;
    }
    // Now a[j...i-1] is non-increasing.
    // The suffix a[j...n-1] is of the form [non-increasing part][non-decreasing part].

    // The length of the prefix to remove is `j`.
    // This means the remaining array is a[j...n-1].
    // This remaining array is good.
    // Any shorter prefix removal (i.e., starting from an index k < j)
    // would mean a[k] is part of the remaining array.
    // Since a[k] < a[k+1] and a[k+1] is part of the non-increasing segment,
    // this would break the non-increasing property from the left.
    // Specifically, a[k] < a[k+1] where a[k+1] >= a[k+2] >= ... >= a[i-1] <= a[i] <= ... <= a[n-1].
    // This structure (a[k] < a[k+1] and a[k+1] >= a[k+2]) cannot be formed into a non-decreasing sequence
    // by picking from ends, because a[k] would have to be picked before a[k+1] (if a[k] is smaller)
    // but a[k+1] is not the last element.
    // Or if a[k] is picked after a[k+1], then a[k] must be >= a[k+1], which contradicts a[k] < a[k+1].
    // The only way to make it good is to remove a[k].
    // So, the shortest prefix to remove is of length `j`.

    std::cout << j << std::endl;
}

