        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm> // For std::min and std::max

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p

    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For current 'm', we need to find a subsegment [l, r]
        // that contains all numbers from 1 to m, and no numbers > m.
        // The length of this subsegment must be exactly m.

        // The subsegment must contain 1, 2, ..., m.
        // So, its left boundary 'l' must be <= pos[k] for all k=1..m.
        // And its right boundary 'r' must be >= pos[k] for all k=1..m.
        // This means 'l' must be <= min(pos[1]...pos[m])
        // and 'r' must be >= max(pos[1]...pos[m]).

        // We maintain current_min_idx and current_max_idx for numbers 1 to m-1.
        // When we consider 'm', we update these to include pos[m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // The smallest possible range [l, r] that contains all numbers 1 to m
        // is [current_min_idx, current_max_idx].
        // The length of this minimal range is (current_max_idx - current_min_idx + 1).

        // For 'm' to be beautiful, this minimal range must have length 'm'.
        // If (current_max_idx - current_min_idx + 1) == m,
        // it means all numbers from 1 to m are located within a contiguous block of length m.
        // Since they are all distinct and there are m of them, this block must be
        // exactly {1, 2, ..., m} as a set, and thus a permutation of them.
        if ((current_max_idx - current_min_idx + 1) == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

