#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    std::string ans1 = "Tidak"; // Box 1: (-inf, -1]
    std::string ans2 = "Tidak"; // Box 2: (-1, 0)
    std::string ans3 = "Tidak"; // Box 3: (0, 1)
    std::string ans4 = "Tidak"; // Box 4: [1, inf)

    if (total_toys == 1) {
        if (A == 1) ans1 = "Ya";
        if (B == 1) ans2 = "Ya";
        if (C == 1) ans3 = "Ya";
        if (D == 1) ans4 = "Ya";
    } else {
        // Case 1: Final toy is positive
        // This requires an even number of initial negative toys (A+B is even).
        // If A+B is odd, it's impossible to get a positive final toy.
        if ((A + B) % 2 == 0) {
            // Can it be in Box 3 (0, 1)?
            // Yes, if there's at least one toy with magnitude < 1 (B or C)
            // OR if there are no toys with magnitude >= 1 (A and D are 0).
            // If A+D > 0, we need to be able to "reduce" the magnitude.
            // This is possible if B+C > 0 (i.e., there's at least one toy with magnitude < 1).
            // If A+D > 0 and B+C == 0, then all toys have magnitude >= 1, so the product will be >= 1.
            // So, for Box 3 (0,1), we need (B+C > 0) OR (A+D == 0).
            // The condition (A+D == 0) implies all toys are in B or C, so B+C > 0 is guaranteed.
            // Thus, the condition simplifies to B+C > 0.
            if (B + C > 0) {
                ans3 = "Ya";
            }

            // Can it be in Box 4 [1, inf)?
            // Yes, if there's at least one toy with magnitude >= 1 (A or D).
            // If A+D > 0, we can always arrange multiplications to keep magnitude >= 1.
            // For example, multiply all B/C toys first (product < 1), then multiply by A/D toys.
            // If A+D == 0, then all toys are in B or C. The product will be < 1.
            // So, for Box 4 [1, inf), we need A+D > 0.
            if (A + D > 0) {
                ans4 = "Ya";
            }
        }

        // Case 2: Final toy is negative
        // This requires an odd number of initial negative toys (A+B is odd).
        // If A+B is even, it's impossible to get a negative final toy.
        if ((A + B) % 2 == 1) {
            // Can it be in Box 2 (-1, 0)?
            // Similar logic to Box 3. We need (B+C > 0) OR (A+D == 0).
            if (B + C > 0) {
                ans2 = "Ya";
            }

            // Can it be in Box 1 (-inf, -1]?
            // Similar logic to Box 4. We need A+D > 0.
            if (A + D > 0) {
                ans1 = "Ya";
            }
        }
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

