                    // This is because if we have a '01' at index i and a '10' at index j,
                    // and we decide to swap them, the cost is |i-j|.
                    // If we have a '01' at index i and a '10' at index i+1, we can swap them for cost 1.
                    // This is the minimum possible cost for a swap.
                    // If we have a '01' at index i and a '10' at index j, and we don't swap them,
                    // we must flip both, costing 2.
                    // So, if we have both types of mismatches, we can always resolve one of each
                    // with a cost of 1 (by swapping adjacent differing bits).
                    // This is a common trick in these types of problems.
                    // The cost of 1 comes from the fact that we can always find an adjacent pair
                    // or effectively treat it as such.
                    // The problem is that we don't know the exact indices.
                    // Let's re-evaluate.
                    // If a[i] = '0', b[i] = '1' (type 01)
                    // If a[j] = '1', b[j] = '0' (type 10)
                    // We can swap a[i] and a[j]. Cost |i-j|. Both become correct.
                    // Or we can flip a[i] (cost 1) and flip a[j] (cost 1). Total cost 2.
                    // So if |i-j| < 2, swap is better. If |i-j| >= 2, flips are better.
                    // This means we only consider swaps for adjacent differing bits.
                    // If a[i] != b[i] and a[i+1] != b[i+1] and a[i] != a[i+1] (i.e., one is '01' and other is '10'),
                    // we can swap a[i] and a[i+1] for cost 1.
                    // This resolves both mismatches.
                    // This is the greedy strategy.
                    // Iterate through the string.
                    // If a[i] != b[i]:
                    //   If a[i+1] != b[i+1] and a[i] != a[i+1] (meaning a[i] is '0', b[i] is '1' and a[i+1] is '1', b[i+1] is '0' OR vice versa)
                    //     Then we can swap a[i] and a[i+1]. Cost 1. Increment i to skip i+1.
                    //   Else (no adjacent swap possible or beneficial)
                    //     Flip a[i]. Cost 1.
                    // This logic is correct.

                    // Let's trace the example:
                    // n=3, a="100", b="001"
                    // i=0: a[0]='1', b[0]='0'. Mismatch.
                    //      a[1]='0', b[1]='0'. Match. No adjacent swap.
                    //      Flip a[0]. Cost 1. total_cost = 1. a becomes "000".
                    // i=1: a[1]='0', b[1]='0'. Match.
                    // i=2: a[2]='0', b[2]='1'. Mismatch.
                    //      End of string. No adjacent swap.
                    //      Flip a[2]. Cost 1. total_cost = 1+1=2. a becomes "001".
                    // Final cost 2. This matches example.

                    // Example 2:
                    // n=4, a="0101", b="0011"
                    // i=0: a[0]='0', b[0]='0'. Match.
                    // i=1: a[1]='1', b[1]='0'. Mismatch.
                    //      a[2]='0', b[2]='1'. Mismatch.
                    //      a[1] != b[1] AND a[2] != b[2] AND a[1] != a[2] ('1' vs '0').
                    //      This is an adjacent swap candidate.
                    //      Swap a[1] and a[2]. Cost 1. total_cost = 1.
                    //      Increment i to skip a[2]. i becomes 2.
                    // i=2 (after increment):
                    // i=3: a[3]='1', b[3]='1'. Match.
                    // Final cost 1. This matches example.

                    // This greedy strategy seems to work.
                    // The logic is:
                    // Iterate i from 0 to n-1.
                    // If a[i] != b[i]:
                    //   If i+1 < n and a[i+1] != b[i+1] and a[i] != a[i+1]:
                    //     total_cost += 1;
                    //     i++; // Skip next character as it's resolved
                    //   Else:
                    //     total_cost += 1; // Flip a[i]
                }
            }
        }
    }

    // The above logic is correct.
    // The crucial part is that if a[i] != b[i] and a[i+1] != b[i+1] and a[i] != a[i+1],
    // it means one is '0' and needs to be '1', and the other is '1' and needs to be '0'.
    // For example, a[i]='0', b[i]='1' and a[i+1]='1', b[i+1]='0'.
    // Swapping a[i] and a[i+1] makes a[i]='1' (matches b[i]) and a[i+1]='0' (matches b[i+1]).
    // This costs |i - (i+1)| = 1.
    // If we were to flip them, it would cost 1 (for a[i]) + 1 (for a[i+1]) = 2.
    // So, swapping adjacent differing bits is always optimal if possible.
    // If such an adjacent pair is not found, then we must flip the current bit, costing 1.

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (i + 1 < n && a[i+1] != b[i+1] && a[i] != a[i+1]) {
                // Found an adjacent pair that can be swapped for cost 1
                total_cost += 1;
                i++; // Skip the next character as it's also resolved
            } else {
                // No adjacent swap possible or beneficial, so flip current bit
                total_cost += 1;
            }
        }
    }

    std::cout << total_cost << std::endl;

    return 0;
}

#include <iostream>
