// Function to check if a sub-array is a permutation of its length
// This version uses a boolean array for presence check and finds max value
// It also checks if all numbers from 1 to length are present
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) return true; // An empty sequence can be considered a permutation of length 0
    if (len > arr.size() - start_idx) return false; // Not enough elements

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    // After iterating, check if max_val is equal to len
    // and if all numbers from 1 to len were seen.
    // The `seen` array check `seen[val]` already ensures distinctness and range [1, len].
    // If max_val == len, and all numbers from 1 to len are distinct and within range,
    // then all numbers from 1 to len must be present.
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    int max_overall = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] > max_overall) {
            max_overall = a[i];
        }
    }

    std::vector<std::pair<int, int>> solutions;

    // Precompute prefix permutation checks
    std::vector<bool> is_prefix_perm(n + 1, false);
    if (n > 0) {
        std::vector<bool> seen_prefix(n + 1, false); // Max possible value is n, but elements are up to n-1
        int current_max_prefix = 0;
        bool possible_prefix = true;
        for (int l1 = 1; l1 <= n; ++l1) {
            int val = a[l1 - 1];
            if (val <= 0 || val > l1 || seen_prefix[val]) {
                possible_prefix = false;
            }
            if (possible_prefix) {
                seen_prefix[val] = true;
                if (val > current_max_prefix) {
                    current_max_prefix = val;
                }
                if (current_max_prefix == l1) {
                    is_prefix_perm[l1] = true;
                }
            }
        }
    }

    // Precompute suffix permutation checks
    std::vector<bool> is_suffix_perm(n + 1, false);
    if (n > 0) {
        std::vector<bool> seen_suffix(n + 1, false); // Max possible value is n, but elements are up to n-1
        int current_max_suffix = 0;
        bool possible_suffix = true;
        for (int l2 = 1; l2 <= n; ++l2) {
            int val = a[n - l2];
            if (val <= 0 || val > l2 || seen_suffix[val]) {
                possible_suffix = false;
            }
            if (possible_suffix) {
                seen_suffix[val] = true;
                if (val > current_max_suffix) {
                    current_max_suffix = val;
                }
                if (current_max_suffix == l2) {
                    is_suffix_perm[l2] = true;
                }
            }
        }
    }

    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 = n - l1 must be at least 1
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            solutions.push_back({l1, l2});
        }
    }

    std::cout << solutions.size() << "\n";
    for (const auto& p : solutions) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
