long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is optimal
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0 && n / 2 > 1) { // N/2 is odd and N/2 > 1
                    // Taking N/2 leaves an odd number for opponent, which is good for Chanek
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even or N/2 = 1
                    // Taking 1 leaves an odd number for opponent, which is good for Chanek
                    chanek_coins += 1;
                    n -= 1;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                if (n == 2) { // Opponent takes 1
                    n -= 1;
                } else if ((n / 2) % 2 != 0 && n / 2 > 1) { // N/2 is odd and N/2 > 1
                    // Opponent takes N/2 to maximize their coins
                    n /= 2;
                } else { // N/2 is even or N/2 = 1
                    // Opponent takes 1 to maximize their coins
                    n -= 1;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

