    int countP = 0;
    int countS = 0;

    for (char ch : s) {
        if (ch == 'R') {
            countR++;
        } else if (ch == 'P') {
            countP++;
        } else { // ch == 'S'
            countS++;
        }
    }

    char optimal_counter_move;
    if (countR >= countP && countR >= countS) {
        // 'R' is the most frequent move by the bot.
        // To maximize wins against 'R', we should play 'P'.
        optimal_counter_move = 'P';
    } else if (countP >= countR && countP >= countS) {
        // 'P' is the most frequent move by the bot.
        // To maximize wins against 'P', we should play 'S'.
        optimal_counter_move = 'S';
    } else { // countS >= countR && countS >= countP
        // 'S' is the most frequent move by the bot.
        // To maximize wins against 'S', we should play 'R'.
        optimal_counter_move = 'R';
    }

    for (int i = 0; i < n; ++i) {
        std::cout << optimal_counter_move;
    }
    std::cout << std::endl;
}

