#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    if (n == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    long long score = 0;
    int initial_wins = 0;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            initial_wins++;
            if (i > 0 && s[i-1] == 'W') {
                score += 2;
            } else {
                score += 1;
            }
        }
    }

    if (initial_wins == 0) { // All L's initially
        if (k == 0) {
            std::cout << 0 << std::endl;
        } else {
            std::cout << std::min((long long)n, k) * 2 - 1 << std::endl;
        }
        return;
    }

    // Find the first and last 'W'
    int first_w = -1;
    int last_w = -1;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            if (first_w == -1) {
                first_w = i;
            }
            last_w = i;
        }
    }

    // Collect lengths of 'L' segments between 'W's
    std::vector<int> gaps;
    int current_gap = 0;
    for (int i = first_w + 1; i <= last_w; ++i) {
        if (s[i] == 'L') {
            current_gap++;
        } else { // s[i] == 'W'
            if (current_gap > 0) {
                gaps.push_back(current_gap);
            }
            current_gap = 0;
        }
    }
    std::sort(gaps.begin(), gaps.end());

    // Fill internal gaps
    for (int gap_len : gaps) {
        if (k >= gap_len) {
            k -= gap_len;
            score += gap_len * 2 + 1; // Each L becomes W, adds 2 points. The first L in the gap connects two Ws, adding 1 extra point.
                                      // Example: W L L W -> W W W W. Score change: 0 -> 1+2+2+2 = 7.
                                      // Original: W W. Score: 1+2 = 3.
                                      // W L W. Score: 1+1+1 = 3.
                                      // W L L W. Score: 1+1+1+1 = 4.
                                      // If we fill LLL (gap_len=3) between W and W: W LLL W -> W WWWW W.
                                      // Original score for W...W: 1+2*(num_W-1)
                                      // After filling: 1+2*(num_W+gap_len-1)
                                      // Score increase: 2*gap_len.
                                      // But this is for a block.
                                      // Let's re-evaluate:
                                      // W L W -> W W W.
                                      // Original: W(1) L(0) W(1) = 2.
                                      // New: W(1) W(2) W(2) = 5.
                                      // Increase: 3. Gap length = 1. 2*1 + 1 = 3. Correct.
                                      // W L L W -> W W W W.
                                      // Original: W(1) L(0) L(0) W(1) = 2.
                                      // New: W(1) W(2) W(2) W(2) = 7.
                                      // Increase: 5. Gap length = 2. 2*2 + 1 = 5. Correct.
        } else {
            break;
        }
    }

    // Fill 'L's before the first 'W'
    int prefix_L_count = first_w;
    if (k >= prefix_L_count) {
        k -= prefix_L_count;
        score += prefix_L_count * 2; // Each L becomes W, adds 2 points.
                                     // Example: L L W -> W W W.
                                     // Original: L(0) L(0) W(1) = 1.
                                     // New: W(1) W(2) W(2) = 5.
                                     // Increase: 4. prefix_L_count = 2. 2*2 = 4. Correct.
    } else {
        score += k * 2;
        k = 0;
    }

    // Fill 'L's after the last 'W'
    int suffix_L_count = n - 1 - last_w;
    if (k >= suffix_L_count) {
        k -= suffix_L_count;
        score += suffix_L_count * 2; // Each L becomes W, adds 2 points.
                                     // Example: W L L -> W W W.
                                     // Original: W(1) L(0) L(0) = 1.
                                     // New: W(1) W(2) W(2) = 5.
                                     // Increase: 4. suffix_L_count = 2. 2*2 = 4. Correct.
    } else {
        score += k * 2;
        k = 0;
    }

    std::cout << score << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

