#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;

    // Friends who receive w_i = 1 integer
    // These friends should get the largest available integers, and their happiness is 2 * integer.
    // We assign the k_one largest integers to these friends.
    int k_one = 0;
    for (int i = 0; i < k; ++i) {
        if (w[i] == 1) {
            k_one++;
        }
    }

    // Assign largest elements to friends with w_i = 1
    // These are the k_one largest elements from 'a'.
    // They will be both max and min for their respective friends.
    // The w array is sorted, so the last k_one elements are the ones with w_i = 1.
    // The a array is sorted, so the last k_one elements are the largest.
    for (int i = 0; i < k_one; ++i) {
        total_happiness += 2 * a[n - 1 - i];
    }

    // Friends who receive w_i > 1 integers
    // These friends need a min and a max.
    // To maximize sum of happiness, we should give them the remaining largest elements as their max.
    // And the smallest available elements as their min.

    // The remaining largest elements are a[n - 1 - k_one], a[n - 2 - k_one], ...
    // These should be assigned as the 'max' for friends with w_i > 1.
    // There are k - k_one such friends.
    // The w array is sorted, so w[0]...w[k-k_one-1] are the w_i > 1 values.
    // We iterate from the largest w_i > 1 down to the smallest w_i > 1.
    // This corresponds to iterating w from index k - k_one - 1 down to 0.
    // The largest remaining elements from 'a' are assigned as max values.
    // These are a[n - 1 - k_one], a[n - 2 - k_one], ..., a[n - 1 - k_one - (k - k_one - 1)].
    // This means we use elements from a[n - 1 - k_one] down to a[n - k].

    int current_a_idx_for_max = n - 1 - k_one; // Index of the largest available element for max
    for (int i = k - k_one - 1; i >= 0; --i) { // Iterate through friends with w_i > 1, from largest w_i to smallest
        total_happiness += a[current_a_idx_for_max]; // Assign the largest available as max
        current_a_idx_for_max--;
    }

    // Now assign the minimums for friends with w_i > 1.
    // These friends are w[0]...w[k-k_one-1].
    // We need to assign w_i - 1 additional elements to each of these friends,
    // and the smallest element among them will be their min.
    // To maximize sum of happiness, we should give the smallest available elements as min.
    // The smallest available elements are a[0], a[1], ...
    // We iterate through friends with w_i > 1, from smallest w_i to largest.
    // This corresponds to iterating w from index 0 up to k - k_one - 1.

    int current_a_idx_for_min = 0; // Index of the smallest available element for min
    for (int i = 0; i < k - k_one; ++i) { // Iterate through friends with w_i > 1, from smallest w_i to largest
        total_happiness += a[current_a_idx_for_min]; // Assign the smallest available as min
        current_a_idx_for_min += (w[i] - 1); // Skip w_i - 1 elements for this friend
        current_a_idx_for_min++; // Move to the next smallest available for the next friend's min
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
