#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << "\n\n";
    } else {
        // We need to append at most 3 elements.
        // Let the current sum be S and current XOR sum be X.
        // We want to find b1, b2, b3 such that (S + b1 + b2 + b3) = 2 * (X ^ b1 ^ b2 ^ b3).
        // A simple strategy is to append two elements.
        // Let's try to append b1 and b2.
        // We want (S + b1 + b2) = 2 * (X ^ b1 ^ b2).
        // Consider b1 = X.
        // Then the new XOR sum becomes X' = X ^ X = 0.
        // The new sum becomes S' = S + X.
        // The condition becomes S + X = 2 * 0, which means S + X = 0.
        // This is only true if S=0 and X=0, which is not generally the case.

        // Let's try to append b1 and b2 such that X ^ b1 ^ b2 = 0.
        // This means b1 ^ b2 = X.
        // And we want S + b1 + b2 = 2 * 0 = 0. This is not possible for non-negative numbers.

        // The problem statement guarantees a solution always exists with at most 3 elements.
        // A common strategy for these problems is to make the XOR sum equal to some value, say Y,
        // and then make the sum equal to 2Y.

        // Let's try to append two elements: X and S + X.
        // New XOR sum: X' = current_xor_sum ^ X = 0.
        // New sum: S' = current_sum + X.
        // Now we need to append one more element, say `val`, such that:
        // (S' + val) = 2 * (X' ^ val)
        // (current_sum + X + val) = 2 * (0 ^ val)
        // (current_sum + X + val) = 2 * val
        // current_sum + X = val
        // So, if we append X and then (current_sum + X), the condition should hold.

        // Let's verify this strategy:
        // Initial: sum = S, xor_sum = X
        // Append b1 = X:
        //   New sum = S + X
        //   New xor_sum = X ^ X = 0
        // Append b2 = S + X:
        //   Final sum = (S + X) + (S + X) = 2 * (S + X)
        //   Final xor_sum = 0 ^ (S + X) = S + X
        // Check condition: Final sum == 2 * Final xor_sum
        // 2 * (S + X) == 2 * (S + X)
        // This holds!

        // So, we append two elements: X and S + X.
        // The problem states "at most 3 elements". This strategy uses 2 elements.
        // The values can be large, up to 10^9 for initial elements, sum can be 10^5 * 10^9 = 10^14.
        // X can be up to 2^30 (approx 10^9).
        // S + X can be up to 10^14 + 10^9, which fits in long long.

        std::cout << 2 << "\n";
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
    }
}

