    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // Rule 1: If s[i] is '0', then w[i-x] and w[i+x] must be '0'
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Rule 2: Verify if the constructed w can produce s
    // For each s[i], check if it's '1'. If it is, then at least one of w[i-x] or w[i+x] must be '1'.
    // If s[i] is '0', we've already handled it by setting corresponding w characters to '0'.
    // So, we only need to check s[i] == '1'.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            bool found_one = false;
            if (i - x >= 0 && w[i - x] == '1') {
                found_one = true;
            }
            if (i + x < n && w[i + x] == '1') {
                found_one = true;
            }
            if (!found_one) {
                // If s[i] is '1' but neither w[i-x] nor w[i+x] is '1',
                // then no such w exists.
                std::cout << -1 << std::endl;
                return;
            }
        }
    }

    std::cout << w << std::endl;
}

