#include <map>

long long get_max_divisor_not_divisible_by_q(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    std::map<long long, int> prime_factors_q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            while (temp_q % i == 0) {
                prime_factors_q[i]++;
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        prime_factors_q[temp_q]++;
    }

    for (auto const& [factor, exponent] : prime_factors_q) {
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= factor;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

