#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int pivot = 0; pivot <= 9; ++pivot) {
        std::string current_coloring(n, ' ');
        char last1 = '0';
        char last2 = '0';
        bool possible_pivot = true;

        for (int i = 0; i < n; ++i) {
            char digit = s[i];
            if (digit < (pivot + '0')) {
                // Must be color 1
                if (digit < last1) {
                    possible_pivot = false;
                    break;
                }
                current_coloring[i] = '1';
                last1 = digit;
            } else if (digit > (pivot + '0')) {
                // Must be color 2
                if (digit < last2) {
                    possible_pivot = false;
                    break;
                }
                current_coloring[i] = '2';
                last2 = digit;
            } else { // digit == pivot
                // Can be color 1 or 2. Prefer 2 if possible to keep last1 small.
                // If it can be color 2, assign it to 2.
                if (digit >= last2) {
                    current_coloring[i] = '2';
                    last2 = digit;
                } else if (digit >= last1) { // Otherwise, try to assign to 1.
                    current_coloring[i] = '1';
                    last1 = digit;
                } else { // Cannot be assigned to either without violating non-decreasing property
                    possible_pivot = false;
                    break;
                }
            }
        }

        if (possible_pivot) {
            // Final check: ensure last1 <= first2.
            // This is implicitly handled by the logic:
            // - All digits < pivot are 1.
            // - All digits > pivot are 2.
            // - Digits == pivot are assigned greedily.
            //   If a digit == pivot is assigned 1, it means it was >= last1.
            //   If a digit == pivot is assigned 2, it means it was >= last2.
            //   The crucial part is that last1 will be <= pivot, and first2 will be >= pivot.
            //   So last1 <= first2 is guaranteed if both sequences are non-decreasing.
            //   The only edge case is if last1 is from a digit < pivot and first2 is from a digit > pivot.
            //   But the logic ensures that if a digit is assigned to 1, it's >= last1, and if to 2, it's >= last2.
            //   The pivot value itself acts as the boundary.
            //   Any digit assigned '1' will be <= pivot. Any digit assigned '2' will be >= pivot.
            //   So, the last '1' digit will be <= pivot, and the first '2' digit will be >= pivot.
            //   Thus, last '1' digit <= first '2' digit is always true.

            result = current_coloring;
            found_solution = true;
            break; 
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

