    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_pattern(k, '?');

    // Step 1: Propagate known characters within each k-cycle
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            if (fixed_pattern[i % k] == '?') {
                fixed_pattern[i % k] = s[i];
            } else if (fixed_pattern[i % k] != s[i]) {
                // Conflict: s[i] contradicts an already established character in its k-cycle
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Check if the fixed_pattern itself is k-balanced
    int zeros_in_pattern = 0;
    int ones_in_pattern = 0;
    int q_marks_in_pattern = 0;

    for (int i = 0; i < k; ++i) {
        if (fixed_pattern[i] == '0') {
            zeros_in_pattern++;
        } else if (fixed_pattern[i] == '1') {
            ones_in_pattern++;
        } else { // fixed_pattern[i] == '?'
            q_marks_in_pattern++;
        }
    }

    if (zeros_in_pattern > k / 2 || ones_in_pattern > k / 2) {
        // Too many 0s or 1s already in the first k characters
        std::cout << "NO\n";
        return;
    }

    // Step 3: Fill remaining '?' in fixed_pattern to satisfy k-balance
    // We need k/2 zeros and k/2 ones.
    // We have zeros_in_pattern and ones_in_pattern.
    // We need to fill (k/2 - zeros_in_pattern) '0's and (k/2 - ones_in_pattern) '1's.
    // The total number of '?' is q_marks_in_pattern.
    // The sum of needed '0's and '1's must equal q_marks_in_pattern.
    // (k/2 - zeros_in_pattern) + (k/2 - ones_in_pattern) = k - (zeros_in_pattern + ones_in_pattern)
    // This is exactly q_marks_in_pattern. So, it's always possible to fill them.

    // The problem statement implies that if the first k characters can be made k-balanced,
    // and the k-cycle consistency holds, then the entire string can be made k-balanced.
    // This is because the pattern fixed_pattern[i % k] determines s[i] for all i.
    // If fixed_pattern is k-balanced, then any substring s[j...j+k-1] will also be k-balanced
    // because it will be a cyclic shift of fixed_pattern.
    // A cyclic shift of a k-balanced string is also k-balanced.

    std::cout << "YES\n";
}

