#include <iostream>

long long sum_arithmetic_series(long long n) {
    if (n <= 0) {
        return 0;
    }
    long long MOD = 1000000007;
    long long n_mod = n % MOD;
    long long n_plus_1_mod = (n + 1) % MOD;

    long long term1 = n_mod;
    long long term2 = n_plus_1_mod;

    // One of n or n+1 must be even, so (n*(n+1))/2 is an integer.
    // We need to divide by 2.
    // Since MOD is prime and > 2, we can multiply by modular inverse of 2.
    // Modular inverse of 2 modulo 10^9+7 is (10^9+7 + 1) / 2 = 500000004.
    long long inv2 = 500000004;

    long long sum = (term1 * term2) % MOD;
    sum = (sum * inv2) % MOD;
    return sum;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // If b = 1, mod(x, 1) is always 0, so no nice integers.
    // The sum_arithmetic_series(b-1) will be sum_arithmetic_series(0) which is 0.
    // So the formula naturally handles b=1.

    long long sum_r = sum_arithmetic_series(b - 1); // Sum of r from 1 to b-1

    long long sum_k_b_plus_1 = 0;
    // Sum of (k*b + 1) for k from 1 to a
    // This is sum(k*b) + sum(1)
    // = b * sum(k) + a
    // = b * (a*(a+1)/2) + a

    long long sum_k = sum_arithmetic_series(a); // Sum of k from 1 to a

    long long term_b_sum_k = (b % MOD * sum_k) % MOD;
    long long term_a = a % MOD;

    sum_k_b_plus_1 = (term_b_sum_k + term_a) % MOD;

    long long total_sum = (sum_r * sum_k_b_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

