#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 0) {
        std::cout << 0 << std::endl;
        return 0;
    }

    std::vector<long long> L(n);
    std::deque<int> dq;

    for (int i = 0; i < n; ++i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long val = 0;
        if (!dq.empty()) {
            val = std::max(val, L[dq.back()] + (i - dq.back()));
        }
        L[i] = std::max(h[i], val);
        dq.push_back(i);
    }

    dq.clear();
    std::vector<long long> R(n);
    for (int i = n - 1; i >= 0; --i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long val = 0;
        if (!dq.empty()) {
            val = std::max(val, R[dq.back()] + (dq.back() - i));
        }
        R[i] = std::max(h[i], val);
        dq.push_back(i);
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, std::min(L[i], R[i]));
    }

    std::cout << max_ops << std::endl;

    return 0;
}

