#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_ones(n, 0);
    std::vector<int> right_zeros(n, 0);

    // Calculate left_ones: length of consecutive 1s ending at i
    if (a[0] == 1) left_ones[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == 1) {
            left_ones[i] = left_ones[i - 1] + 1;
        } else {
            left_ones[i] = 0;
        }
    }

    // Calculate right_zeros: length of consecutive 0s starting at i
    if (a[n - 1] == 0) right_zeros[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zeros[i] = right_zeros[i + 1] + 1;
        } else {
            right_zeros[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n - 1; ++i) {
        if (a[i] == 1 && a[i + 1] == 0) { // Found a 10 pattern
            int k_val = (std::min(left_ones[i], right_zeros[i + 1]) + 1) / 2;
            max_k = std::max(max_k, k_val);
        }
    }

    std::cout << max_k << "\n";

    std::vector<int> result_a = a;
    for (int i = 0; i < n - 1; ++i) {
        if (a[i] == 1 && a[i + 1] == 0) { // Found a 10 pattern
            int len_ones = left_ones[i];
            int len_zeros = right_zeros[i + 1];
            int k_val = (std::min(len_ones, len_zeros) + 1) / 2;

            // Change 1s to 0s
            for (int j = 0; j < k_val; ++j) {
                if (i - j >= 0) {
                    result_a[i - j] = 0;
                }
            }
            // Change 0s to 1s
            for (int j = 0; j < k_val; ++j) {
                if (i + 1 + j < n) {
                    result_a[i + 1 + j] = 1;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << result_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Iterate in reverse order of removal, effectively adding vertices
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being "added" in this step

        active_vertices[k] = true; // Mark vertex k as active

        // Update shortest paths using vertex k as an intermediate
        // Floyd-Warshall step: dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                if (dist[i][k] != -1 && dist[k][j] != -1) { // Check for reachability if using a sentinel for infinity
                    if (dist[i][j] == -1 || dist[i][k] + dist[k][j] < dist[i][j]) {
                        dist[i][j] = dist[i][k] + dist[k][j];
                    }
                }
            }
        }

        // After updating with k as an intermediate, also update paths using other active vertices
        // This is crucial because k might open up new shorter paths between existing active vertices
        // that don't necessarily pass through k itself as the *last* intermediate.
        // The standard Floyd-Warshall order is k, then i, then j.
        // Here, k is the *newest* vertex. We need to ensure all pairs (i,j)
        // among currently active vertices consider all active vertices (including k) as intermediates.
        // The previous loop (i,j,k) already did this for k as the *newest* intermediate.
        // The full Floyd-Warshall loop structure is:
        // for k_prime in all_vertices:
        //   for i_prime in all_vertices:
        //     for j_prime in all_vertices:
        //       dist[i_prime][j_prime] = min(dist[i_prime][j_prime], dist[i_prime][k_prime] + dist[k_prime][j_prime])
        //
        // When we add vertex k, we need to ensure that all paths between *currently active* vertices
        // are updated considering *all currently active* vertices as intermediates.
        // The loop above (for i,j,k) correctly updates dist[i][j] using k as an intermediate.
        // However, it doesn't update dist[k][j] using some other active vertex 'm' as an intermediate,
        // or dist[i][k] using 'm' as an intermediate.
        //
        // A more robust way is to re-run the Floyd-Warshall step for all active vertices.
        // Since we are adding vertices one by one, the `dist` matrix already holds shortest paths
        // considering all vertices `x[k_idx+1], ..., x[n-1]` as intermediates.
        // When `x[k_idx]` is added, we need to update paths considering `x[k_idx]` as an intermediate.
        // The standard Floyd-Warshall update `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`
        // is sufficient if `i` and `j` are also active.
        //
        // Let's re-evaluate the Floyd-Warshall update order.
        // The standard Floyd-Warshall algorithm iterates `k` (intermediate), then `i` (source), then `j` (destination).
        // `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`.
        // In our reversed approach, `k` is the vertex being added.
        // So, for the current `k` (which is `x[k_idx]`), we need to update all pairs `(i, j)`
        // using `k` as an intermediate. This is what the first nested loop does.
        //
        // However, we also need to consider paths like `i -> m -> k` or `k -> m -> j` where `m` is another active vertex.
        // The standard Floyd-Warshall structure handles this naturally.
        //
        // The correct way to integrate the new vertex `k` into the all-pairs shortest path calculation
        // is to consider `k` as an intermediate for all existing pairs, and also consider existing active
        // vertices as intermediates for paths involving `k`.
        //
        // The three nested loops for Floyd-Warshall are:
        // for (int k_prime = 0; k_prime < n; ++k_prime) { // intermediate
        //   for (int i_prime = 0; i_prime < n; ++i_prime) { // source
        //     for (int j_prime = 0; j_prime < n; ++j_prime) { // destination
        //       dist[i_prime][j_prime] = min(dist[i_prime][j_prime], dist[i_prime][k_prime] + dist[k_prime][j_prime]);
        //     }
        //   }
        // }
        //
        // When we add vertex `k = x[k_idx]`, we need to ensure that `dist` matrix reflects shortest paths
        // considering all currently active vertices as intermediates.
        // The `dist` matrix *already* contains shortest paths considering `x[k_idx+1], ..., x[n-1]` as intermediates.
        // Now we add `x[k_idx]`. So we need to run the Floyd-Warshall step for `k = x[k_idx]`.
        //
        // The loops should be:
        // 1. Update paths `i -> j` using `k` as intermediate:
        //    for i in 0..n-1:
        //      for j in 0..n-1:
        //        dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        //
        // 2. Update paths `i -> k` using other active vertices `m` as intermediate:
        //    for i in 0..n-1:
        //      for m in 0..n-1: (where m is active)
        //        dist[i][k] = min(dist[i][k], dist[i][m] + dist[m][k])
        //
        // 3. Update paths `k -> j` using other active vertices `m` as intermediate:
        //    for j in 0..n-1:
        //      for m in 0..n-1: (where m is active)
        //        dist[k][j] = min(dist[k][j], dist[k][m] + dist[m][j])
        //
        // Combining these, the standard Floyd-Warshall structure where `k` is the outermost loop
        // naturally handles this.
        //
        // So, the correct way to do this is:
        // For the current `k` (the vertex being added):
        // 1. Update all `dist[i][j]` using `k` as an intermediate.
        //    This means `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`.
        //    This loop is already present.
        //
        // 2. Update all `dist[i][k]` using any other active vertex `m` as an intermediate.
        //    This means `dist[i][k] = min(dist[i][k], dist[i][m] + dist[m][k])`.
        //    This is implicitly handled if we consider `k` as a `j` and `m` as an intermediate.
        //
        // 3. Update all `dist[k][j]` using any other active vertex `m` as an intermediate.
        //    This means `dist[k][j] = min(dist[k][j], dist[k][m] + dist[m][j])`.
        //    This is implicitly handled if we consider `k` as an `i` and `m` as an intermediate.
        //
        // The standard Floyd-Warshall algorithm is `for k, for i, for j`.
        // If we are adding vertices in reverse order `x_n, x_{n-1}, ..., x_1`,
        // and `k` is the current vertex being added, then `k` becomes the `k_prime` in Floyd-Warshall.
        //
        // So, the loop `for i, for j, dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`
        // is indeed the correct step for integrating `k` as a new intermediate vertex.
        // This single step updates all paths `i -> j` that *might* now be shorter by passing through `k`.
        // It also updates paths `i -> k` and `k -> j` if they can be shortened by passing through other active vertices.
        //
        // Example: `i -> m -> k`. When `k` is added, `dist[i][k]` might be updated by `dist[i][m] + dist[m][k]`.
        // This happens if `m` was already active.
        // The current loop `for i, for j, dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`
        // does not explicitly do `dist[i][k] = min(dist[i][k], dist[i][m] + dist[m][k])`.
        //
        // Let's trace the standard Floyd-Warshall:
        // `dist[i][j]` is the shortest path using intermediates `0..k-1`.
        // To get `dist[i][j]` using intermediates `0..k`, we do:
        // `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`.
        //
        // In our reversed approach, `k` is the *newest* vertex.
        // `dist` matrix initially contains direct edges.
        // When `x[n-1]` is added, `k = x[n-1]`. We update `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`.
        // This means `dist` now contains shortest paths using `x[n-1]` as an intermediate.
        // When `x[n-2]` is added, `k = x[n-2]`. We update `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`.
        // This means `dist` now contains shortest paths using `x[n-1]` AND `x[n-2]` as intermediates.
        // This is exactly how Floyd-Warshall works. The `k` in the outermost loop of Floyd-Warshall
        // corresponds to the vertex being "activated" or "considered as an intermediate".
        //
        // So, the single loop `for i, for j, dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`
        // is correct for integrating `k` as the newest intermediate.
        //
        // After this, `dist[i][j]` holds the shortest path between `i` and `j` using any of the
        // currently active vertices (including `k`) as intermediates.

        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                if (dist[i][j] != -1) { // Only sum if path exists
                    current_sum += dist[i][j];
                }
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (before x_1, before x_2, ..., before x_n)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with a small positive integer

    // The maximum number of elements in the array is 10^4.
    // The maximum value of X is 10^9.
    // We need to generate X subsequences.
    // A block of k identical elements contributes 2^k - 1 subsequences.
    // We can use powers of 2 to represent X.
    // For example, if X = 10, we need 10 subsequences.
    // 10 = 8 + 2.
    // We can have a block of 3 elements (2^3-1 = 7 subsequences) and a block of 1 element (2^1-1 = 1 subsequence).
    // This strategy is flawed because if we have multiple blocks, say [v1, v1, v1] and [v2],
    // subsequences like [v1, v2] might violate the condition.
    // The key insight is to make sure that elements from different "blocks" are far apart.

    // Let's use a strategy where we have blocks of identical numbers.
    // For example, [A, A, ..., A] (k times), then [B, B, ..., B] (m times), etc.
    // If A and B are chosen such that B - A >= d, then any subsequence containing both A and B
    // will be discarded.
    // So, we can count subsequences from each block independently.
    // A block of `k` identical numbers `v` contributes `2^k - 1` valid subsequences (all elements are `v`).
    // We can construct `X` by summing up `2^k - 1` terms.
    // For example, if X = 10, we can use `2^3 - 1 = 7` and `2^2 - 1 = 3`.
    // So we need a block of 3 identical numbers and a block of 2 identical numbers.
    // Let's say we have `v1, v1, v1` and `v2, v2`.
    // We need `v2 - v1 >= d`.
    // We can set `v1 = 1`, `v2 = 1 + d`, `v3 = 1 + 2d`, etc.

    // The maximum number of elements is 10^4.
    // The maximum value of X is 10^9.
    // The largest power of 2 less than or equal to 10^9 is 2^29 (approx 5*10^8).
    // So we might need up to 30 blocks.
    // Each block can have up to 60 elements (2^60-1 is huge, but 2^k-1 for k=60 is max for long long).
    // If X = 10^9, and we use 2^k-1 terms, the maximum k is around 30.
    // If we use k=1 for all terms, we need 10^9 elements, which is too many.
    // We need to use larger k values.
    // The maximum k such that 2^k-1 <= X is k approx log2(X).
    // For X=10^9, k approx 29.
    // If we use k=29, we use one block of 29 elements.
    // We can decompose X into sum of (2^k - 1) terms.
    // X = sum(c_i * (2^i - 1)) where c_i is the count of blocks of size i.
    // This is equivalent to decomposing X+1 into sum of 2^i terms.
    // X+1 = sum(c_i * 2^i). This is just the binary representation of X+1.
    // If X+1 = sum(b_i * 2^i) where b_i is 0 or 1, then we need a block of size `i` for each `i` where `b_i=1`.
    // Each such block will contribute `2^i - 1` subsequences.
    // The total number of elements will be sum(i * b_i).
    // For X=10^9, X+1 approx 10^9.
    // The binary representation of 10^9 has about 30 bits.
    // The sum of `i` for `i` up to 29 is `1+2+...+29 = 29*30/2 = 435`.
    // This is well within the 10^4 limit.

    // Algorithm:
    // 1. Iterate through powers of 2, from largest to smallest (or smallest to largest).
    // 2. For each power `2^k`, if `X` is large enough to accommodate `2^k - 1` subsequences,
    //    add a block of `k` elements to our array.
    // 3. These `k` elements will all be `current_val`.
    // 4. After adding the block, subtract `2^k - 1` from `X`.
    // 5. Update `current_val` to `current_val + d` to ensure the next block is sufficiently far apart.
    // 6. Repeat until `X` becomes 0.

    // Max k for 2^k-1 <= 10^9 is k=29 (2^29-1 = 536870911).
    // Max k for 2^k-1 <= 10^18 is k=60 (2^60-1 approx 1.15 * 10^18).
    // We need to iterate k from 1 up to 60 (or 62 for safety with long long).
    // The number of elements in the array should not exceed 10^4.
    // If X = 10^9, X+1 = 1000000001.
    // Binary representation of 1000000001:
    // 111011100110101100101000000001 (30 bits)
    // The sum of indices for set bits: 0+1+... (up to 29).
    // The maximum sum of indices for 2^k-1 terms is for X = 2^N - 1.
    // Then X+1 = 2^N. This means only the N-th bit is set.
    // We add N elements.
    // If X = 2^N - 2, then X+1 = 2^N - 1. All bits from 0 to N-1 are set.
    // We add 0+1+...+(N-1) = N*(N-1)/2 elements.
    // For N=30, this is 30*29/2 = 435 elements. This is well within 10^4.

    // Let's iterate k from 1 to 60.
    for (int k = 1; k <= 60; ++k) {
        // Calculate 2^k - 1.
        // Use 1LL << k to avoid overflow for k >= 31.
        long long num_subsequences_from_k_elements = (1LL << k) - 1;

        // If X is 0, we are done.
        if (X == 0) {
            break;
        }

        // If X is odd, it means we need to add a block that contributes an odd number of subsequences.
        // The only way to get an odd number of subsequences (2^k - 1) is if k=1.
        // If X is odd, we must take a block of size 1.
        // This is equivalent to checking the least significant bit of X.
        // If X & 1 is true, we need to add a block of size 1.
        // This is the standard way to decompose a number into powers of 2 (X = sum b_i * 2^i).
        // Here we are decomposing X into sum of (2^k - 1) terms.
        // This is equivalent to decomposing X+1 into sum of 2^k terms.
        // If (X+1) has k-th bit set, we add a block of size k.
        // (X+1) >> k & 1 checks if the k-th bit of (X+1) is set.

        if (((X + 1) >> k) & 1) { // If the k-th bit of (X+1) is set
            // Add k elements of current_val to the result array
            for (int i = 0; i < k; ++i) {
                result_array.push_back(current_val);
            }
            // Subtract the contribution from X
            // X -= num_subsequences_from_k_elements; // This is implicitly handled by the bit manipulation logic
            // Update current_val for the next block
            current_val += d;
        }
        // If the array size exceeds 10^4, it's an invalid case for this construction.
        // However, based on the analysis above, this should not happen for X <= 10^9.
        if (result_array.size() > 10000) {
            // This case should not be reached with X <= 10^9.
            // But as a safeguard, if it does, print -1.
            std::cout << -1 << std::endl;
            return 0;
        }
    }

    if (result_array.empty()) {
        // This can happen if X=0, but problem states 1 <= X.
        // If X=1, (1+1)>>1 & 1 is true, k=1, adds 1 element.
        // So result_array will never be empty for valid X.
        // If X is very large and we run out of k values, but X is not 0.
        // This means X+1 has a bit set for k > 60.
        // This implies X > 2^60 - 1, which is greater than 10^18.
        // But X is <= 10^9. So this case won't happen.
        std::cout << -1 << std::endl;
    } else {
        std::cout << result_array.size() << std::endl;
        for (size_t i = 0; i < result_array.size(); ++i) {
            std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p; // Use long long for p to avoid overflow during subtractions
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> treated_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        treated_children_ids.push_back(children[i].id);
        children[i].in_line = false; // Mark as treated

        long long current_v_effect = children[i].v;
        long long total_d_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_effect from previous children who cried and left
            children[j].p -= total_d_effect;

            // Apply v_effect from the current child being treated
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect = std::max(0LL, current_v_effect - 1);
            }

            // Check if child j's confidence drops below zero
            if (children[j].p < 0) {
                children[j].in_line = false; // Child j leaves the line
                total_d_effect += children[j].d; // Add child j's d to total_d_effect for subsequent children
            }
        }
    }

    std::cout << treated_children_ids.size() << "\n";
    for (size_t i = 0; i < treated_children_ids.size(); ++i) {
        std::cout << treated_children_ids[i] << (i == treated_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, std::numeric_limits<long long>::max());

    // First pass: Determine upper bounds for initial_a[i]
    // For each type 2 query (2 l r m), we know that for all j in [l, r],
    // initial_a[j] + current_delta[j] <= m.
    // This implies initial_a[j] <= m - current_delta[j].
    // We want to find the tightest upper bound for each initial_a[j].
    std::vector<long long> current_delta(n, 0);
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // If any initial_a[j] is still max_long_long, it means it was never constrained by a type 2 query.
    // We can set it to 0, as 0 is within the allowed range and won't violate any constraints.
    // Or, more generally, any value that satisfies the absolute value constraint.
    // Setting to 0 is simplest.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == std::numeric_limits<long long>::max()) {
            initial_a[i] = 0;
        }
    }

    // Second pass: Verify the solution
    // Simulate all operations with the derived initial_a and check if all conditions are met.
    std::vector<long long> simulated_a = initial_a;
    current_delta.assign(n, 0); // Reset current_delta for simulation

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                simulated_a[j] += ops[i].val;
                current_delta[j] += ops[i].val; // Keep track of delta for type 2 checks
            }
        } else { // type 2
            long long max_val_in_range = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, initial_a[j] + current_delta[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraints for initial_a
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] < -1000000000LL || initial_a[i] > 1000000000LL) {
            // This case should ideally not be reached if the problem constraints are consistent,
            // as m_i values are within 5*10^7 and d_i values are within 10^4.
            // The maximum possible delta is 5000 * 10^4 = 5*10^7.
            // So m_i - delta_j will be roughly in range [-10^8, 10^8], well within 10^9.
            // However, it's good practice to check.
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point that satisfies x[right_ptr] - x[i] <= d

    for (int i = 0; i < n; ++i) {
        // Advance right_ptr until x[right_ptr] - x[i] > d or right_ptr reaches end
        // The condition is x[right_ptr] <= x[i] + d
        while (right_ptr < n && x[right_ptr] <= x[i] + d) {
            right_ptr++;
        }
        // At this point, all points from x[i+1] to x[right_ptr-1] satisfy the condition with x[i]
        // We need to choose two more points from this range.
        // The number of points available to choose from is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let k = right_ptr - 1 - i. These are the points x[i+1], ..., x[right_ptr-1].
        // We need to choose 2 points from these k points.
        // The number of ways to choose 2 points from k points is k * (k - 1) / 2.

        long long num_available_points = right_ptr - 1 - i;

        if (num_available_points >= 2) {
            count += num_available_points * (num_available_points - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_val = elements[0].value;
    long long max_val = elements[n - 1].value;

    long long goodness_case1 = max_val + elements[n - 2].value - (min_val + elements[1].value);
    std::vector<int> partition_case1(n, 1); // All in subsequence 1

    long long goodness_case2 = max_val + elements[n - 2].value + h - (min_val + elements[1].value + h);
    std::vector<int> partition_case2(n, 1); // All in subsequence 1 (or all in 2, same goodness)

    long long goodness_case3 = max_val + min_val + h - (min_val + elements[1].value);
    std::vector<int> partition_case3(n);
    partition_case3[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition_case3[elements[i].original_index] = 2;
    }

    long long goodness_case4 = max_val + elements[n - 2].value + h - (min_val + max_val);
    std::vector<int> partition_case4(n);
    partition_case4[elements[n - 1].original_index] = 1;
    for (int i = 0; i < n - 1; ++i) {
        partition_case4[elements[i].original_index] = 2;
    }

    long long min_goodness = -1;
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence.
    // min_f = min_val + elements[1].value
    // max_f = max_val + elements[n-2].value
    // goodness = max_f - min_f
    min_goodness = goodness_case1;
    best_partition = partition_case1;

    // Case 2: All elements in one subsequence, but h is very large.
    // This is effectively the same as Case 1 for goodness calculation,
    // as all f values are of the form a_i + a_j.
    // The problem statement implies that if h is large, it's better to put all elements in one subsequence.
    // This is already covered by Case 1.

    // Case 3: min_val is in one subsequence, all others in another.
    // min_f = min_val + elements[1].value (from elements[0] and elements[1] being different)
    // max_f = max_val + elements[n-2].value + h (from elements[n-1] and elements[n-2] being same)
    // No, this is wrong.
    // If elements[0] is in S1, and all others in S2:
    // min_f = elements[0].value + elements[1].value + h (from elements[0] and elements[1])
    // max_f = elements[n-1].value + elements[n-2].value (from elements[n-1] and elements[n-2])
    // goodness = max_f - min_f
    // This is not necessarily true.
    // The minimum f value could be elements[1].value + elements[2].value (if n >= 3)
    // The maximum f value could be elements[0].value + elements[n-1].value + h
    // Let's re-evaluate the four critical values for min/max f:
    // A = elements[0].value + elements[1].value (min sum of two smallest)
    // B = elements[n-2].value + elements[n-1].value (max sum of two largest)
    // C = elements[0].value + elements[n-1].value (min + max)

    // Option 1: All in one group (e.g., group 1)
    // min_f = A
    // max_f = B
    // goodness = B - A
    if (min_goodness > B - A) {
        min_goodness = B - A;
        best_partition = partition_case1;
    }

    // Option 2: elements[0] in group 1, all others in group 2.
    // min_f = min(A + h, elements[1].value + elements[2].value (if n>=3))
    // max_f = max(C + h, B)
    // If n=2: elements[0] in S1, elements[1] in S2.
    // min_f = elements[0].value + elements[1].value + h
    // max_f = elements[0].value + elements[1].value + h
    // goodness = 0
    if (n == 2) {
        if (min_goodness > 0) {
            min_goodness = 0;
            best_partition[elements[0].original_index] = 1;
            best_partition[elements[1].original_index] = 2;
        }
    } else { // n >= 3
        long long current_min_f = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
        long long current_max_f = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value);
        if (min_goodness > current_max_f - current_min_f) {
            min_goodness = current_max_f - current_min_f;
            best_partition = partition_case3; // elements[0] in 1, others in 2
        }
    }

    // Option 3: elements[n-1] in group 1, all others in group 2.
    // min_f = min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h)
    // max_f = max(elements[n-2].value + elements[n-1].value + h, elements[n-2].value + elements[n-3].value (if n>=3))
    // If n=2: elements[0] in S2, elements[1] in S1. Same as above, goodness 0.
    if (n >= 3) {
        long long current_min_f = std::min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h);
        long long current_max_f = std::max(elements[n-2].value + elements[n-1].value + h, elements[n-3].value + elements[n-2].value);
        if (min_goodness > current_max_f - current_min_f) {
            min_goodness = current_max_f - current_min_f;
            best_partition = partition_case4; // elements[n-1] in 1, others in 2
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Check for k=1
    // A single cut divides s into P1 and P2.
    // We can form P2P1. We need P2P1 to be a palindrome and P2P1 != s.
    // Since s is already a palindrome, P2P1 != s is the main condition.
    // If P2P1 == s, then P1P2 == P2P1.
    // This implies s is a periodic string with period |P1| or |P2|.
    // Specifically, if P1P2 == P2P1, then s must be of the form XYXY...
    // Or, more simply, if P1P2 == P2P1, then s is a rotation of itself.
    // For a palindrome s, if P1P2 == P2P1, it means s is formed by repeating a shorter palindrome.
    // Example: "abccba" cut "abc|cba". P2P1 = "cbaabc". This is not "abccba".
    // Example: "otto" cut "ot|to". P2P1 = "toot". This is a palindrome and != "otto". So k=1.
    // Example: "ababa" cut "ab|aba". P2P1 = "abaab". This is not "ababa".
    // Example: "aaaaa" cut "aa|aaa". P2P1 = "aaaaa". This is "aaaaa".
    // The only case where P2P1 == s for a palindrome s is if s consists of all identical characters.
    // For example, "aaaaa". If s = "aaaaa", P1 = "aa", P2 = "aaa". P2P1 = "aaaaa".
    // If s is not all identical characters, then P2P1 will be different from s.
    // We need to check if P2P1 is a palindrome.

    // Iterate through all possible cut positions for k=1
    for (int i = 1; i < n; ++i) {
        std::string p1 = s.substr(0, i);
        std::string p2 = s.substr(i);
        std::string s_prime = p2 + p1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // With k=2, we have 3 pieces: P1, P2, P3.
    // We can reorder them.
    // The problem statement implies that if a solution exists, k=1 or k=2.
    // This is because if s is a palindrome, and not all characters are the same,
    // then a single cut in the middle (if N is even) or near the middle
    // often allows forming a new palindrome.
    // If s consists of all identical characters (e.g., "qqqq"), then no reordering
    // of any number of pieces will ever produce a different string.
    // In this case, the answer is "Impossible".
    // We need to check if all characters in s are the same.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 must be the answer.
        // Why k=2 is always possible if not all characters are the same?
        // Consider s = "nolon". k=1 doesn't work.
        // P1="no", P2="l", P3="on". Reorder to "onlno". This is a palindrome and != "nolon".
        // This requires 2 cuts.
        // The problem statement guarantees that if a solution exists, it's 1 or 2.
        // The only case where no solution exists is if all characters are the same.
        // If s is a palindrome and not all characters are the same,
        // then s must have at least two distinct characters.
        // For example, "abacaba".
        // If N is odd, s[0]...s[N/2-1] s[N/2] s[N/2+1]...s[N-1]
        // The first half s[0...N/2-1] is not all identical characters (otherwise s would be).
        // Take s[0...N/2-1]. This substring is not a palindrome itself (unless N=1 or N=2).
        // If s is a palindrome and not all characters are the same,
        // then the first half of s (excluding the middle character if N is odd)
        // cannot be a string of all identical characters.
        // For example, if s = "abacaba", first half is "aba".
        // If s = "racecar", first half is "rac".
        // If s = "level", first half is "le".
        // If s = "madam", first half is "ma".
        // If s = "noon", first half is "no".
        // If s = "otto", first half is "ot".
        // If s = "kinnikkinnik", first half is "kinnik".
        // The first half of s (s.substr(0, n/2)) is not a palindrome itself,
        // unless n/2 is 0 or 1.
        // If s.substr(0, n/2) is not a palindrome, then its reverse is different.
        // Let s_half = s.substr(0, n/2).
        // If s_half is not a palindrome, then s_half != reverse(s_half).
        // Consider the string s_half + s[n/2] + reverse(s_half) (if n is odd)
        // or s_half + reverse(s_half) (if n is even).
        // This is the original string s.
        // If s_half is not a palindrome, then s_half != reverse(s_half).
        // This means that s is not formed by repeating a single character.
        // If s is a palindrome and not all characters are the same,
        // then the string s.substr(0, n/2) cannot be a palindrome itself.
        // (Unless n/2 is 0 or 1, i.e., n is 0, 1, 2, 3).
        // For n=1, "a", impossible.
        // For n=2, "aa", impossible.
        // For n=3, "aba", s.substr(0,1) = "a", which is a palindrome.
        // For n=4, "abba", s.substr(0,2) = "ab", not a palindrome.
        // For n=5, "abcba", s.substr(0,2) = "ab", not a palindrome.
        // If s.substr(0, n/2) is not a palindrome, then we can always make 2 cuts.
        // Cut s into s.substr(0, n/2), s.substr(n/2, n%2), s.substr(n/2 + n%2).
        // Example: "nolon", n=5. s.substr(0,2)="no", s.substr(2,1)="l", s.substr(3)="on".
        // Pieces: "no", "l", "on".
        // Reorder to "on", "l", "no" -> "onlno". This is a palindrome and != "nolon".
        // This is always possible if s is a palindrome and not all characters are the same.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
