// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// The sum can exceed 2^31-1.
// x will always be within [0, n+1] range, so int is fine for x.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1); // a[0] is unused, a[1] will be set for each run
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    // dp_y[i] stores the total y accumulated when starting at x=i and performing the first step (x+a_i, y+a_i)
    // and then the second step (x-a_i, y+a_i), and then continuing from the new x.
    // dp_y[i] = a_i + a_i + result_from_new_x
    // dp_y[i] = 2 * a_i + result_from_new_x
    // dp_parity[i] stores the parity of the x value when we land on x=i.
    // If x_start is odd, then x_start + a_x is even, x_start + a_x - a_x is odd.
    // If x_start is even, then x_start + a_x is odd, x_start + a_x - a_x is even.
    // This means the parity of x flips after each full (step 2, step 3) cycle.
    // However, the problem states that a_x is used for both steps.
    // Let's re-evaluate the parity.
    // Start: (x_0, y_0)
    // Step 2: (x_0 + a[x_0], y_0 + a[x_0])
    // Step 3: (x_0 + a[x_0] - a[x_0 + a[x_0]], y_0 + a[x_0] + a[x_0 + a[x_0]])
    // The new x is x_0 + a[x_0] - a[x_0 + a[x_0]].
    // The parity of this new x depends on a[x_0] and a[x_0 + a[x_0]].
    // This is not a simple flip.

    // The problem is that a_x is used for both steps.
    // Let's denote the current x as `curr_x`.
    // Step 2: `val1 = a[curr_x]`. New state: `(curr_x + val1, y_curr + val1)`.
    // Let `next_x_after_step2 = curr_x + val1`.
    // Step 3: `val2 = a[next_x_after_step2]`. New state: `(next_x_after_step2 - val2, y_curr + val1 + val2)`.
    // This is the crucial part. The `a_x` in step 3 refers to `a` at the `x` *after* step 2.

    // We need to compute results for a_1 = 1, 2, ..., n-1.
    // This suggests dynamic programming or memoization.
    // Let `solve(current_x, current_y_offset, initial_a1)` be the function that returns the final y.
    // `current_y_offset` is the y accumulated so far.
    // The state for DP should be `(x, parity_of_a_x_used_in_step2)`.
    // The parity of `a_x` matters because `x + a_x` and `x - a_x` depend on it.
    // If `a_x` is even, `x` parity doesn't change. If `a_x` is odd, `x` parity flips.

    // Let's define `dp[x][parity]` as the pair `{final_y_contribution, final_x_parity}`
    // when starting at `x` with `a[x]` having `parity`.
    // This is getting complicated. A simpler DP approach might be:
    // `dp[x]` stores the result if we start at `x` and `a[x]` is the value used for the first step.
    // `dp[x]` will store `(total_y_added, final_x_value)` or just `total_y_added` if `x` terminates.
    // The issue is that `a[x]` is not fixed for `x=1`.

    // The problem is that `a_1` changes for each run.
    // For `x > 1`, `a_x` is fixed.
    // Let `dp[x]` be the total `y` accumulated from `x` until termination, assuming `x` is the `x` *after* step 2.
    // So, if we are at `x_curr`, we calculate `val1 = a[x_curr]`.
    // Then `next_x_after_step2 = x_curr + val1`.
    // If `next_x_after_step2` is out of bounds, `y_final = y_curr + val1`.
    // Otherwise, `val2 = a[next_x_after_step2]`.
    // `next_x_after_step3 = next_x_after_step2 - val2`.
    // If `next_x_after_step3` is out of bounds, `y_final = y_curr + val1 + val2`.
    // Otherwise, we need to continue from `next_x_after_step3`.

    // This looks like a standard DP on states `(x, parity_of_a_x_used_in_step2)`.
    // The parity of `a_x` is not fixed for `x=1`.
    // For `x > 1`, `a_x` is fixed.
    // Let `dp[x][0]` be the result if we arrive at `x` and the `a[x]` used for step 2 is even.
    // Let `dp[x][1]` be the result if we arrive at `x` and the `a[x]` used for step 2 is odd.
    // The `a[x]` value itself is fixed for `x > 1`. So `a[x]` has a fixed parity.
    // This means `dp[x][a[x]%2]` is the only relevant state for `x > 1`.
    // For `x=1`, we need to compute for `a[1]` being `i`.

    // Let `memo[x]` store the result for starting at `x` (after step 3).
    // `memo[x]` will store a pair: `{total_y_added_from_this_point, final_x_value_if_terminates_in_bounds}`
    // Or, more simply, `memo[x]` stores `(total_y_added, final_x_value)` if it terminates, or `(-1, -1)` if it loops.
    // We can compute this for `x` from `n` down to `1`.
    // `memo[x]` will store `(y_sum, final_x)` for the sequence starting at `x` and performing one full cycle (step 2, step 3).
    // This is not quite right. `memo[x]` should store the total `y` accumulated from `x` until termination.

    // Let `dp[x]` be the pair `(total_y_added, final_x_position)` if starting at `x` and performing one full cycle (step 2, step 3).
    // `dp[x]` will be computed for `x` from `2` to `n`.
    // `dp[x].first` is the `y` added in one cycle.
    // `dp[x].second` is the `x` after one cycle.
    // If `x` goes out of bounds during the cycle, `dp[x].second` will be `0` or `n+1`.
    // We need to handle cycles.

    // Let `memo[x]` store the final `y` value if the program starts at `x` (after step 3) and terminates.
    // `memo[x] = -1` if it loops.
    // We can compute `memo[x]` for `x` from `n` down to `1`.
    // For `x` from `n` down to `1`:
    //   `val1 = a[x]`
    //   `x_after_step2 = x + val1`
    //   If `x_after_step2 <= 0` or `x_after_step2 > n`:
    //     `memo[x] = val1`
    //   Else:
    //     `val2 = a[x_after_step2]`
    //     `x_after_step3 = x_after_step2 - val2`
    //     If `x_after_step3 <= 0` or `x_after_step3 > n`:
    //       `memo[x] = val1 + val2`
    //     Else:
    //       // Now we need to continue from `x_after_step3`.
    //       // This is where DP comes in.
    //       // `memo[x] = val1 + val2 + memo[x_after_step3]`
    //       // But `memo[x_after_step3]` might not be computed yet if `x_after_step3 > x`.
    //       // This means we need to use recursion with memoization.

    // Let's use recursion with memoization.
    // `memo[x]` stores the final `y` value if the program starts at `x` (after step 3) and terminates.
    // `visited[x]` to detect cycles.
    // `a[1]` is not fixed, so we can't precompute `memo[1]`.
    // We can precompute `memo[x]` for `x` from `2` to `n`.

    std::vector<long long> memo(n + 1, -2); // -2 indicates not computed, -1 indicates loop
    std::vector<bool> visiting(n + 1, false); // To detect cycles

    // Function to calculate the total y from a given starting x (after step 3)
    // and the value of a[x] that was used for the *previous* step 2.
    // This is not quite right. The `a[x]` value is fixed for `x > 1`.
    // The `a[x]` value for `x=1` is the `i` from the problem statement.

    // Let's define `calculate_y(current_x)`:
    // This function returns the total `y` accumulated from `current_x` until termination.
    // `current_x` is the `x` value *after* a step 3.
    // The `a` array is fixed for `x > 1`.
    // For `x=1`, `a[1]` is set to `i`.

    // We need to compute for `a[1] = i` for `i = 1 to n-1`.
    // For each `i`:
    //   Set `a[1] = i`.
    //   Call `solve(1, 0)` where `solve(x, y_accumulated)` returns final `y`.

    // `solve(x, y_accumulated)`:
    //   If `x <= 0` or `x > n`, return `y_accumulated`.
    //   `val1 = a[x]`
    //   `y_after_step2 = y_accumulated + val1`
    //   `x_after_step2 = x + val1`
    //   If `x_after_step2 <= 0` or `x_after_step2 > n`, return `y_after_step2`.
    //   `val2 = a[x_after_step2]`
    //   `y_after_step3 = y_after_step2 + val2`
    //   `x_after_step3 = x_after_step2 - val2`
    //   If `x_after_step3 <= 0` or `x_after_step3 > n`, return `y_after_step3`.
    //   Recursively call `solve(x_after_step3, y_after_step3)`.

    // This recursive approach will be too slow for `n=2*10^5` if we don't memoize.
    // The state for memoization needs to be `(x, a[1])`. This is `N * N` states, too many.

    // The key observation is that for `x > 1`, `a[x]` is fixed.
    // For `x=1`, `a[1]` is `i`.
    // Let `dp[x][parity_of_a_x]` be the result.
    // `dp[x][0]` for `a[x]` even, `dp[x][1]` for `a[x]` odd.
    // This is still not quite right. The `a[x]` value itself matters, not just its parity.

    // Let's analyze the transitions:
    // `(x, y)` -> `(x + a[x], y + a[x])` -> `(x + a[x] - a[x + a[x]], y + a[x] + a[x + a[x]])`
    // Let `f(x) = x + a[x] - a[x + a[x]]` be the next `x` value.
    // Let `g(x) = a[x] + a[x + a[x]]` be the `y` added in one full cycle.
    // We are looking for `y_final = sum(g(x_k))` where `x_0 = 1`, `x_{k+1} = f(x_k)`.

    // For `x > 1`, `f(x)` and `g(x)` are fixed.
    // We can precompute `f(x)` and `g(x)` for `x` from `2` to `n`.
    // Let `next_x[x]` be `f(x)` and `y_add[x]` be `g(x)`.
    // We can use DP to find the total `y` and final `x` for `x > 1`.
    // `memo[x]` stores `(total_y_from_x, final_x_from_x)`
    // `memo[x].first` is the sum of `g` values.
    // `memo[x].second` is the final `x` value.
    // If `x` goes out of bounds, `memo[x].second` will be `0` or `n+1`.
    // If `x` enters a cycle, `memo[x].second` will be `-1`.

    std::vector<std::pair<long long, int>> memo_fixed(n + 1, {-2, -2}); // {-2,-2} not computed, {-1,-1} loop
    std::vector<bool> visiting_fixed(n + 1, false);

    // Recursive function to compute memo_fixed[x] for x > 1
    // Returns {total_y_added, final_x_position}
    std::pair<long long, int> compute_fixed(int x) {
        if (x <= 0 || x > n) {
            return {0, x}; // Base case: out of bounds, 0 y added from this point
        }
        if (memo_fixed[x].first != -2) {
            return memo_fixed[x]; // Already computed
        }
        if (visiting_fixed[x]) {
            return memo_fixed[x] = {-1, -1}; // Cycle detected
        }

        visiting_fixed[x] = true;

        long long val1 = a[x];
        int x_after_step2 = x + val1;

        if (x_after_step2 <= 0 || x_after_step2 > n) {
            visiting_fixed[x] = false;
            return memo_fixed[x] = {val1, x_after_step2};
        }

        long long val2 = a[x_after_step2];
        int x_after_step3 = x_after_step2 - val2;

        std::pair<long long, int> res_from_next = compute_fixed(x_after_step3);

        visiting_fixed[x] = false;

        if (res_from_next.first == -1) { // Loop detected downstream
            return memo_fixed[x] = {-1, -1};
        } else {
            return memo_fixed[x] = {val1 + val2 + res_from_next.first, res_from_next.second};
        }
    }

    // Precompute for x from 2 to n
    for (int i = 2; i <= n; ++i) {
        if (memo_fixed[i].first == -2) {
            compute_fixed(i);
        }
    }

    // Now, for each query (a[1] = i)
    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a[1] for the current run

        long long current_y = 0;
        int current_x = 1;

        // Simulate the first full cycle (step 2, step 3)
        // This part cannot use memo_fixed directly because a[1] is variable.

        long long val1 = a[current_x];
        current_y += val1;
        int x_after_step2 = current_x + val1;

        if (x_after_step2 <= 0 || x_after_step2 > n) {
            std::cout << current_y << "\n";
            continue;
        }

        long long val2 = a[x_after_step2];
        current_y += val2;
        int x_after_step3 = x_after_step2 - val2;

        if (x_after_step3 <= 0 || x_after_step3 > n) {
            std::cout << current_y << "\n";
            continue;
        }

        // Now we are at x_after_step3, and we can use memo_fixed if x_after_step3 > 1.
        // If x_after_step3 == 1, it's a special case because a[1] is variable.
        // This means we might enter a cycle involving x=1.

        // To handle cycles involving x=1, we need to detect them during the simulation.
        // We can use a `visited_path` set or vector for the current run.
        // However, the problem states that `x` starts at `1`.
        // The `x` values are `1 -> x_after_step3 -> f(x_after_step3) -> ...`
        // If `x_after_step3` is `1`, then we are in a cycle `1 -> 1`.
        // If `x_after_step3` is `k > 1`, and `f(k)` eventually leads back to `1`, it's also a cycle.

        // Let's re-think the structure.
        // For each `i` (a[1]):
        //   `x = 1`, `y = 0`
        //   `path_x` stores `x` values visited in this run.
        //   `path_y` stores `y` values accumulated at each `x` in this run.
        //   `path_idx` maps `x` to its index in `path_x`.
        //   Loop:
        //     If `x <= 0` or `x > n`, print `y` and break.
        //     If `x` is in `path_idx`: print `-1` and break (cycle).
        //     Add `x` to `path_x`, `y` to `path_y`, `path_idx[x] = current_path_length`.
        //     `val1 = a[x]`
        //     `y += val1`
        //     `x += val1`
        //     If `x <= 0` or `x > n`, print `y` and break.
        //     `val2 = a[x]`
        //     `y += val2`
        //     `x -= val2`
        // This is too slow. `N` runs, each `N` steps. `N^2` total.

        // The `memo_fixed` approach is correct for `x > 1`.
        // For `x=1`, we have `a[1] = i`.
        // `x_0 = 1`.
        // `y_0 = 0`.
        // `val1_0 = a[1]`.
        // `y_1 = y_0 + val1_0`.
        // `x_1 = x_0 + val1_0`.
        // If `x_1` is out of bounds, `y_final = y_1`.
        // Else:
        //   `val2_0 = a[x_1]`.
        //   `y_2 = y_1 + val2_0`.
        //   `x_2 = x_1 - val2_0`.
        //   If `x_2` is out of bounds, `y_final = y_2`.
        //   Else:
        //     Now we are at `(x_2, y_2)`.
        //     If `x_2 == 1`: This is a cycle `1 -> 1`. Output `-1`.
        //     If `x_2 > 1`: We can use `memo_fixed[x_2]`.
        //       `res = memo_fixed[x_2]`.
        //       If `res.first == -1` (loop), output `-1`.
        //       Else, output `y_2 + res.first`.

        // This logic seems sound.
        // The only remaining edge case is if `x_2` is `1` and `a[1]` is such that it leads back to `1`.
        // Example: `n=3`, `a_2=1, a_3=2`.
        // For `i=1`: `a[1]=1`.
        // `x=1, y=0`.
        // `val1 = a[1] = 1`. `y=1`, `x=1+1=2`.
        // `val2 = a[2] = 1`. `y=1+1=2`, `x=2-1=1`.
        // Now `x=1`. This is a cycle. Output `-1`.
        // This is correctly handled by `if (x_2 == 1)`.

        long long current_y_val = 0;
        int current_x_val = 1;

        long long val1 = a[current_x_val];
        current_y_val += val1;
        int x_after_step2 = current_x_val + val1;

        if (x_after_step2 <= 0 || x_after_step2 > n) {
            std::cout << current_y_val << "\n";
            continue;
        }

        long long val2 = a[x_after_step2];
        current_y_val += val2;
        int x_after_step3 = x_after_step2 - val2;

        if (x_after_step3 <= 0 || x_after_step3 > n) {
            std::cout << current_y_val << "\n";
            continue;
        }

        // Now we are at (x_after_step3, current_y_val)
        // If x_after_step3 is 1, it means we returned to the starting point (x=1)
        // after one full cycle. Since a[1] is fixed for this run, this is an infinite loop.
        if (x_after_step3 == 1) {
            std::cout << -1 << "\n";
            continue;
        }

        // If x_after_step3 > 1, we can use the precomputed memo_fixed values.
        std::pair<long long, int> res_from_next = memo_fixed[x_after_step3];

        if (res_from_next.first == -1) { // Loop detected downstream
            std::cout << -1 << "\n";
        } else {
            std::cout << current_y_val + res_from_next.first << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for target tracks
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All target tracks covered
            return true;
        }

        long long current_h = h[h_idx];

        // Find the first target track p[p_idx] that can be reached by current_h
        // i.e., abs(current_h - p[p_idx]) <= T
        // This means p[p_idx] must be in [current_h - T, current_h + T]
        // Since p is sorted, we can skip tracks that are too far to the left.
        while (p_idx < m && p[p_idx] < current_h - T) {
            p_idx++;
        }

        if (p_idx == m) { // All target tracks covered, or remaining are too far left
            return true;
        }

        // If current_h can reach p[p_idx], then it can cover a range of tracks
        // starting from p[p_idx] up to current_h + T.
        // The head can move to p[p_idx] and then sweep right.
        // The time taken to reach p[p_idx] is abs(current_h - p[p_idx]).
        // The remaining time is T - abs(current_h - p[p_idx]).
        // So, the head can cover tracks up to p[p_idx] + (T - abs(current_h - p[p_idx])).
        // This simplifies to max(current_h, p[p_idx]) + (T - abs(current_h - p[p_idx]))
        // which is equivalent to current_h + T if current_h >= p[p_idx]
        // and p[p_idx] + T if current_h < p[p_idx]
        // More simply, the rightmost track it can cover is current_h + T.
        // However, if it moves left to p[p_idx], it can then sweep right.
        // The total distance it can cover is T.
        // If it moves to p[p_idx], it uses abs(current_h - p[p_idx]) time.
        // It can then cover tracks up to p[p_idx] + (T - abs(current_h - p[p_idx])).

        // The actual range covered by a head h_i is [h_i - T, h_i + T].
        // We need to cover p[p_idx], p[p_idx+1], ...
        // If h_i covers p[p_idx], it can also cover other tracks to its right.
        // The rightmost track it can cover is p[p_idx] + (T - abs(h_i - p[p_idx])).
        // Let's call this `max_reachable_right`.
        // We need to find the largest `p_k` such that `p_k <= max_reachable_right`.
        // And then advance `p_idx` past `p_k`.

        if (p[p_idx] > current_h + T) {
            // This head cannot reach p[p_idx]
            // Since h is sorted, subsequent heads might be able to.
            // But if this head cannot reach it, and we are trying to cover p[p_idx] with it,
            // it means this head is too far left.
            // This should not happen if the while loop above is correct.
            // The while loop ensures p[p_idx] >= current_h - T.
            // So if p[p_idx] > current_h + T, then current_h - T <= p[p_idx] > current_h + T.
            // This means p[p_idx] is outside the range [current_h - T, current_h + T].
            // This head cannot cover p[p_idx].
            // This implies that the current head cannot cover the current target track.
            // Since heads are sorted, and target tracks are sorted,
            // if h_idx cannot cover p_idx, then h_idx-1 also cannot.
            // This means we need to use a head h_k (k > h_idx) to cover p_idx.
            // But our greedy strategy is to use the current head h_idx for p_idx.
            // If it can't, then we fail.
            // This is the core of the greedy check.
            return false;
        }

        // If we reach here, current_h can cover p[p_idx].
        // Now, find how many subsequent tracks it can cover.
        // The head moves to p[p_idx]. Time used: abs(current_h - p[p_idx]).
        // Remaining time: T_rem = T - abs(current_h - p[p_idx]).
        // From p[p_idx], it can sweep right up to p[p_idx] + T_rem.
        long long max_covered_right = p[p_idx] + (T - std::abs(current_h - p[p_idx]));

        // Advance p_idx past all tracks covered by current_h
        while (p_idx < m && p[p_idx] <= max_covered_right) {
            p_idx++;
        }
    }
    return p_idx == m; // All target tracks must be covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // Max possible time: distance from first head to last track, or last head to first track.
    // Or simply, max(p_m - h_1, h_n - p_1) if n=1.
    // A safe upper bound is the maximum possible coordinate value (10^10).
    // Or, the distance between the furthest head and furthest track.
    // max(abs(h[0] - p[m-1]), abs(h[n-1] - p[0]))
    long long high = std::max(std::abs(h[0] - p[m-1]), std::abs(h[n-1] - p[0]));
    // A tighter upper bound could be max(p[m-1] - p[0], h[n-1] - h[0]) + max(p[m-1]-h[n-1], h[0]-p[0])
    // But 2 * 10^10 is a safe upper bound.
    high = std::max(high, 20000000000LL); // Ensure it's large enough for any case.

    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

