#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;
    int count_n = 0;

    for (char c : s) {
        if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        } else if (c == 'n') {
            count_n++;
        }
    }

    // To form 'one': requires 'o', 'n', 'e'
    // To form 'zero': requires 'z', 'e', 'r', 'o'

    // Prioritize 'one's to maximize the binary number
    int num_ones = count_n; // 'n' is unique to 'one' among the letters 'o', 'n', 'e', 'z', 'r'
                            // 'o' and 'e' are shared with 'zero'.
                            // So, the number of 'one's is limited by 'n'.
                            // If we have 'n' 'n's, we can form at most 'n' 'one's.
                            // This will consume 'n' 'o's and 'n' 'e's.

    int num_zeros = 0;
    if (count_o >= num_ones && count_e >= num_ones) {
        // After forming num_ones, remaining letters for 'zero':
        // 'o': count_o - num_ones
        // 'e': count_e - num_ones
        // 'z': count_z
        // 'r': count_r
        num_zeros = std::min({count_z, count_e - num_ones, count_r, count_o - num_ones});
    } else {
        // This case should not happen based on problem constraints
        // "It is guaranteed that it is possible to rearrange the letters in such a way that they form a sequence of words"
        // This implies that the counts will always be sufficient for some combination.
        // However, if 'n' is the limiting factor for 'one's, then count_o and count_e must be at least num_ones.
        // If count_n is 0, num_ones is 0. Then num_zeros is min(count_z, count_e, count_r, count_o).
        // If count_n > 0, then num_ones > 0.
        // The problem guarantees that a valid arrangement exists.
        // The logic for num_ones = count_n is correct because 'n' is only used in 'one'.
        // Any 'n' must correspond to an 'one'.
        // The remaining 'o', 'e', 'z', 'r' must form 'zero's.
        num_zeros = std::min({count_z, count_e - num_ones, count_r, count_o - num_ones});
    }


    bool first = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first) {
            std::cout << " ";
        }
        std::cout << 1;
        first = false;
    }
    for (int i = 0; i < num_zeros; ++i) {
        if (!first) {
            std::cout << " ";
        }
        std::cout << 0;
        first = false;
    }
    std::cout << std::endl;

    return 0;
}

