#include <iostream>
#include <algorithm> // For std::max
#include <cmath>     // For std::ceil, though integer division can be used

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k sticks and k coal.
        // To get k coal, we need k * y sticks. Each coal trade costs 1 trade.
        // So, k coal trades will cost k * y sticks and k trades.
        // Total sticks required for both coal and torches: k * y + k.
        long long total_sticks_needed = k * y + k;

        // We start with 1 stick.
        // We need to acquire (total_sticks_needed - 1) additional sticks.
        long long sticks_to_acquire = total_sticks_needed - 1;

        // Each stick trade (1 stick for x sticks) gives a net gain of (x - 1) sticks.
        // Number of stick trades needed: ceil(sticks_to_acquire / (x - 1)).
        // Using integer division for ceil: (a + b - 1) / b
        long long num_stick_trades = (sticks_to_acquire + (x - 1) - 1) / (x - 1);

        // Total trades = trades for sticks + trades for coal.
        // Trades for coal is simply k.
        long long total_trades = num_stick_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

