#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);
    bool found_n = false;

    for (int i = 0; i < n; ++i) {
        int max_val_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) {
                max_val_row = std::max(max_val_row, a[i][j]);
            }
        }
        p[i] = max_val_row;
        if (p[i] == n) {
            found_n = true;
        }
    }

    if (!found_n) {
        // If no p[i] is n, it means n was never the minimum of any pair.
        // This implies that the actual value n was assigned to some p[k],
        // and for all j != k, p[j] < n.
        // In this case, p[k] would be max(p[j] for j!=k) which is max_val_row.
        // Since p[k] is n, and all other p[j] are less than n,
        // max_val_row for p[k] would be max(p[j]) which is less than n.
        // So, if n is not found in any p[i] (which are currently max_val_row),
        // it means the actual value n must be assigned to some p[k]
        // where p[k] is currently max_val_row, and we need to increment it.
        // The problem guarantees a solution exists.
        // This happens when the true p[k] = n, and all other p[j] < n.
        // Then for this k, max_{j!=k} min(p[k], p[j]) = max_{j!=k} min(n, p[j]) = max_{j!=k} p[j].
        // This max_{j!=k} p[j] would be the largest value among 1 to n-1.
        // So, one of the p[i] values (which are max_val_row) must be n-1.
        // We find the first such p[i] and increment it to n.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

