#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_r_pos = -1, it means the frog is at cell 0.
                             // If last_r_pos = k, it means the frog is at cell k.

        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed).
                // The previous 'R' or start was at last_r_pos (0-indexed).
                // The gap is (i+1) - (last_r_pos + 1) = i - last_r_pos.
                // Or, more simply, the distance from the previous safe spot (last_r_pos)
                // to the current safe spot (i+1) is (i+1) - (last_r_pos + 1) + 1 = i - last_r_pos.
                // No, it's the distance between the indices.
                // If last_r_pos is -1 (start at 0), and current 'R' is at index i (cell i+1).
                // The distance is (i+1) - 0 = i+1.
                // If last_r_pos is k (cell k+1), and current 'R' is at index i (cell i+1).
                // The distance is (i+1) - (k+1) = i - k.
                max_gap = std::max(max_gap, i - last_r_pos);
                last_r_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R'
        // (or cell 0 if no 'R's) to the target cell n+1.
        // The last 'R' was at index last_r_pos (cell last_r_pos + 1).
        // The target is cell n+1.
        // The distance is (n+1) - (last_r_pos + 1) = n - last_r_pos.
        max_gap = std::max(max_gap, (int)s.length() - last_r_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

