#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_values;
    std::vector<int> available_small_values;

    p[0] = q[0];
    used_values.insert(q[0]);

    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            p[i] = q[i];
            if (used_values.count(q[i])) {
                // This should not happen if q is valid, as q_i > q_{i-1} implies q_i is a new max.
                // But as a safety check or for invalid inputs.
                std::cout << -1 << "\n";
                return;
            }
            used_values.insert(q[i]);
            // Add all numbers between q[i-1] and q[i] (exclusive) to available_small_values
            for (int j = q[i-1] + 1; j < q[i]; ++j) {
                available_small_values.push_back(j);
            }
        } else { // q[i] == q[i-1]
            // p[i] must be a value smaller than q[i] and not yet used.
            // We prioritize using the largest available small value to keep options open for later.
            if (available_small_values.empty()) {
                std::cout << -1 << "\n";
                return;
            }
            p[i] = available_small_values.back();
            available_small_values.pop_back();
            used_values.insert(p[i]); // Mark as used
        }
    }

    // Final check for distinctness and range (1 to n)
    // The construction ensures distinctness and values <= n.
    // We just need to ensure all values 1 to n are used exactly once.
    // The `used_values` set should contain exactly `n` elements.
    // And all `p_i` must be within [1, n].
    // The construction ensures p_i <= q_i <= n.
    // The construction ensures p_i >= 1 (as available_small_values only contains positive integers).
    // The only remaining check is if all numbers 1 to n are used.
    // This is implicitly handled by checking if `used_values.size() == n`.
    // If `used_values.size() < n`, it means some numbers from 1 to n were not used,
    // which implies some `p_i` must have been outside [1, n] or duplicated,
    // but our construction logic prevents that.
    // The only way `used_values.size() < n` could happen is if `available_small_values` was empty
    // when it shouldn't have been, leading to -1.
    // Or if `q_i` values themselves are invalid (e.g., `q_i` is repeated but not `p_i`).
    // The problem guarantees `q_i` is valid for *some* permutation.
    // So, if we reach here, the constructed `p` should be valid.

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
