#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the 0-indexed position of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int min_idx = pos[1];
    int max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, min_idx and max_idx are already set to pos[1].
        // For m > 1, we need to update min_idx and max_idx to include pos[m].
        if (m > 1) {
            min_idx = std::min(min_idx, pos[m]);
            max_idx = std::max(max_idx, pos[m]);
        }

        // A number m is beautiful if the subarray p[min_idx...max_idx]
        // contains exactly m elements (i.e., its length is m)
        // and its elements are 1, 2, ..., m.
        // The elements 1, ..., m are guaranteed to be within p[min_idx...max_idx]
        // by how min_idx and max_idx are updated.
        // We just need to check if the length of this subarray is m.
        if (max_idx - min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

