#include <iostream>
#include <string>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, int> counts;
    for (char c : s) {
        counts[c]++;
    }

    int horizontal_moves = std::min(counts['L'], counts['R']);
    int vertical_moves = std::min(counts['U'], counts['D']);

    if (horizontal_moves == 0 && vertical_moves == 0) {
        std::cout << 0 << std::endl << std::endl;
        return;
    }

    if (horizontal_moves == 0) { // Only vertical moves possible
        // To form a valid path, we need at least one U and one D.
        // If we only have U or only D, we can't return to (0,0).
        // If we have both, we can form "UD" or "DU".
        // The problem states "visits no cell (except (0,0)) twice".
        // If we have only vertical moves, e.g., UUDD, (0,1) is visited twice.
        // The only way to avoid this is to have exactly one U and one D.
        // So, if horizontal_moves is 0, we can only use "UD" or "DU".
        // This means vertical_moves must be at least 1.
        // If vertical_moves is 0, it's already handled by the first if.
        // So if horizontal_moves is 0 and vertical_moves > 0, we can only use 2 moves.
        std::cout << 2 << std::endl;
        std::cout << "UD" << std::endl;
        return;
    }

    if (vertical_moves == 0) { // Only horizontal moves possible
        // Similar to the vertical case, we can only use "LR" or "RL".
        // This means horizontal_moves must be at least 1.
        // If horizontal_moves is 0, it's already handled by the first if.
        // So if vertical_moves is 0 and horizontal_moves > 0, we can only use 2 moves.
        std::cout << 2 << std::endl;
        std::cout << "LR" << std::endl;
        return;
    }

    // If both horizontal_moves > 0 and vertical_moves > 0
    // We can construct a path like U...ULL...LR...RD...D
    // The maximum length is 2 * horizontal_moves + 2 * vertical_moves
    std::cout << 2 * horizontal_moves + 2 * vertical_moves << std::endl;
    std::string result = "";
    for (int i = 0; i < vertical_moves; ++i) result += 'U';
    for (int i = 0; i < horizontal_moves; ++i) result += 'L';
    for (int i = 0; i < vertical_moves; ++i) result += 'D';
    for (int i = 0; i < horizontal_moves; ++i) result += 'R';
    std::cout << result << std::endl;
}

