    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i-1]
    // This marks the end of the initial non-decreasing suffix
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }

    // Now `a[i...n-1]` is non-decreasing.
    // If `i` is 0, the whole array is non-decreasing, so it's good.
    // If `i` is not 0, then `a[i-1] > a[i]`.

    // Find the rightmost index `j` such that a[j] > a[j-1]
    // This marks the end of the initial non-increasing suffix (from `i-1` backwards)
    // We start from `i` because `a[i...n-1]` is already non-decreasing.
    // We are looking for the point where the sequence stops being non-increasing
    // when moving left from `i-1`.
    int j = i;
    while (j > 0 && a[j-1] >= a[j]) {
        j--;
    }

    // The prefix to remove is `a[0...j-1]`.
    // The remaining suffix is `a[j...n-1]`.
    // This suffix `a[j...n-1]` is guaranteed to be good.
    // Why?
    // From `j` to `i-1`, the elements are non-increasing: `a[j] >= a[j+1] >= ... >= a[i-1]`.
    // From `i` to `n-1`, the elements are non-decreasing: `a[i] <= a[i+1] <= ... <= a[n-1]`.
    //
    // The combined suffix `a[j...n-1]` has the form:
    // `[non-increasing part] [non-decreasing part]`
    // Example: `[5, 4, 3, 2, 3]` (n=5)
    // i = 4 (a[3]=2, a[4]=3, a[3] <= a[4])
    // i = 3 (a[2]=3, a[3]=2, a[2] > a[3]) -> stop. i=3. Suffix `[2,3]` is non-decreasing.
    // Now j starts from i=3.
    // j = 3 (a[2]=3, a[3]=2, a[2] >= a[3])
    // j = 2 (a[1]=4, a[2]=3, a[1] >= a[2])
    // j = 1 (a[0]=5, a[1]=4, a[0] >= a[1])
    // j = 0 (stop). j=0.
    //
    // The remaining suffix is `a[j...n-1]`.
    // This structure `[non-increasing part] [non-decreasing part]` is exactly what makes an array "good".
    // We can pick elements from the ends:
    // 1. Pick from the left (non-increasing part) until we reach the minimum of that part.
    // 2. Pick from the right (non-decreasing part) until we reach the minimum of that part.
    // 3. The remaining elements will be the minimums of the two parts, or the elements around the "valley".
    //
    // More formally, to make `c` non-decreasing:
    // We can take elements from the right end (`a[n-1], a[n-2], ...`) as long as they are greater than or equal to the last element added to `c`.
    // We can take elements from the left end (`a[j], a[j+1], ...`) as long as they are greater than or equal to the last element added to `c`.
    //
    // The crucial observation is that the elements `a[j], ..., a[i-1]` are non-increasing, and `a[i], ..., a[n-1]` are non-decreasing.
    // This means the array `a[j...n-1]` has at most one "valley".
    // An array with at most one valley (i.e., it's non-increasing then non-decreasing) is always good.
    // We can always pick the elements from the ends to form a non-decreasing sequence.
    // For example, pick `a[j], a[j+1], ..., a[i-1]` in reverse order (from right to left of this segment),
    // and `a[n-1], a[n-2], ..., a[i]` in reverse order (from right to left of this segment).
    // This is equivalent to picking `a[j]` then `a[j+1]` ... `a[i-1]` from the left, and `a[n-1]` then `a[n-2]` ... `a[i]` from the right.
    // The strategy is to always pick the smaller of the two ends, or if they are equal, pick one.
    // This works because the "valley" structure ensures that the elements at the ends are always candidates for the next smallest element.

    std::cout << j << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Operations for the median element itself
    operations += std::abs(a[median_idx] - s);

    // Operations for elements to the left of the median
    // These elements must be <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Operations for elements to the right of the median
    // These elements must be >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int i = 0;
    while (i < n) {
        if (a[i] != b[i]) {
            // Mismatch at index i
            // Check if there's an adjacent mismatch of the opposite type
            if (i + 1 < n && a[i+1] != b[i+1] && a[i] != a[i+1]) {
                // Found a pair (a[i], b[i]) and (a[i+1], b[i+1]) such that
                // a[i] != b[i] and a[i+1] != b[i+1] and a[i] != a[i+1]
                // This means (a[i], b[i]) is (0,1) and (a[i+1], b[i+1]) is (1,0)
                // OR (a[i], b[i]) is (1,0) and (a[i+1], b[i+1]) is (0,1)
                // In either case, a[i] and a[i+1] are different, and they both need to flip.
                // Swapping a[i] and a[i+1] will fix both positions.
                // Cost of swap is |i - (i+1)| = 1.
                cost += 1;
                i += 2; // Both positions i and i+1 are now fixed
            } else {
                // Mismatch at index i, but no adjacent opposite mismatch to swap with.
                // Or it's the last element.
                // We must flip a[i]. Cost is 1.
                cost += 1;
                i += 1; // Position i is now fixed
            }
        } else {
            // No mismatch at index i, move to the next position
            i += 1;
        }
    }

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will track the rightmost valid point for the current 'i'

    for (int i = 0; i < n; ++i) {
        // Advance right_ptr until x[right_ptr] is out of range (x[i] + d)
        // or it reaches the end of the array.
        // The condition x[right_ptr] <= x[i] + d ensures that
        // any point x[j] where i < j < right_ptr will satisfy x[j] - x[i] <= d
        // and x[right_ptr] - x[i] <= d.
        while (right_ptr < n && x[right_ptr] <= x[i] + d) {
            right_ptr++;
        }

        // At this point, all points from x[i+1] to x[right_ptr-1] are within
        // the distance 'd' from x[i].
        // The number of such points is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let k = right_ptr - 1 - i.
        // We need to choose 2 additional points from these 'k' points.
        // The number of ways to choose 2 points from 'k' points is k * (k - 1) / 2.

        long long k = right_ptr - 1 - i;
        if (k >= 2) { // We need at least 2 points to form a triplet with x[i]
            count += k * (k - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

// Function to check if a box can be the special box
// Parameters:
// initial_counts: vector of initial toy counts {A, B, C, D}
// target_box_idx: 0 for Box 1, 1 for Box 2, 2 for Box 3, 3 for Box 4
//
// The logic is based on analyzing the parity of negative numbers and the
// possibility of achieving the target magnitude range.
//
// Box 1: (-inf, -1] (negative, magnitude >= 1)
// Box 2: (-1, 0)    (negative, magnitude < 1)
// Box 3: (0, 1)     (positive, magnitude < 1)
// Box 4: [1, inf)   (positive, magnitude >= 1)
bool can_be_special_box(const std::vector<long long>& initial_counts, int target_box_idx) {
    long long A = initial_counts[0];
    long long B = initial_counts[1];
    long long C = initial_counts[2];
    long long D = initial_counts[3];

    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false; // Should not happen based on constraints A+B+C+D > 0

    // If only one toy initially, that toy is the super toy.
    // Check if its initial box matches the target box.
    if (total_toys == 1) {
        if (A == 1) return target_box_idx == 0;
        if (B == 1) return target_box_idx == 1;
        if (C == 1) return target_box_idx == 2;
        if (D == 1) return target_box_idx == 3;
    }

    // Parity of negative numbers:
    // A toy from Box 1 is negative.
    // A toy from Box 2 is negative.
    // So, total initial negative toys = A + B.
    // The final product's sign depends on the parity of (A + B).
    // If (A + B) is odd, final product is negative.
    // If (A + B) is even, final product is positive.

    bool final_sign_negative_required = (target_box_idx == 0 || target_box_idx == 1);
    bool final_sign_positive_required = (target_box_idx == 2 || target_box_idx == 3);

    // Case 1: Target Box 1 (negative, magnitude >= 1)
    if (target_box_idx == 0) {
        // Need odd number of negatives
        if ((A + B) % 2 == 0) { // Current negatives are even, need to make it odd
            // If we have any toys that can change sign (A or B), we can achieve odd.
            // If A+B is 0, we can't get negative.
            // If A+B is even and > 0, we can't get odd.
            // This is wrong. We can always achieve odd or even if A+B > 0.
            // The question is about *possibility*.
            // If A+B is even, we can make it odd by multiplying with a positive,
            // or by multiplying two negatives to get a positive, reducing negative count by 2.
            // The parity of (A+B) is fixed for the final product.
            // If (A+B) is even, the final product will be positive. So Box 1 is impossible.
            return false;
        }
        // Need magnitude >= 1
        // This is possible if A+D > 0 (at least one toy with magnitude >= 1)
        // OR if B+C > 0 (at least one toy with magnitude < 1) AND A+D > 0.
        // If A+D == 0, all initial toys have magnitude < 1.
        // Then any product will also have magnitude < 1. So Box 1 is impossible.
        if (A + D == 0) return false;
        return true;
    }

    // Case 2: Target Box 2 (negative, magnitude < 1)
    if (target_box_idx == 1) {
        // Need odd number of negatives
        if ((A + B) % 2 == 0) {
            return false;
        }
        // Need magnitude < 1
        // This is possible if B+C > 0 (at least one toy with magnitude < 1)
        // If B+C == 0, all initial toys have magnitude >= 1.
        // Then any product will also have magnitude >= 1. So Box 2 is impossible.
        if (B + C == 0) return false;
        return true;
    }

    // Case 3: Target Box 3 (positive, magnitude < 1)
    if (target_box_idx == 2) {
        // Need even number of negatives
        if ((A + B) % 2 != 0) {
            return false;
        }
        // Need magnitude < 1
        // This is possible if B+C > 0 (at least one toy with magnitude < 1)
        // If B+C == 0, all initial toys have magnitude >= 1.
        // Then any product will also have magnitude >= 1. So Box 3 is impossible.
        if (B + C == 0) return false;
        return true;
    }

    // Case 4: Target Box 4 (positive, magnitude >= 1)
    if (target_box_idx == 3) {
        // Need even number of negatives
        if ((A + B) % 2 != 0) {
            return false;
        }
        // Need magnitude >= 1
        // This is possible if A+D > 0 (at least one toy with magnitude >= 1)
        // If A+D == 0, all initial toys have magnitude < 1.
        // Then any product will also have magnitude < 1. So Box 4 is impossible.
        if (A + D == 0) return false;
        return true;
    }

    return false; // Should not be reached
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int T;
    std::cin >> T;
    while (T--) {
        std::vector<long long> initial_counts(4);
        std::cin >> initial_counts[0] >> initial_counts[1] >> initial_counts[2] >> initial_counts[3];

        for (int i = 0; i < 4; ++i) {
            if (can_be_special_box(initial_counts, i)) {
                std::cout << "Ya";
            } else {
                std::cout << "Tidak";
            }
            if (i < 3) {
                std::cout << " ";
            }
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> A(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A[i].value;
        A[i].original_index = i;
    }

    std::vector<ElementB> B(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B[i].value;
        B[i].original_index = i;
    }

    std::sort(A.begin(), A.end(), compareA);
    std::sort(B.begin(), B.end(), compareB);

    std::vector<long long> result_A(m);
    for (int i = 0; i < m; ++i) {
        // The i-th smallest B value (B[i].value) should be paired with
        // the (m-1-i)-th largest A value (A[m-1-i].value).
        // This means B[i].original_index will receive A[m-1-i].value.
        result_A[B[i].original_index] = A[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_A[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

bool is_permutation(const std::vector<int>& arr, int len) {
    if (len == 0) return false; // A permutation must have non-zero length
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (arr[i] <= 0 || arr[i] > len) {
            return false;
        }
        if (seen[arr[i]]) {
            return false;
        }
        seen[arr[i]] = true;
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<int, int>> results;

    // Precompute max prefix values and check distinctness
    std::vector<int> max_prefix(n);
    std::vector<bool> distinct_prefix(n);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max = 0;
    bool current_distinct = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] <= 0 || a[i] > n || seen_prefix[a[i]]) {
            current_distinct = false;
        }
        if (current_distinct) {
            seen_prefix[a[i]] = true;
        }
        if (a[i] > current_max) {
            current_max = a[i];
        }
        max_prefix[i] = current_max;
        distinct_prefix[i] = current_distinct;
    }

    // Precompute max suffix values and check distinctness
    std::vector<int> max_suffix(n);
    std::vector<bool> distinct_suffix(n);
    std::vector<bool> seen_suffix(n + 1, false);
    current_max = 0;
    current_distinct = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] <= 0 || a[i] > n || seen_suffix[a[i]]) {
            current_distinct = false;
        }
        if (current_distinct) {
            seen_suffix[a[i]] = true;
        }
        if (a[i] > current_max) {
            current_max = a[i];
        }
        max_suffix[i] = current_max;
        distinct_suffix[i] = current_distinct;
    }

    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        bool p1_is_perm = false;
        if (distinct_prefix[l1 - 1] && max_prefix[l1 - 1] == l1) {
            p1_is_perm = true;
        }

        bool p2_is_perm = false;
        if (distinct_suffix[l1] && max_suffix[l1] == l2) {
            p2_is_perm = true;
        }

        if (p1_is_perm && p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int first_w = -1;
        int last_w = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_w == -1) {
                    first_w = i;
                }
                last_w = i;
            }
        }

        if (first_w == -1) { // All 'L's
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                std::cout << std::min(n, k) * 2 - 1 << "\n";
            }
            continue;
        }

        // Calculate initial score and count L's between W's
        long long current_score = 0;
        int l_count_total = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                current_score += 1;
                if (i > 0 && s[i-1] == 'W') {
                    current_score += 1;
                }
            } else {
                l_count_total++;
            }
        }

        std::vector<int> gaps;
        int current_gap = 0;
        for (int i = first_w + 1; i <= last_w; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else {
                if (current_gap > 0) {
                    gaps.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        std::sort(gaps.begin(), gaps.end());

        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                current_score += (long long)gap_len * 2 + 1; // gap_len L's become W's, connecting two W blocks
            } else {
                break;
            }
        }

        // Remaining k can be used to convert L's at the ends
        // L's before first_w: first_w
        // L's after last_w: n - 1 - last_w
        int l_before_first_w = first_w;
        int l_after_last_w = n - 1 - last_w;

        int can_convert_at_ends = l_before_first_w + l_after_last_w;
        int convert_count = std::min(k, can_convert_at_ends);
        current_score += (long long)convert_count * 2;

        std::cout << current_score << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks for the minimum absolute difference between medians.
        // Let the sorted array be a_0, a_1, ..., a_{2n-1}.
        //
        // Consider a partition where Class 1 has k students and Class 2 has 2n-k students.
        // Both k and 2n-k must be odd. This means k must be odd.
        //
        // The median of a class of size S is the element at index (S-1)/2 in its sorted list (0-indexed).
        //
        // It can be proven that the optimal strategy is to pick the smallest n elements for one class
        // and the largest n elements for the other class, or more generally, to split the sorted array
        // into two contiguous blocks of elements, or to pick elements such that the medians are
        // a_{n-1} and a_n.
        //
        // More formally, if we sort all 2n elements, the median of any class of size S will be
        // one of the elements from the original array.
        //
        // Consider the case where Class 1 has $S_1$ students and Class 2 has $S_2$ students.
        // $S_1 + S_2 = 2n$. Both $S_1, S_2$ are odd.
        //
        // The smallest possible median for a class of size $S_1$ is $a_{(S_1-1)/2}$.
        // The largest possible median for a class of size $S_1$ is $a_{2n - 1 - (S_1-1)/2}$.
        //
        // The key insight for this problem type is often that the optimal medians will be
        // adjacent elements in the globally sorted array.
        //
        // For a class of size $S_1$, its median is the $(S_1+1)/2$-th element.
        // For a class of size $S_2$, its median is the $(S_2+1)/2$-th element.
        //
        // The problem statement implies that we can choose any $S_1$ odd students for Class 1
        // and the remaining $S_2$ odd students for Class 2.
        //
        // The minimum possible difference is achieved when the medians are $a_{n-1}$ and $a_n$.
        //
        // To see why, consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        // If we form two classes, say $C_1$ and $C_2$, with sizes $S_1$ and $S_2$ respectively.
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        //
        // If we choose $n$ elements for one class and $n$ elements for the other,
        // this is not allowed because $n$ can be even.
        //
        // The problem states that each class must have an odd number of students.
        //
        // Let's consider the specific partition where Class 1 consists of students
        // $a_0, a_1, \dots, a_{n-1}$ and Class 2 consists of students $a_n, a_{n+1}, \dots, a_{2n-1}$.
        // This is not a valid partition because both classes have $n$ students, and $n$ can be even.
        //
        // However, the problem is asking for the minimum possible absolute difference.
        //
        // The median of the first class will be $a_{n-1}$ and the median of the second class will be $a_n$.
        // This is because if we take $n$ elements for the first class, its median is $a_{(n-1)/2}$ if $n$ is odd.
        // If we take $n$ elements for the second class, its median is $a_{n + (n-1)/2}$ if $n$ is odd.
        //
        // The crucial observation is that the problem asks for the minimum difference.
        // The elements $a_{n-1}$ and $a_n$ are the two "middle" elements of the entire sorted array.
        //
        // If we can construct two classes such that one median is $a_{n-1}$ and the other is $a_n$,
        // then the difference is $a_n - a_{n-1}$.
        //
        // Can we always do this?
        //
        // Consider Class 1: $a_0, a_1, \dots, a_{n-1}$. This class has $n$ students.
        // Consider Class 2: $a_n, a_{n+1}, \dots, a_{2n-1}$. This class has $n$ students.
        //
        // If $n$ is odd, then this is a valid partition.
        // Median of Class 1 is $a_{(n-1)/2}$.
        // Median of Class 2 is $a_{n + (n-1)/2}$.
        //
        // Example 1: n=1, 2n=2. a = [1, 1]. Sorted: [1, 1].
        // n=1 is odd.
        // Class 1: [a_0] = [1]. Median = 1.
        // Class 2: [a_1] = [1]. Median = 1.
        // Difference = |1-1| = 0.
        // Using the formula $a_n - a_{n-1}$: $a_1 - a_0 = 1 - 1 = 0$. Matches.
        //
        // Example 2: n=3, 2n=6. a = [6, 5, 4, 1, 2, 3]. Sorted: [1, 2, 3, 4, 5, 6].
        // n=3 is odd.
        // Class 1: [a_0, a_1, a_2] = [1, 2, 3]. Median = 2.
        // Class 2: [a_3, a_4, a_5] = [4, 5, 6]. Median = 5.
        // Difference = |2-5| = 3.
        // The example output is 1. This means my assumption about the partition is wrong.
        //
        // The example output for n=3 is 1.
        // One possible partition: Class 1: [6, 4, 2] -> sorted [2, 4, 6], median 4.
        // Class 2: [5, 1, 3] -> sorted [1, 3, 5], median 3.
        // Difference = |4-3| = 1.
        //
        // In this example, the medians are 3 and 4. These are $a_2$ and $a_3$ in the sorted array [1, 2, 3, 4, 5, 6].
        // $a_2 = 3$, $a_3 = 4$.
        //
        // This suggests that the minimum difference is always $a_n - a_{n-1}$ (using 0-indexed $a_0, \dots, a_{2n-1}$).
        //
        // Let's prove this.
        // Let $M_1$ and $M_2$ be the medians of the two classes.
        // We want to minimize $|M_1 - M_2|$.
        //
        // Consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        // Any element $a_i$ can be a median of a class.
