    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;

        std::map<char, int> counts;
        for (char ch : s) {
            counts[ch]++;
        }

        char most_frequent_char = ' ';
        int max_count = -1;

        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_char = 'R';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_char = 'S';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_char = 'P';
        }

        char my_optimal_move = get_winning_move(most_frequent_char);

        for (size_t i = 0; i < s.length(); ++i) {
