#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // Rule 1: If s[i] is '0', then both w[i-x] and w[i+x] must be '0'.
    // This allows us to set some characters of w to '0'.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Rule 2: Verify if the constructed w can produce the given s.
    // For each s[i], check if it can be '1' based on w.
    // If s[i] is '1', but our w cannot make it '1', then no solution exists.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            bool can_be_one = false;
            if (i - x >= 0 && w[i - x] == '1') {
                can_be_one = true;
            }
            if (i + x < n && w[i + x] == '1') {
                can_be_one = true;
            }

            if (!can_be_one) {
                std::cout << -1 << std::endl;
                return;
            }
        }
    }

    std::cout << w << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

