    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;
    int a_ptr_left = 0;
    int a_ptr_right = n - 1;

    // Friends with w_i = 1 get two times the largest available numbers.
    // These are the friends with the largest w_i values, as they are sorted.
    // No, this is incorrect. Friends with w_i = 1 should get the largest numbers.
    // Friends with w_i > 1 should get one largest number and one smallest number.
    // Let's re-evaluate.

    // The largest 'k' numbers from 'a' will always be used as the 'max_val' for each friend.
    // This is because each friend needs a max_val, and to maximize sum of max_vals, we pick the largest.
    // So, the k largest numbers a[n-k], ..., a[n-1] will be the max_vals.
    // Add these to total_happiness.
    for (int i = 0; i < k; ++i) {
        total_happiness += a[a_ptr_right];
        a_ptr_right--;
    }

    // Now, distribute the remaining numbers and determine the 'min_val' for each friend.
    // Friends with w_i = 1: Their max_val is already taken from a_ptr_right.
    // They need one more number, which will also be their min_val.
    // To maximize happiness, this number should be as large as possible.
    // Since we already took the k largest numbers for max_val, the next largest available numbers
    // should go to friends with w_i = 1.
    // These are the friends with w_i = 1. They are at the end of the sorted 'w' array.
    // Iterate 'w' in reverse for friends with w_i = 1.
    // The largest w_i values are at the end of the sorted w array.
    // The friends with w_i = 1 should get the largest available numbers for their min_val (which is also their only other number).
    // These are the largest numbers from the remaining pool.
    // The largest numbers from the remaining pool are a[a_ptr_right], a[a_ptr_right-1], ...
    // So, for friends with w_i = 1, their happiness is max_val + min_val.
    // We already added max_val. Now add min_val.
    // The largest available numbers for min_val should go to friends with w_i = 1.
    // These are the numbers a[a_ptr_right], a[a_ptr_right-1], ...
    // The friends with w_i = 1 are at the end of the sorted w array.
    // So, iterate w from right to left.
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += a[a_ptr_right];
            a_ptr_right--;
        } else {
            // Friends with w_i > 1: Their max_val is already taken.
            // They need w_i - 1 additional numbers, and one of these will be their min_val.
            // To maximize happiness, their min_val should be as large as possible.
            // However, to maximize the *sum* of happiness, the smallest available numbers
            // should be assigned as min_val for friends with w_i > 1.
            // This is because these friends also consume w_i - 2 other numbers that don't affect happiness.
            // To "save" larger numbers for other min_vals or for friends with w_i=1,
            // the friends who take many numbers (large w_i) should take the smallest available numbers
            // as their min_val.
            // So, iterate w from left to right for friends with w_i > 1.
            // The smallest w_i values (that are > 1) are at the beginning of the sorted w array.
            // These friends will take a[a_ptr_left] as their min_val.
            // And then they will consume w_i - 2 more numbers from the left.
            total_happiness += a[a_ptr_left];
            a_ptr_left += (w[i] - 1); // Consume w_i - 1 numbers, including the min_val
        }
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

