// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // This means we need to remove some prime factors from p such that the resulting number is not divisible by q.
        // To maximize x, we should remove as few factors as possible, or factors that are "small" in terms of their contribution to p.
        // More precisely, we want to remove factors such that x is no longer divisible by q, but x is as large as possible.
        // This implies that x should be p / (some factor of q that is also a factor of p).

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 1;

        for (long long factor : q_prime_factors) {
            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= factor;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

