void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    for (int p = 0; p <= 9; ++p) {
        std::vector<int> colors(n);
        int last1 = -1; // Last digit colored 1
        int last2 = -1; // Last digit colored 2

        bool possible_p = true;
        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                colors[i] = 1;
                if (d[i] < last1) {
                    possible_p = false;
                    break;
                }
                last1 = d[i];
            } else if (d[i] > p) {
                colors[i] = 2;
                if (d[i] < last2) {
                    possible_p = false;
                    break;
                }
                last2 = d[i];
            } else { // d[i] == p
                if (p >= last2) { // Can be colored 2
                    colors[i] = 2;
                    last2 = p;
                } else if (p >= last1) { // Must be colored 1
                    colors[i] = 1;
                    last1 = p;
                } else { // Cannot be colored 1 or 2
                    possible_p = false;
                    break;
                }
            }
        }

        if (possible_p) {
            for (int i = 0; i < n; ++i) {
                std::cout << colors[i];
            }
            std::cout << "\n";
            return;
        }
    }

