#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    // Step 1: Propagate known characters based on s[i] == s[i+k] property
    for (int i = 0; i < n - k; ++i) {
        if (s[i] != '?' && s[i+k] == '?') {
            s[i+k] = s[i];
        } else if (s[i] == '?' && s[i+k] != '?') {
            s[i] = s[i+k];
        } else if (s[i] != '?' && s[i+k] != '?' && s[i] != s[i+k]) {
            std::cout << "NO\n";
            return;
        }
    }

    // Step 2: Check the first k characters for balance
    // For each position i from 0 to k-1, s[i], s[i+k], s[i+2k], ... must be the same.
    // We need to determine these characters.
    // We can iterate through the first k characters and count known 0s and 1s.
    int count0 = 0;
    int count1 = 0;
    for (int i = 0; i < k; ++i) {
        if (s[i] == '0') {
            count0++;
        } else if (s[i] == '1') {
            count1++;
        }
    }

    // If count0 or count1 exceeds k/2, it's impossible.
    if (count0 > k / 2 || count1 > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // We have k/2 - count0 '0's and k/2 - count1 '1's to fill among '?'s in the first k positions.
    // This is always possible if count0 <= k/2 and count1 <= k/2.
    // The remaining '?'s (k - count0 - count1) can be filled arbitrarily to satisfy the counts.
    // For example, fill (k/2 - count0) '0's and (k/2 - count1) '1's.
    // The remaining '?'s (k - count0 - count1 - (k/2 - count0) - (k/2 - count1) = 0) are already filled.
    // This logic is slightly flawed. We don't need to fill them explicitly.
    // We just need to check if it's *possible* to fill them.
    // The number of '?'s in the first k positions is k - count0 - count1.
    // We need to assign k/2 - count0 zeros and k/2 - count1 ones to these '?'s.
    // The total number of '?'s must be at least (k/2 - count0) + (k/2 - count1).
    // (k - count0 - count1) >= (k/2 - count0) + (k/2 - count1)
    // k - count0 - count1 >= k - count0 - count1
    // This inequality is always true. So, if count0 <= k/2 and count1 <= k/2, it's always possible to fill the first k positions.

    // Step 3: Verify the entire string
    // The propagation in Step 1 ensures that s[i] == s[i+k] for all i.
    // This means that for any substring S[j...j+k-1], the characters S[j], S[j+1], ..., S[j+k-1]
    // are determined by the characters S[j%k], S[(j+1)%k], ..., S[(j+k-1)%k].
    // In other words, the pattern of the first k characters repeats.
    // So, if the first k characters can be made k-balanced, the entire string will be k-balanced.
    // We already checked if the first k characters can be made k-balanced in Step 2.

    std::cout << "YES\n";
}

