#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;
    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum_r = sum_{r=1 to b-1} r
    // Sum_r = (b-1) * b / 2
    // We need to compute this modulo MOD.
    // Since b-1 and b are consecutive, one is even. So (b-1)*b is always even.
    // We can divide by 2 before taking modulo, or multiply by modular inverse of 2.
    // Modular inverse of 2 modulo 10^9+7 is (10^9+7 + 1) / 2 = 500000004.
    long long sum_r_term1 = (b - 1) % MOD;
    long long sum_r_term2 = b % MOD;
    long long inv2 = 500000004; // Modular inverse of 2 modulo 10^9+7

    long long sum_r = (sum_r_term1 * sum_r_term2) % MOD;
    sum_r = (sum_r * inv2) % MOD;

    // Sum_k_b_plus_1 = sum_{k=1 to a} (k * b + 1)
    // Sum_k_b_plus_1 = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // Sum_k_b_plus_1 = b * (a * (a+1) / 2) + a
    // We need to compute this modulo MOD.
    long long sum_k_term1 = (a % MOD);
    long long sum_k_term2 = ((a + 1) % MOD);
    long long sum_k = (sum_k_term1 * sum_k_term2) % MOD;
    sum_k = (sum_k * inv2) % MOD;

    long long sum_k_b_plus_1 = (b % MOD * sum_k) % MOD;
    sum_k_b_plus_1 = (sum_k_b_plus_1 + (a % MOD)) % MOD;

    long long total_sum = (sum_r * sum_k_b_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

long long solve() {
    int n;
    std::cin >> n;
    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 1) {
        return 1;
    }

    std::vector<long long> L(n);
    L[0] = 1;
    for (int i = 1; i < n; ++i) {
        L[i] = std::min(h[i], L[i - 1] + 1);
    }

    std::vector<long long> R(n);
    R[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        R[i] = std::min(h[i], R[i + 1] + 1);
    }

    long long max_k = 0;
    for (int i = 0; i < n; ++i) {
        max_k = std::max(max_k, std::min(L[i], R[i]));
    }

    return max_k;
}

